import { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search, Bell, Pin } from 'lucide-react';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

type TabKey = 'chat' | 'notice';

export default function Messages() {
  const navigate = useNavigate();
  const conversations = useStore(s => s.conversations);
  const [tab, setTab] = useState<TabKey>('chat');
  const [keyword, setKeyword] = useState('');

  const sorted = useMemo(() => {
    return [...conversations]
      .sort((a, b) => Number(b.pinned) - Number(a.pinned))
      .filter(c =>
        keyword.trim()
          ? c.peer.nickname.includes(keyword) || c.lastMessage.includes(keyword)
          : true
      );
  }, [conversations, keyword]);

  const totalUnread = conversations.reduce((sum, c) => sum + c.unread, 0);

  return (
    <div className="min-h-screen bg-ink-50">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="flex items-center justify-between h-14 px-4">
          <h1 className="font-display font-semibold text-base tracking-tight">消息</h1>
        </div>

        {/* Tab 切换 */}
        <div className="flex px-4">
          <button
            onClick={() => setTab('chat')}
            className={cn(
              'flex-1 py-2.5 text-sm font-medium relative btn-press',
              tab === 'chat' ? 'text-white' : 'text-white/60'
            )}
          >
            私聊
            {totalUnread > 0 && tab !== 'chat' && (
              <span className="ml-1 inline-flex items-center justify-center min-w-[16px] h-4 px-1 rounded-full bg-danger-500 text-white text-[10px] font-semibold">
                {totalUnread}
              </span>
            )}
            {tab === 'chat' && (
              <span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-8 h-0.5 rounded-full bg-white" />
            )}
          </button>
          <button
            onClick={() => navigate('/notifications')}
            className={cn(
              'flex-1 py-2.5 text-sm font-medium relative btn-press',
              tab === 'notice' ? 'text-white' : 'text-white/60'
            )}
          >
            通知
            {tab === 'notice' && (
              <span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-8 h-0.5 rounded-full bg-white" />
            )}
          </button>
        </div>

        {/* 搜索栏 */}
        {tab === 'chat' && (
          <div className="px-4 pb-3 pt-1">
            <div className="relative">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/60" />
              <input
                value={keyword}
                onChange={e => setKeyword(e.target.value)}
                placeholder="搜索昵称或消息"
                className="w-full h-9 pl-9 pr-3 rounded-full bg-white/20 text-white text-sm placeholder:text-white/60 focus:outline-none focus:bg-white/30 transition-all"
              />
            </div>
          </div>
        )}
      </div>

      {/* 通知 Tab 提示卡片 */}
      {tab === 'notice' ? (
        <div className="p-3">
          <button
            onClick={() => navigate('/notifications')}
            className="w-full bg-white rounded-2xl p-4 shadow-card flex items-center gap-3 btn-press animate-fade-in"
          >
            <div className="w-11 h-11 rounded-xl bg-primary-50 flex items-center justify-center shrink-0">
              <Bell size={20} className="text-primary-600" />
            </div>
            <div className="flex-1 text-left">
              <div className="font-semibold text-ink-900 text-sm">通知中心</div>
              <div className="text-xs text-ink-400 mt-0.5">查看任务、支付、社交等通知</div>
            </div>
            <span className="text-ink-300 text-sm">›</span>
          </button>
        </div>
      ) : sorted.length === 0 ? (
        <Empty
          icon="💬"
          title="暂无会话"
          desc={keyword ? '没有匹配的会话' : '接单或发布任务后即可与对方沟通'}
        />
      ) : (
        <div className="p-3 space-y-2">
          {sorted.map(conv => (
            <button
              key={conv.id}
              onClick={() => navigate(`/messages/${conv.id}`)}
              className={cn(
                'w-full bg-white rounded-2xl p-3.5 shadow-card flex items-center gap-3 btn-press animate-fade-in text-left',
                conv.pinned && 'ring-1 ring-primary-100'
              )}
            >
              <div className="relative shrink-0">
                <Avatar src={conv.peer.avatar} name={conv.peer.nickname} size={48} />
                {conv.online && (
                  <span className="absolute bottom-0 right-0 w-3 h-3 rounded-full bg-success-500 border-2 border-white" />
                )}
                {conv.unread > 0 && (
                  <span className="absolute -top-1 -right-1 inline-flex items-center justify-center min-w-[18px] h-[18px] px-1 rounded-full bg-danger-500 text-white text-[10px] font-semibold border-2 border-white">
                    {conv.unread > 99 ? '99+' : conv.unread}
                  </span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between gap-2">
                  <div className="flex items-center gap-1 min-w-0">
                    {conv.pinned && <Pin size={12} className="text-primary-500 shrink-0" fill="currentColor" />}
                    <span className="font-semibold text-ink-900 text-sm truncate">{conv.peer.nickname}</span>
                  </div>
                  <span className="text-[11px] text-ink-400 shrink-0">{conv.lastTime}</span>
                </div>
                <div className="flex items-center justify-between gap-2 mt-1">
                  <span className={cn('text-xs line-clamp-1', conv.unread > 0 ? 'text-ink-700' : 'text-ink-400')}>
                    {conv.lastMessage}
                  </span>
                  <span className="text-[10px] px-1.5 py-0.5 rounded bg-ink-100 text-ink-500 shrink-0 max-w-[120px] truncate">
                    {conv.source}
                  </span>
                </div>
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}
