import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  MapPin, Clock, Users, Send, Heart, Share2, Flag, ChevronRight, Star, MessageSquare,
} from 'lucide-react';
import { useStore } from '@/store';
import { categoryConfig, formatPrice } from '@/data/mock';
import PageHeader from '@/components/PageHeader';
import StatusBadge from '@/components/StatusBadge';
import Avatar from '@/components/Avatar';
import Modal from '@/components/Modal';
import { cn } from '@/lib/utils';

export default function TaskDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { getTask, user, acceptTask, favorites, toggleFavorite, orders, showToast } = useStore();
  const [reportOpen, setReportOpen] = useState(false);

  const task = id ? getTask(id) : undefined;

  if (!task) {
    return (
      <div className="min-h-screen bg-ink-50">
        <PageHeader title="任务详情" />
        <div className="flex flex-col items-center justify-center py-24 text-ink-400">
          <p className="text-sm">任务不存在或已下架</p>
          <button onClick={() => navigate('/tasks')} className="mt-4 text-primary-600 text-sm font-medium">返回任务市场</button>
        </div>
      </div>
    );
  }

  const cat = categoryConfig[task.category];
  const isFav = favorites.includes(task.id);
  const isOwn = task.publisherId === user.id;
  const relatedOrder = orders.find(o => o.taskId === task.id);

  const handleAccept = () => {
    const ok = acceptTask(task.id);
    if (ok) {
      showToast('接单成功！', 'success');
      const order = orders.find(o => o.taskId === task.id) || relatedOrder;
      if (order) navigate(`/orders/${order.id}`);
      else navigate('/tasks');
    } else {
      showToast('接单失败，任务可能已被接取', 'error');
    }
  };

  const handleShare = () => showToast('链接已复制到剪贴板', 'info');

  const mainBtn = () => {
    if (task.status === 'OPEN') {
      return isOwn ? (
        <button disabled className="flex-1 py-3 rounded-xl text-sm font-semibold bg-ink-200 text-ink-400">
          等待接单中
        </button>
      ) : (
        <button onClick={handleAccept} className="flex-1 py-3 rounded-xl text-sm font-semibold bg-gradient-blue-purple text-white btn-press shadow-gradient-lg">
          立即接单
        </button>
      );
    }
    return (
      <button
        onClick={() => relatedOrder && navigate(`/orders/${relatedOrder.id}`)}
        disabled={!relatedOrder}
        className={cn(
          'flex-1 py-3 rounded-xl text-sm font-semibold btn-press',
          relatedOrder ? 'bg-gradient-blue-purple text-white shadow-gradient' : 'bg-ink-200 text-ink-400'
        )}
      >
        {relatedOrder ? '查看订单' : '暂无订单'}
      </button>
    );
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      <PageHeader
        title="任务详情"
        right={
          <button onClick={() => setReportOpen(true)} className="p-1.5 rounded-full hover:bg-ink-100 btn-press">
            <Flag size={18} className="text-ink-600" />
          </button>
        }
      />

      {/* 图片区 / 渐变占位 */}
      <div className="h-48 mx-4 mt-3 rounded-2xl overflow-hidden relative">
        {task.images.length > 0 ? (
          <img src={task.images[0]} alt={task.title} className="w-full h-full object-cover" />
        ) : (
          <div
            className="w-full h-full flex flex-col items-center justify-center text-white"
            style={{ background: `linear-gradient(135deg, ${cat.color}, ${cat.color}cc)` }}
          >
            <span className="text-6xl">{cat.icon}</span>
            <span className="mt-2 text-sm font-medium opacity-90">{cat.label}</span>
          </div>
        )}
      </div>

      {/* 标题 + 价格 */}
      <div className="px-4 mt-4">
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <div className="flex items-start justify-between gap-2">
            <h1 className="font-display font-bold text-ink-900 text-lg leading-snug flex-1">{task.title}</h1>
            <StatusBadge status={task.status} size="md" />
          </div>
          <div className="flex items-baseline gap-1 mt-2">
            <span className="text-warning-600 font-display font-bold text-3xl">¥{formatPrice(task.price)}</span>
            <span className="text-xs text-ink-400">/ 单</span>
          </div>
          <div className="flex items-center gap-1.5 mt-2.5 flex-wrap">
            <span
              className="text-[11px] px-2 py-0.5 rounded font-medium"
              style={{ color: cat.color, backgroundColor: cat.color + '15' }}
            >
              {cat.icon} {cat.label}
            </span>
            {task.tags.map(tag => (
              <span key={tag} className="text-[11px] px-2 py-0.5 rounded bg-ink-100 text-ink-500 font-medium">{tag}</span>
            ))}
          </div>
        </div>
      </div>

      {/* 任务信息 */}
      <div className="px-4 mt-3">
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <div className="grid grid-cols-2 gap-3">
            <InfoItem icon={<MapPin size={15} />} label="地点" value={task.location || '不限'} />
            <InfoItem icon={<Clock size={15} />} label="截止" value={task.deadline || '不限'} />
            <InfoItem icon={<Users size={15} />} label="人数" value={`${task.headcount} 人`} />
            <InfoItem icon={<Send size={15} />} label="交付" value={task.deliveryMethod} />
          </div>
          <div className="border-t border-ink-100 mt-3 pt-3">
            <h3 className="text-xs font-semibold text-ink-500 mb-1.5">任务描述</h3>
            <p className="text-sm text-ink-700 leading-relaxed whitespace-pre-wrap">{task.description}</p>
          </div>
        </div>
      </div>

      {/* 发布者卡片 */}
      <div className="px-4 mt-3">
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <div className="flex items-center gap-3">
            <Avatar src={task.publisher.avatar} name={task.publisher.nickname} size={44} ring />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1.5">
                <span className="font-semibold text-ink-900 text-sm">{task.publisher.nickname}</span>
                {task.publisher.verified && (
                  <span className="text-[10px] px-1 py-0.5 rounded bg-success-100 text-success-700 font-medium">
                    已认证 {task.publisher.verifyLevel}
                  </span>
                )}
              </div>
              <div className="flex items-center gap-2 mt-0.5 text-[11px] text-ink-400">
                <span className="flex items-center gap-0.5"><Star size={11} className="text-warning-500" fill="currentColor" />信誉 {task.publisher.creditScore}</span>
                <span>Lv.{task.publisher.level}</span>
                <span>完成率 {task.publisher.completeRate}%</span>
              </div>
            </div>
            <button className="text-xs text-primary-600 font-medium flex items-center gap-0.5 btn-press">
              查看主页<ChevronRight size={14} />
            </button>
          </div>
        </div>
      </div>

      {/* 评论 */}
      <div className="px-4 mt-3">
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <h3 className="text-sm font-semibold text-ink-900 flex items-center gap-1.5 mb-3">
            <MessageSquare size={15} className="text-ink-500" /> 评论 (2)
          </h3>
          <div className="space-y-3">
            <CommentItem name="陈学长" avatar="陈" time="20分钟前" content="请问可以线上完成吗？我有相关经验。" />
            <CommentItem name="李设计" avatar="李" time="10分钟前" content="已私信，希望合作～" />
          </div>
          <div className="flex items-center gap-2 mt-3 pt-3 border-t border-ink-100">
            <input
              placeholder="说点什么…"
              className="flex-1 bg-ink-100 rounded-full px-4 py-2 text-sm text-ink-700 placeholder:text-ink-400 outline-none"
            />
            <button
              onClick={() => showToast('评论功能演示中', 'info')}
              className="w-9 h-9 flex items-center justify-center bg-gradient-blue-purple text-white rounded-full btn-press shadow-gradient"
            >
              <Send size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* 底部操作栏 */}
      <div className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-white border-t border-ink-100 px-4 py-3 flex items-center gap-3 z-40" style={{ paddingBottom: 'calc(var(--safe-bottom) + 12px)' }}>
        <button
          onClick={() => toggleFavorite(task.id)}
          className="flex flex-col items-center gap-0.5 w-12 btn-press"
        >
          <Heart size={22} className={cn(isFav ? 'text-danger-500' : 'text-ink-400')} fill={isFav ? 'currentColor' : 'none'} />
          <span className="text-[10px] text-ink-500">{isFav ? '已收藏' : '收藏'}</span>
        </button>
        <button onClick={handleShare} className="flex flex-col items-center gap-0.5 w-12 btn-press">
          <Share2 size={22} className="text-ink-400" />
          <span className="text-[10px] text-ink-500">分享</span>
        </button>
        {mainBtn()}
      </div>

      {/* 举报弹窗 */}
      <Modal open={reportOpen} onClose={() => setReportOpen(false)} title="举报任务">
        <div className="py-2">
          {['虚假信息', '违规内容', '诈骗嫌疑', '重复发布', '其他原因'].map(r => (
            <button
              key={r}
              onClick={() => { setReportOpen(false); showToast('举报已提交，我们会尽快处理', 'success'); }}
              className="w-full flex items-center justify-between px-5 py-3.5 hover:bg-ink-50 btn-press"
            >
              <span className="text-sm text-ink-700">{r}</span>
              <ChevronRight size={16} className="text-ink-300" />
            </button>
          ))}
        </div>
      </Modal>
    </div>
  );
}

function InfoItem({ icon, label, value }: { icon: React.ReactNode; label: string; value: string }) {
  return (
    <div className="flex items-center gap-2">
      <span className="text-ink-400">{icon}</span>
      <div className="min-w-0">
        <div className="text-[11px] text-ink-400">{label}</div>
        <div className="text-sm text-ink-700 font-medium truncate">{value}</div>
      </div>
    </div>
  );
}

function CommentItem({ name, avatar, time, content }: { name: string; avatar: string; time: string; content: string }) {
  return (
    <div className="flex items-start gap-2.5">
      <Avatar name={avatar} size={32} />
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5">
          <span className="text-xs font-medium text-ink-700">{name}</span>
          <span className="text-[10px] text-ink-400">{time}</span>
        </div>
        <p className="text-sm text-ink-600 mt-0.5">{content}</p>
      </div>
    </div>
  );
}
