import { useMemo } from 'react';
import { Shield, TrendingUp, Lightbulb } from 'lucide-react';
import { creditEvents } from '@/data/mock';
import { useStore } from '@/store';
import type { CreditEvent } from '@/types';
import PageHeader from '@/components/PageHeader';
import { cn } from '@/lib/utils';

export default function Credit() {
  const { user } = useStore();
  const score = user.creditScore;

  const level = useMemo(() => {
    if (score >= 90) return { label: '优秀', color: '#10B981', bg: '#ECFDF5' };
    if (score >= 80) return { label: '良好', color: '#2563EB', bg: '#EFF6FF' };
    if (score >= 60) return { label: '一般', color: '#F59E0B', bg: '#FFFBEB' };
    return { label: '较低', color: '#EF4444', bg: '#FEF2F2' };
  }, [score]);

  const tips = [
    '按时完成接取的任务，避免责任取消',
    '保持良好的沟通，争取五星评价',
    '完成学生认证可获得信誉加分',
    '连续完成多个任务可解锁成就奖励',
  ];

  return (
    <div className="min-h-screen pb-6 bg-ink-50">
      <PageHeader title="信誉中心" back />

      <div className="px-3 py-3 space-y-3">
        {/* 信誉分展示 */}
        <div className="bg-white rounded-2xl p-5 shadow-card text-center animate-slide-up">
          <div className="relative inline-flex items-center justify-center">
            <svg width="140" height="140" className="-rotate-90">
              <circle cx="70" cy="70" r="60" fill="none" stroke="#F1F5F9" strokeWidth="10" />
              <circle
                cx="70" cy="70" r="60" fill="none" stroke={level.color} strokeWidth="10"
                strokeLinecap="round"
                strokeDasharray={2 * Math.PI * 60}
                strokeDashoffset={2 * Math.PI * 60 - (score / 100) * 2 * Math.PI * 60}
                style={{ transition: 'stroke-dashoffset 0.8s ease' }}
              />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="font-display text-4xl font-bold" style={{ color: level.color }}>{score}</span>
              <span className="text-xs text-ink-400 mt-0.5">信誉分</span>
            </div>
          </div>
          <div
            className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-semibold mt-2"
            style={{ color: level.color, backgroundColor: level.bg }}
          >
            <Shield size={14} />
            {level.label}
          </div>
          <p className="text-xs text-ink-400 mt-2">距离下一档还需 {score >= 90 ? 0 : (score >= 80 ? 90 - score : (score >= 60 ? 80 - score : 60 - score))} 分</p>
        </div>

        {/* 等级说明 */}
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <h3 className="font-display font-semibold text-ink-900 text-sm mb-3">等级说明</h3>
          <div className="grid grid-cols-4 gap-2">
            {[
              { range: '0-60', label: '低', color: '#EF4444' },
              { range: '60-80', label: '一般', color: '#F59E0B' },
              { range: '80-90', label: '良好', color: '#2563EB' },
              { range: '90+', label: '优秀', color: '#10B981' },
            ].map(item => (
              <div
                key={item.label}
                className={cn(
                  'rounded-xl p-2 text-center',
                  level.label === item.label ? 'ring-2' : ''
                )}
                style={{
                  backgroundColor: item.color + '12',
                  ...(level.label === item.label ? { '--tw-ring-color': item.color } as React.CSSProperties : {}),
                }}
              >
                <p className="text-xs font-bold" style={{ color: item.color }}>{item.label}</p>
                <p className="text-[10px] text-ink-400 mt-0.5">{item.range}</p>
              </div>
            ))}
          </div>
        </div>

        {/* 提升建议 */}
        <div className="bg-gradient-to-br from-primary-50 to-purple-50 rounded-2xl p-4 shadow-card">
          <div className="flex items-center gap-1.5 mb-2">
            <Lightbulb size={16} className="text-warning-500" />
            <h3 className="font-display font-semibold text-ink-900 text-sm">提升建议</h3>
          </div>
          <ul className="space-y-1.5">
            {tips.map((tip, i) => (
              <li key={i} className="flex items-start gap-2 text-xs text-ink-600">
                <span className="text-primary-500 mt-0.5">•</span>
                <span>{tip}</span>
              </li>
            ))}
          </ul>
        </div>

        {/* 信誉事件时间线 */}
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <div className="flex items-center gap-1.5 mb-3">
            <TrendingUp size={16} className="text-primary-600" />
            <h3 className="font-display font-semibold text-ink-900 text-sm">信誉记录</h3>
          </div>
          <div className="relative">
            {creditEvents.map((event, i) => (
              <EventItem key={event.id} event={event} last={i === creditEvents.length - 1} />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function EventItem({ event, last }: { event: CreditEvent; last: boolean }) {
  const isPositive = event.delta > 0;
  const appealing = event.status === 'appealing';

  return (
    <div className="flex gap-3 relative">
      {/* 时间线 */}
      <div className="flex flex-col items-center">
        <div
          className={cn('w-2.5 h-2.5 rounded-full shrink-0 mt-1.5', isPositive ? 'bg-success-500' : 'bg-danger-500')}
        />
        {!last && <div className="w-px flex-1 bg-ink-200 my-1" />}
      </div>

      {/* 内容 */}
      <div className={cn('flex-1 pb-4', last && 'pb-0')}>
        <div className="flex items-start justify-between gap-2">
          <p className="text-sm text-ink-800 font-medium flex-1">{event.reason}</p>
          <span
            className="font-display font-bold text-sm shrink-0"
            style={{ color: isPositive ? '#10B981' : '#EF4444' }}
          >
            {isPositive ? '+' : ''}{event.delta}
          </span>
        </div>
        <div className="flex items-center gap-2 mt-1">
          <span className="text-[11px] text-ink-400">{event.createdAt}</span>
          {appealing && (
            <span className="text-[10px] px-1.5 py-0.5 rounded bg-warning-100 text-warning-600 font-medium">申诉中</span>
          )}
        </div>
      </div>
    </div>
  );
}
