import { useEffect, type ReactNode } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import {
  LayoutDashboard, ListTodo, ClipboardList, Users, Wallet, FileText, ArrowLeft,
} from 'lucide-react';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

const navItems = [
  { to: '/admin', icon: LayoutDashboard, label: '工作台', end: true },
  { to: '/admin/tasks', icon: ListTodo, label: '任务' },
  { to: '/admin/orders', icon: ClipboardList, label: '订单' },
  { to: '/admin/users', icon: Users, label: '用户' },
  { to: '/admin/finance', icon: Wallet, label: '财务' },
  { to: '/admin/content', icon: FileText, label: '内容' },
];

export default function AdminLayout({ children }: { children: ReactNode }) {
  const navigate = useNavigate();
  const setMode = useStore(s => s.setMode);

  useEffect(() => {
    setMode('admin');
  }, [setMode]);

  const handleBack = () => {
    setMode('user');
    navigate('/');
  };

  return (
    <div className="min-h-screen bg-ink-50">
      <header className="sticky top-0 z-40 bg-white border-b border-ink-200 shadow-card">
        <div className="max-w-[1200px] mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-blue-purple flex items-center justify-center text-white font-bold text-sm font-display shadow-gradient">校</div>
            <h1 className="font-display font-semibold text-ink-900 text-base">校园Pro 管理后台</h1>
          </div>
          <button
            onClick={handleBack}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-ink-100 hover:bg-ink-200 text-ink-700 text-sm font-medium btn-press"
          >
            <ArrowLeft size={16} />
            返回用户端
          </button>
        </div>
        <nav className="max-w-[1200px] mx-auto px-4">
          <div className="flex items-center gap-1 overflow-x-auto no-scrollbar -mb-px">
            {navItems.map(item => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.end}
                className={({ isActive }) => cn(
                  'flex items-center gap-1.5 px-3 py-2.5 text-sm font-medium border-b-2 whitespace-nowrap transition-colors',
                  isActive
                    ? 'border-primary-600 text-primary-600'
                    : 'border-transparent text-ink-500 hover:text-ink-700'
                )}
              >
                <item.icon size={16} />
                {item.label}
              </NavLink>
            ))}
          </div>
        </nav>
      </header>
      <main className="max-w-[1200px] mx-auto px-4 py-5 animate-fade-in">
        {children}
      </main>
    </div>
  );
}
