import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Sparkles, ArrowLeft, Loader2, TrendingUp, Zap, Target, Lightbulb, ChevronRight } from 'lucide-react';
import { diagnoseMonetization, DEMAND_LABEL, DIFFICULTY_LABEL, type DiagnosisInput, type MonetizationPlan } from '@/services/ai';
import { categoryConfig } from '@/data/mock';
import { formatPrice } from '@/data/mock';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

const HOBBY_OPTIONS = ['摄影', '音乐', '吉他', '运动', '健身', '阅读', '游戏', '电影', '旅行', '写作', '绘画', '编程'];
const SKILL_OPTIONS = ['Python编程', 'Java', '前端开发', 'PS设计', 'PPT制作', '摄影', '英语翻译', '视频剪辑', '高数', '写作', '吉他', '健身指导'];
const FREE_TIME_OPTIONS = [
  { key: 'rich', label: '充足', desc: '每周 15h+' },
  { key: 'normal', label: '一般', desc: '每周 5-15h' },
  { key: 'tight', label: '紧张', desc: '每周 <5h' },
] as const;

export default function AISkillDiagnosis() {
  const navigate = useNavigate();
  const { user, showToast } = useStore();
  const [major, setMajor] = useState(user.bio.includes('计算机') ? '计算机科学与技术' : '');
  const [selectedHobbies, setSelectedHobbies] = useState<string[]>([]);
  const [selectedSkills, setSelectedSkills] = useState<string[]>(user.skills.map(s => s.name));
  const [freeTime, setFreeTime] = useState<DiagnosisInput['freeTime']>('normal');
  const [loading, setLoading] = useState(false);
  const [plans, setPlans] = useState<MonetizationPlan[] | null>(null);

  const toggle = (list: string[], item: string, setter: (v: string[]) => void) => {
    setter(list.includes(item) ? list.filter(i => i !== item) : [...list, item]);
  };

  const runDiagnosis = () => {
    if (!major.trim()) {
      showToast('请填写你的专业', 'error');
      return;
    }
    setLoading(true);
    setPlans(null);
    // 模拟 AI 思考延迟
    setTimeout(() => {
      const result = diagnoseMonetization({
        major,
        hobbies: selectedHobbies,
        skills: selectedSkills,
        freeTime,
      });
      setPlans(result);
      setLoading(false);
    }, 1800);
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="flex items-center gap-3 h-14 px-4">
          <button onClick={() => navigate(-1)} className="p-1.5 -ml-1.5 rounded-full btn-press">
            <ArrowLeft size={20} />
          </button>
          <div className="flex items-center gap-1.5">
            <Sparkles size={18} className="text-white" />
            <h1 className="font-display font-semibold text-base">AI 技能变现诊断</h1>
          </div>
        </div>
        <div className="px-4 pb-4">
          <p className="text-white/80 text-xs leading-relaxed">
            告诉 AI 你的专业、兴趣和技能，智能诊断出最适合你的校园变现方向，含定价建议与接单策略。
          </p>
        </div>
      </div>

      <div className="px-3 -mt-2 space-y-3">
        {/* 输入区 */}
        <div className="bg-white rounded-2xl p-4 shadow-card space-y-4 animate-slide-up">
          {/* 专业 */}
          <div>
            <label className="text-sm font-semibold text-ink-800 flex items-center gap-1.5 mb-2">
              <Target size={15} className="text-primary-600" /> 你的专业
            </label>
            <input
              value={major}
              onChange={e => setMajor(e.target.value)}
              placeholder="如：计算机科学与技术"
              className="w-full h-11 px-3.5 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-400 focus:outline-none focus:border-primary-400 focus:bg-white transition-all"
            />
          </div>

          {/* 兴趣 */}
          <div>
            <label className="text-sm font-semibold text-ink-800 flex items-center gap-1.5 mb-2">
              <Lightbulb size={15} className="text-warning-500" /> 兴趣爱好
              <span className="text-[11px] font-normal text-ink-400">（可多选）</span>
            </label>
            <div className="flex flex-wrap gap-2">
              {HOBBY_OPTIONS.map(h => (
                <button
                  key={h}
                  onClick={() => toggle(selectedHobbies, h, setSelectedHobbies)}
                  className={cn(
                    'px-3 py-1.5 rounded-full text-xs font-medium border transition-all btn-press',
                    selectedHobbies.includes(h)
                      ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient'
                      : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  {h}
                </button>
              ))}
            </div>
          </div>

          {/* 技能 */}
          <div>
            <label className="text-sm font-semibold text-ink-800 flex items-center gap-1.5 mb-2">
              <Zap size={15} className="text-success-500" /> 已有技能
              <span className="text-[11px] font-normal text-ink-400">（可多选）</span>
            </label>
            <div className="flex flex-wrap gap-2">
              {SKILL_OPTIONS.map(s => (
                <button
                  key={s}
                  onClick={() => toggle(selectedSkills, s, setSelectedSkills)}
                  className={cn(
                    'px-3 py-1.5 rounded-full text-xs font-medium border transition-all btn-press',
                    selectedSkills.includes(s)
                      ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient'
                      : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          {/* 空闲时间 */}
          <div>
            <label className="text-sm font-semibold text-ink-800 flex items-center gap-1.5 mb-2">
              <TrendingUp size={15} className="text-accent-500" /> 空闲时间
            </label>
            <div className="grid grid-cols-3 gap-2">
              {FREE_TIME_OPTIONS.map(o => (
                <button
                  key={o.key}
                  onClick={() => setFreeTime(o.key)}
                  className={cn(
                    'py-2.5 rounded-xl text-center border transition-all btn-press',
                    freeTime === o.key
                      ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient'
                      : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  <div className="text-sm font-semibold">{o.label}</div>
                  <div className={cn('text-[10px] mt-0.5', freeTime === o.key ? 'text-white/70' : 'text-ink-400')}>{o.desc}</div>
                </button>
              ))}
            </div>
          </div>

          {/* 诊断按钮 */}
          <button
            onClick={runDiagnosis}
            disabled={loading}
            className="w-full py-3.5 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold btn-press shadow-gradient-lg flex items-center justify-center gap-2 disabled:opacity-60"
          >
            {loading ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                AI 正在分析你的变现潜力…
              </>
            ) : (
              <>
                <Sparkles size={18} />
                开始 AI 诊断
              </>
            )}
          </button>
        </div>

        {/* AI 思考动画 */}
        {loading && (
          <div className="bg-white rounded-2xl p-5 shadow-card animate-slide-up space-y-3">
            <div className="flex items-center gap-2 text-primary-600">
              <div className="w-2 h-2 rounded-full bg-primary-500 animate-pulse" />
              <span className="text-xs font-medium">正在匹配校园需求知识库…</span>
            </div>
            <div className="flex items-center gap-2 text-primary-600">
              <div className="w-2 h-2 rounded-full bg-primary-500 animate-pulse" style={{ animationDelay: '0.3s' }} />
              <span className="text-xs font-medium">分析你的技能与市场需求的契合度…</span>
            </div>
            <div className="flex items-center gap-2 text-primary-600">
              <div className="w-2 h-2 rounded-full bg-primary-500 animate-pulse" style={{ animationDelay: '0.6s' }} />
              <span className="text-xs font-medium">生成个性化变现方案…</span>
            </div>
          </div>
        )}

        {/* 诊断结果 */}
        {plans && plans.length > 0 && (
          <div className="space-y-3 animate-slide-up">
            <div className="flex items-center gap-2 px-1">
              <Sparkles size={16} className="text-primary-600" />
              <h2 className="text-sm font-bold text-ink-900">为你诊断出 {plans.length} 个变现方向</h2>
            </div>
            {plans.map((plan, idx) => {
              const cat = categoryConfig[plan.category];
              return (
                <div
                  key={plan.serviceName}
                  className="bg-white rounded-2xl p-4 shadow-card border border-ink-100 hover-lift"
                  style={{ animationDelay: `${idx * 0.1}s` }}
                >
                  <div className="flex items-start justify-between gap-2 mb-2">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 mb-1">
                        <span className="text-base">{cat.icon}</span>
                        <span className="text-[10px] px-1.5 py-0.5 rounded badge-gradient font-medium">{cat.label}</span>
                      </div>
                      <h3 className="font-semibold text-ink-900 text-sm leading-snug">{plan.serviceName}</h3>
                    </div>
                    {/* 匹配度环 */}
                    <div className="shrink-0 relative w-12 h-12">
                      <svg width="48" height="48" className="-rotate-90">
                        <circle cx="24" cy="24" r="20" fill="none" stroke="#EEF0FF" strokeWidth="4" />
                        <circle
                          cx="24" cy="24" r="20" fill="none" stroke="url(#gradMatch)" strokeWidth="4"
                          strokeLinecap="round"
                          strokeDasharray={2 * Math.PI * 20}
                          strokeDashoffset={2 * Math.PI * 20 * (1 - plan.matchScore / 100)}
                        />
                        <defs>
                          <linearGradient id="gradMatch" x1="0%" y1="0%" x2="100%" y2="100%">
                            <stop offset="0%" stopColor="#6366F1" />
                            <stop offset="100%" stopColor="#A855F7" />
                          </linearGradient>
                        </defs>
                      </svg>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <span className="text-xs font-bold text-gradient">{plan.matchScore}</span>
                      </div>
                    </div>
                  </div>

                  {/* 价格 + 难度 + 需求 */}
                  <div className="grid grid-cols-3 gap-2 my-3">
                    <div className="bg-ink-50 rounded-lg p-2 text-center">
                      <div className="text-[10px] text-ink-400 mb-0.5">建议单价</div>
                      <div className="text-xs font-bold text-gradient">
                        ¥{formatPrice(plan.priceRange[0])}-{formatPrice(plan.priceRange[1])}
                      </div>
                    </div>
                    <div className="bg-ink-50 rounded-lg p-2 text-center">
                      <div className="text-[10px] text-ink-400 mb-0.5">接单难度</div>
                      <div className="text-xs font-semibold text-ink-700">{DIFFICULTY_LABEL[plan.difficulty]}</div>
                    </div>
                    <div className="bg-ink-50 rounded-lg p-2 text-center">
                      <div className="text-[10px] text-ink-400 mb-0.5">市场需求</div>
                      <div className="text-xs font-semibold text-ink-700">{DEMAND_LABEL[plan.demand]}</div>
                    </div>
                  </div>

                  {/* AI 推理 */}
                  <div className="bg-gradient-blue-purple-soft rounded-lg p-2.5 mb-2">
                    <div className="flex items-center gap-1 mb-1">
                      <Sparkles size={11} className="text-primary-600" />
                      <span className="text-[10px] font-semibold text-primary-600">AI 推理</span>
                    </div>
                    <p className="text-[11px] text-ink-600 leading-relaxed">{plan.reasoning}</p>
                  </div>

                  {/* 接单建议 */}
                  <div className="flex items-start gap-1.5">
                    <Lightbulb size={12} className="text-warning-500 shrink-0 mt-0.5" />
                    <p className="text-[11px] text-ink-500 leading-relaxed flex-1">{plan.tips}</p>
                  </div>

                  {/* 去发布 */}
                  <button
                    onClick={() => { showToast('已为你预填该方向，去发布任务', 'success'); navigate('/publish'); }}
                    className="w-full mt-3 py-2 rounded-lg bg-ink-50 text-primary-600 text-xs font-medium flex items-center justify-center gap-1 btn-press hover:bg-primary-50"
                  >
                    去发布此类服务 <ChevronRight size={14} />
                  </button>
                </div>
              );
            })}
          </div>
        )}

        {plans && plans.length === 0 && (
          <div className="bg-white rounded-2xl p-8 shadow-card text-center animate-slide-up">
            <div className="text-4xl mb-2">🤔</div>
            <p className="text-sm text-ink-500">未匹配到合适的变现方向，试试补充更多技能</p>
          </div>
        )}
      </div>
    </div>
  );
}
