import { useState, useMemo } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { SlidersHorizontal, Plus } from 'lucide-react';
import { useStore } from '@/store';
import { categoryConfig } from '@/data/mock';
import type { TaskCategory } from '@/types';
import TaskCard from '@/components/TaskCard';
import Modal from '@/components/Modal';
import Empty from '@/components/Empty';
import { cn } from '@/lib/utils';

type SortKey = 'latest' | 'price' | 'hot';

const sortOptions: { key: SortKey; label: string }[] = [
  { key: 'latest', label: '最新' },
  { key: 'hot', label: '热度' },
  { key: 'price', label: '价格' },
];

export default function Tasks() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { tasks } = useStore();

  const catParam = searchParams.get('cat') as TaskCategory | null;
  const [activeCat, setActiveCat] = useState<TaskCategory | 'all'>(catParam || 'all');
  const [sort, setSort] = useState<SortKey>('latest');
  const [filterOpen, setFilterOpen] = useState(false);
  const [priceRange, setPriceRange] = useState<'all' | 'lt5' | '5to20' | 'gt20'>('all');
  const [statusFilter, setStatusFilter] = useState<'all' | 'OPEN'>('all');

  const categories = Object.entries(categoryConfig) as [TaskCategory, typeof categoryConfig[TaskCategory]][];

  const filtered = useMemo(() => {
    let list = tasks.slice();
    if (activeCat !== 'all') list = list.filter(t => t.category === activeCat);
    if (statusFilter === 'OPEN') list = list.filter(t => t.status === 'OPEN');
    if (priceRange !== 'all') {
      list = list.filter(t => {
        const yuan = t.price / 100;
        if (priceRange === 'lt5') return yuan < 5;
        if (priceRange === '5to20') return yuan >= 5 && yuan <= 20;
        return yuan > 20;
      });
    }
    if (sort === 'price') list.sort((a, b) => b.price - a.price);
    else if (sort === 'hot') list.sort((a, b) => b.hot - a.hot);
    return list;
  }, [tasks, activeCat, sort, priceRange, statusFilter]);

  const activeFilterCount = (priceRange !== 'all' ? 1 : 0) + (statusFilter !== 'all' ? 1 : 0);

  return (
    <div className="min-h-screen bg-ink-50">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="flex items-center justify-between h-14 px-4">
          <h1 className="font-display font-semibold text-base tracking-tight">任务市场</h1>
          <button
            onClick={() => setFilterOpen(true)}
            className="relative p-1.5 rounded-full bg-white/20 backdrop-blur btn-press"
          >
            <SlidersHorizontal size={18} className="text-white" />
            {activeFilterCount > 0 && (
              <span className="absolute -top-0.5 -right-0.5 w-2 h-2 bg-danger-500 rounded-full ring-2 ring-white/30" />
            )}
          </button>
        </div>

        {/* 分类标签 */}
        <div className="flex items-center gap-2 px-4 pb-2.5 overflow-x-auto no-scrollbar">
          <CatPill active={activeCat === 'all'} onClick={() => setActiveCat('all')}>全部</CatPill>
          {categories.map(([key, cfg]) => (
            <CatPill key={key} active={activeCat === key} onClick={() => setActiveCat(key)}>
              <span className="mr-0.5">{cfg.icon}</span>{cfg.label}
            </CatPill>
          ))}
        </div>
        {/* 排序 */}
        <div className="flex items-center gap-2 px-4 pb-3">
          {sortOptions.map(o => (
            <button
              key={o.key}
              onClick={() => setSort(o.key)}
              className={cn(
                'text-xs px-3 py-1 rounded-full font-medium transition-colors',
                sort === o.key ? 'bg-white text-primary-600' : 'bg-white/20 text-white/90'
              )}
            >
              {o.label}
            </button>
          ))}
          <span className="text-[11px] text-white/70 ml-auto">共 {filtered.length} 个任务</span>
        </div>
      </div>

      {/* 任务列表 */}
      <div className="px-4 py-3 space-y-2.5">
        {filtered.length > 0 ? (
          filtered.map(t => <TaskCard key={t.id} task={t} showStatus />)
        ) : (
          <Empty icon="🔍" title="没有符合条件的任务" desc="试试调整筛选或分类" />
        )}
      </div>

      <div className="h-24" />

      {/* 发布浮动按钮 - 渐变 */}
      <button
        onClick={() => navigate('/publish')}
        className="fixed bottom-20 right-4 w-14 h-14 flex items-center justify-center bg-gradient-blue-purple text-white rounded-full shadow-gradient-lg btn-press z-30"
      >
        <Plus size={26} strokeWidth={2.5} />
      </button>

      {/* 筛选弹窗 */}
      <Modal open={filterOpen} onClose={() => setFilterOpen(false)} title="筛选条件">
        <div className="px-5 py-4 space-y-5">
          <div>
            <h4 className="text-sm font-semibold text-ink-800 mb-2.5">价格区间</h4>
            <div className="flex flex-wrap gap-2">
              {([
                ['all', '不限'], ['lt5', '5元以下'], ['5to20', '5-20元'], ['gt20', '20元以上'],
              ] as const).map(([k, label]) => (
                <button
                  key={k}
                  onClick={() => setPriceRange(k)}
                  className={cn(
                    'text-xs px-3.5 py-1.5 rounded-full font-medium border transition-colors',
                    priceRange === k ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <h4 className="text-sm font-semibold text-ink-800 mb-2.5">任务状态</h4>
            <div className="flex flex-wrap gap-2">
              {([
                ['all', '全部'], ['OPEN', '仅可接单'],
              ] as const).map(([k, label]) => (
                <button
                  key={k}
                  onClick={() => setStatusFilter(k)}
                  className={cn(
                    'text-xs px-3.5 py-1.5 rounded-full font-medium border transition-colors',
                    statusFilter === k ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button
              onClick={() => { setPriceRange('all'); setStatusFilter('all'); }}
              className="flex-1 py-2.5 rounded-xl text-sm font-medium bg-ink-100 text-ink-600 btn-press"
            >
              重置
            </button>
            <button
              onClick={() => setFilterOpen(false)}
              className="flex-1 py-2.5 rounded-xl text-sm font-medium bg-gradient-blue-purple text-white btn-press shadow-gradient"
            >
              确定
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

function CatPill({ active, onClick, children }: { active: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        'shrink-0 text-xs px-3 py-1.5 rounded-full font-medium whitespace-nowrap transition-colors btn-press',
        active ? 'bg-white text-primary-600' : 'bg-white/20 text-white/90'
      )}
    >
      {children}
    </button>
  );
}
