import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Plus, Users, Flame, Lock, Clock, Infinity as InfinityIcon } from 'lucide-react';
import { useCountdown } from '@/lib/useCountdown';
import { useStore } from '@/store';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import Modal from '@/components/Modal';
import { cn } from '@/lib/utils';
import type { Circle } from '@/types';

const EMOJI_OPTIONS = ['📚', '🍜', '📷', '💻', '📖', '🗣️', '🎮', '🎵', '🏀', '🎨', '🎪'];

type TabKey = 'joined' | 'hot' | 'expiring';

export default function Circles() {
  const navigate = useNavigate();
  const { showToast, circles, createCircle } = useStore();
  const [tab, setTab] = useState<TabKey>('joined');
  const [createOpen, setCreateOpen] = useState(false);
  const [form, setForm] = useState({
    name: '',
    desc: '',
    icon: '📚',
    tags: '',
    memberLimit: 8,
    isPublic: true,
  });

  const filtered = (() => {
    if (tab === 'hot') return [...circles].sort((a, b) => b.hot - a.hot);
    if (tab === 'expiring') return circles.filter(c => c.lifecycle === 'expiring' || c.lifecycle === 'evaluating').sort((a, b) => (a.evaluateDeadline ?? 0) - (b.evaluateDeadline ?? 0));
    return circles;
  })();

  const handleSubmit = () => {
    if (!form.name.trim()) {
      showToast('请填写吧台名称', 'error');
      return;
    }
    const tags = form.tags
      .split(/[,，]/)
      .map(t => t.trim())
      .filter(Boolean)
      .slice(0, 3);
    const id = createCircle({
      name: form.name.trim(),
      desc: form.desc.trim(),
      icon: form.icon,
      tags,
      memberLimit: form.memberLimit,
      isPublic: form.isPublic,
    });
    setCreateOpen(false);
    setForm({ name: '', desc: '', icon: '📚', tags: '', memberLimit: 8, isPublic: true });
    showToast('吧台创建成功，进入24小时评估期', 'success');
    navigate(`/plaza/circles/${id}`);
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="px-4 pt-4 pb-3">
          <div className="flex items-center gap-1.5">
            <h1 className="font-display text-2xl font-bold">限时吧台</h1>
            <span className="px-1.5 py-0.5 rounded bg-white/20 text-[10px] font-medium">创新功能</span>
          </div>
          <p className="text-white/80 text-xs mt-0.5 leading-relaxed">
            临时兴趣群组 · 24h 评估期 · 活跃达标转永久，否则自动解散
          </p>
        </div>
        {/* Tab */}
        <div className="flex px-4">
          {([
            { key: 'joined', label: '全部吧台' },
            { key: 'hot', label: '热门' },
            { key: 'expiring', label: '即将解散' },
          ] as const).map(t => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={cn(
                'flex-1 py-2.5 text-sm font-medium relative btn-press',
                tab === t.key ? 'text-white' : 'text-white/60'
              )}
            >
              {t.label}
              {tab === t.key && (
                <span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-8 h-0.5 rounded-full bg-white" />
              )}
            </button>
          ))}
        </div>
      </div>

      {/* 吧台列表 */}
      <div className="p-3 space-y-2.5">
        {filtered.length === 0 ? (
          <Empty icon="🎪" title="暂无吧台" desc="创建一个限时吧台，召集同好吧" />
        ) : (
          filtered.map(circle => (
            <CircleCard key={circle.id} circle={circle} onClick={() => navigate(`/plaza/circles/${circle.id}`)} />
          ))
        )}
      </div>

      {/* 创建吧台浮动按钮 */}
      <button
        onClick={() => setCreateOpen(true)}
        className="fixed bottom-24 z-30 w-14 h-14 rounded-full bg-gradient-blue-purple text-white shadow-gradient-lg flex items-center justify-center btn-press"
        style={{ right: 'max(16px, calc(50% - 215px + 16px))' }}
        aria-label="创建吧台"
      >
        <Plus size={24} />
      </button>

      {/* 创建吧台弹窗 */}
      <Modal open={createOpen} onClose={() => setCreateOpen(false)} title="创建限时吧台">
        <div className="px-5 py-4 space-y-4 max-h-[70vh] overflow-y-auto">
          {/* 名称 */}
          <div>
            <label className="block text-xs font-medium text-ink-600 mb-1.5">吧台名称</label>
            <input
              value={form.name}
              onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
              placeholder="给吧台起个名字"
              maxLength={20}
              className="w-full px-3 py-2.5 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-300 focus:outline-none focus:border-primary-400 focus:bg-white transition-colors"
            />
          </div>

          {/* 简介 */}
          <div>
            <label className="block text-xs font-medium text-ink-600 mb-1.5">简介</label>
            <textarea
              value={form.desc}
              onChange={e => setForm(f => ({ ...f, desc: e.target.value }))}
              placeholder="简单介绍吧台主题和规则"
              rows={3}
              maxLength={100}
              className="w-full px-3 py-2.5 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-300 focus:outline-none focus:border-primary-400 focus:bg-white transition-colors resize-none"
            />
          </div>

          {/* 图标选择 */}
          <div>
            <label className="block text-xs font-medium text-ink-600 mb-1.5">吧台图标</label>
            <div className="grid grid-cols-6 gap-2">
              {EMOJI_OPTIONS.map(emoji => (
                <button
                  key={emoji}
                  onClick={() => setForm(f => ({ ...f, icon: emoji }))}
                  className={cn(
                    'aspect-square rounded-xl flex items-center justify-center text-2xl btn-press transition-all',
                    form.icon === emoji
                      ? 'bg-gradient-blue-purple-soft ring-2 ring-primary-400 scale-105'
                      : 'bg-ink-50 hover:bg-ink-100'
                  )}
                >
                  {emoji}
                </button>
              ))}
            </div>
          </div>

          {/* 标签 */}
          <div>
            <label className="block text-xs font-medium text-ink-600 mb-1.5">
              标签 <span className="text-ink-400">（逗号分隔，最多3个）</span>
            </label>
            <input
              value={form.tags}
              onChange={e => setForm(f => ({ ...f, tags: e.target.value }))}
              placeholder="如：学习, 高数, 期末"
              className="w-full px-3 py-2.5 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-300 focus:outline-none focus:border-primary-400 focus:bg-white transition-colors"
            />
          </div>

          {/* 成员上限 */}
          <div>
            <label className="block text-xs font-medium text-ink-600 mb-1.5">成员上限</label>
            <input
              type="number"
              min={2}
              max={50}
              value={form.memberLimit}
              onChange={e => setForm(f => ({ ...f, memberLimit: Math.max(2, Math.min(50, Number(e.target.value) || 8)) }))}
              className="w-full px-3 py-2.5 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 focus:outline-none focus:border-primary-400 focus:bg-white transition-colors"
            />
          </div>

          {/* 公开/私密开关 */}
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-ink-900">公开吧台</p>
              <p className="text-[11px] text-ink-400">{form.isPublic ? '任何人可见并加入' : '仅通过链接/申请加入'}</p>
            </div>
            <button
              onClick={() => setForm(f => ({ ...f, isPublic: !f.isPublic }))}
              className={cn(
                'relative w-11 h-6 rounded-full transition-colors btn-press',
                form.isPublic ? 'bg-primary-500' : 'bg-ink-200'
              )}
            >
              <span
                className={cn(
                  'absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform',
                  form.isPublic && 'translate-x-5'
                )}
              />
            </button>
          </div>
        </div>

        {/* 底部操作 */}
        <div className="flex gap-2 px-5 py-3 border-t border-ink-100">
          <button
            onClick={() => setCreateOpen(false)}
            className="flex-1 py-3 rounded-xl bg-ink-100 text-ink-600 text-sm font-medium btn-press"
          >
            取消
          </button>
          <button
            onClick={handleSubmit}
            className="flex-[2] py-3 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold shadow-gradient btn-press"
          >
            创建吧台
          </button>
        </div>
      </Modal>
    </div>
  );
}

function CircleCard({ circle, onClick }: { circle: Circle; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="w-full bg-white rounded-2xl p-3.5 shadow-card border border-ink-100 hover-lift text-left btn-press animate-fade-in"
    >
      <div className="flex items-start gap-3">
        {/* 图标 */}
        <div className="w-12 h-12 rounded-xl bg-gradient-blue-purple-soft flex items-center justify-center text-2xl shrink-0">
          {circle.icon}
        </div>

        <div className="flex-1 min-w-0">
          {/* 标题行 */}
          <div className="flex items-center gap-1.5 mb-0.5">
            {!circle.isPublic && <Lock size={11} className="text-ink-400 shrink-0" />}
            <h3 className="font-semibold text-ink-900 text-sm truncate">{circle.name}</h3>
            <LifecycleBadge circle={circle} />
          </div>

          {/* 描述 */}
          <p className="text-[11px] text-ink-500 line-clamp-1 mb-1.5">{circle.desc}</p>

          {/* 标签 */}
          <div className="flex flex-wrap gap-1 mb-2">
            {circle.tags.slice(0, 3).map(tag => (
              <span key={tag} className="text-[10px] px-1.5 py-0.5 rounded badge-gradient">#{tag}</span>
            ))}
          </div>

          {/* 底部信息 */}
          <div className="flex items-center justify-between gap-2">
            <div className="flex items-center gap-2.5 text-[11px] text-ink-400">
              <span className="flex items-center gap-0.5">
                <Users size={11} />
                {circle.members.length}/{circle.memberLimit}
              </span>
              <span className="flex items-center gap-0.5">
                <Flame size={11} className="text-warning-500" />
                {circle.hot}
              </span>
              <span className="text-ink-300 truncate max-w-[100px]">{circle.lastMessage}</span>
            </div>
            {circle.unread > 0 && (
              <span className="inline-flex items-center justify-center min-w-[16px] h-4 px-1 rounded-full bg-danger-500 text-white text-[10px] font-semibold">
                {circle.unread}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* 限时倒计时条 */}
      {circle.lifecycle !== 'permanent' && circle.evaluateDeadline && (
        <CountdownBar circle={circle} />
      )}
    </button>
  );
}

function LifecycleBadge({ circle }: { circle: Circle }) {
  if (circle.lifecycle === 'permanent') {
    return (
      <span className="shrink-0 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded bg-success-50 text-success-600 text-[10px] font-semibold">
        <InfinityIcon size={9} /> 永久
      </span>
    );
  }
  if (circle.lifecycle === 'expiring') {
    return (
      <span className="shrink-0 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded bg-danger-50 text-danger-600 text-[10px] font-semibold animate-pulse">
        <Clock size={9} /> 即将解散
      </span>
    );
  }
  return (
    <span className="shrink-0 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded bg-primary-50 text-primary-600 text-[10px] font-semibold">
      <Clock size={9} /> 评估中
    </span>
  );
}

function CountdownBar({ circle }: { circle: Circle }) {
  const { hours, minutes, seconds, expired } = useCountdown(circle.evaluateDeadline);
  const progress = circle.activityScore / circle.activityThreshold;
  const isExpiring = circle.lifecycle === 'expiring';

  if (expired) return null;

  const timeStr = `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;

  return (
    <div className={cn('mt-2.5 rounded-lg p-2', isExpiring ? 'bg-danger-50' : 'bg-primary-50')}>
      <div className="flex items-center justify-between mb-1.5">
        <div className="flex items-center gap-1">
          <Clock size={11} className={isExpiring ? 'text-danger-500' : 'text-primary-500'} />
          <span className={cn('text-[10px] font-semibold', isExpiring ? 'text-danger-600' : 'text-primary-600')}>
            {isExpiring ? '即将解散' : '评估倒计时'}
          </span>
          <span className={cn('text-[11px] font-bold font-mono', isExpiring ? 'text-danger-700' : 'text-primary-700')}>
            {timeStr}
          </span>
        </div>
        <span className="text-[10px] text-ink-500">
          活跃 {circle.activityScore}/{circle.activityThreshold}
        </span>
      </div>
      {/* 活跃度进度条 */}
      <div className="h-1.5 rounded-full bg-white/60 overflow-hidden">
        <div
          className={cn('h-full rounded-full transition-all duration-500', progress >= 1 ? 'bg-gradient-success' : isExpiring ? 'bg-gradient-rose' : 'bg-gradient-blue-purple')}
          style={{ width: `${Math.min(100, progress * 100)}%` }}
        />
      </div>
      {progress >= 1 ? (
        <p className="text-[10px] text-success-600 mt-1 font-medium">已达活跃阈值，即将转为永久吧台</p>
      ) : isExpiring ? (
        <p className="text-[10px] text-danger-500 mt-1">活跃不足，到期后将自动解散</p>
      ) : (
        <p className="text-[10px] text-ink-400 mt-1">达到活跃阈值即可转为永久</p>
      )}
    </div>
  );
}
