import { HashRouter as Router, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { useEffect } from 'react';
import PhoneShell from '@/components/PhoneShell';

// 用户端页面
import Home from '@/pages/user/Home';
import Tasks from '@/pages/user/Tasks';
import TaskDetail from '@/pages/user/TaskDetail';
import Publish from '@/pages/user/Publish';
import Orders from '@/pages/user/Orders';
import OrderDetail from '@/pages/user/OrderDetail';
import Messages from '@/pages/user/Messages';
import Chat from '@/pages/user/Chat';
import Plaza from '@/pages/user/Plaza';
import NewsList from '@/pages/user/NewsList';
import PostDetail from '@/pages/user/PostDetail';
import Profile from '@/pages/user/Profile';
import Wallet from '@/pages/user/Wallet';
import Credit from '@/pages/user/Credit';
import Settings from '@/pages/user/Settings';
import Notifications from '@/pages/user/Notifications';
import AISkillDiagnosis from '@/pages/user/AISkillDiagnosis';
import AIPersonality from '@/pages/user/AIPersonality';
import Circles from '@/pages/user/Circles';
import CircleDetail from '@/pages/user/CircleDetail';
import Favorites from '@/pages/user/Favorites';
import Achievements from '@/pages/user/Achievements';

// 管理端页面
import AdminDashboard from '@/pages/admin/AdminDashboard';
import AdminTasks from '@/pages/admin/AdminTasks';
import AdminOrders from '@/pages/admin/AdminOrders';
import AdminUsers from '@/pages/admin/AdminUsers';
import AdminFinance from '@/pages/admin/AdminFinance';
import AdminContent from '@/pages/admin/AdminContent';

function ScrollToTop() {
  const { pathname } = useLocation();
  useEffect(() => { window.scrollTo(0, 0); }, [pathname]);
  return null;
}

function AppRoutes() {
  return (
    <PhoneShell>
      <ScrollToTop />
      <Routes>
        {/* 用户端 */}
        <Route path="/" element={<Home />} />
        <Route path="/tasks" element={<Tasks />} />
        <Route path="/tasks/:id" element={<TaskDetail />} />
        <Route path="/publish" element={<Publish />} />
        <Route path="/orders" element={<Orders />} />
        <Route path="/orders/:id" element={<OrderDetail />} />
        <Route path="/messages" element={<Messages />} />
        <Route path="/messages/:id" element={<Chat />} />
        <Route path="/plaza" element={<Plaza />} />
        <Route path="/plaza/news" element={<NewsList />} />
        <Route path="/plaza/post/:id" element={<PostDetail />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/profile/wallet" element={<Wallet />} />
        <Route path="/profile/credit" element={<Credit />} />
        <Route path="/profile/settings" element={<Settings />} />
        <Route path="/notifications" element={<Notifications />} />
        <Route path="/profile/ai-skill" element={<AISkillDiagnosis />} />
        <Route path="/profile/ai-personality" element={<AIPersonality />} />
        <Route path="/plaza/circles" element={<Circles />} />
        <Route path="/plaza/circles/:id" element={<CircleDetail />} />
        <Route path="/profile/favorites" element={<Favorites />} />
        <Route path="/profile/achievements" element={<Achievements />} />

        {/* 管理端 */}
        <Route path="/admin" element={<AdminDashboard />} />
        <Route path="/admin/tasks" element={<AdminTasks />} />
        <Route path="/admin/orders" element={<AdminOrders />} />
        <Route path="/admin/users" element={<AdminUsers />} />
        <Route path="/admin/finance" element={<AdminFinance />} />
        <Route path="/admin/content" element={<AdminContent />} />

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </PhoneShell>
  );
}

export default function App() {
  return (
    <Router>
      <AppRoutes />
    </Router>
  );
}
