import { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Bell, ChevronRight } from 'lucide-react';
import PageHeader from '@/components/PageHeader';
import StatusBadge from '@/components/StatusBadge';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { formatPrice, categoryConfig } from '@/data/mock';
import { cn } from '@/lib/utils';
import type { TaskStatus } from '@/types';

type TabKey = 'all' | 'open' | 'doing' | 'confirm' | 'done' | 'closed';

const TABS: { key: TabKey; label: string; statuses: TaskStatus[] }[] = [
  { key: 'all', label: '全部', statuses: [] },
  { key: 'open', label: '待接单', statuses: ['OPEN'] },
  { key: 'doing', label: '进行中', statuses: ['ACCEPTED', 'IN_PROGRESS'] },
  { key: 'confirm', label: '待验收', statuses: ['WAITING_CONFIRM'] },
  { key: 'done', label: '已完成', statuses: ['COMPLETED'] },
  { key: 'closed', label: '退款关闭', statuses: ['REFUNDED', 'CLOSED', 'EXPIRED'] },
];

export default function Orders() {
  const navigate = useNavigate();
  const orders = useStore(s => s.orders);
  const user = useStore(s => s.user);
  const [tab, setTab] = useState<TabKey>('all');

  const filtered = useMemo(() => {
    const target = TABS.find(t => t.key === tab)!;
    if (target.statuses.length === 0) return orders;
    return orders.filter(o => target.statuses.includes(o.status));
  }, [orders, tab]);

  return (
    <div className="min-h-screen bg-ink-50">
      <PageHeader
        title="我的订单"
        right={
          <button
            onClick={() => navigate('/notifications')}
            className="relative p-2 -mr-1 rounded-full hover:bg-ink-100 btn-press"
            aria-label="通知"
          >
            <Bell size={20} className="text-ink-700" />
          </button>
        }
      >
        {/* 状态 Tabs */}
        <div className="flex gap-1 px-3 pb-2 overflow-x-auto no-scrollbar">
          {TABS.map(t => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={cn(
                'shrink-0 px-3.5 py-1.5 rounded-full text-xs font-medium transition-all btn-press',
                tab === t.key
                  ? 'bg-gradient-blue-purple text-white shadow-gradient'
                  : 'bg-white text-ink-500 border border-ink-200'
              )}
            >
              {t.label}
            </button>
          ))}
        </div>
      </PageHeader>

      <div className="p-3 space-y-3">
        {filtered.length === 0 ? (
          <Empty
            icon="📭"
            title="暂无订单"
            desc="去任务大厅看看，接一单试试吧"
            action={
              <button
                onClick={() => navigate('/tasks')}
                className="px-4 py-2 rounded-full bg-gradient-blue-purple text-white text-xs font-medium btn-press shadow-gradient"
              >
                去看看
              </button>
            }
          />
        ) : (
          filtered.map(order => {
            const isAccepter = order.accepterId === user.id;
            const counterparty = isAccepter ? order.task.publisher : order.task.accepter;
            const cat = categoryConfig[order.task.category];
            const lastTime = order.timeline[order.timeline.length - 1]?.time || order.updatedAt;

            return (
              <Link
                key={order.id}
                to={`/orders/${order.id}`}
                className="block bg-white rounded-2xl p-3.5 shadow-card hover:shadow-soft transition-shadow btn-press animate-fade-in"
              >
                <div className="flex items-start gap-3">
                  <div
                    className="w-11 h-11 rounded-xl flex items-center justify-center text-xl shrink-0"
                    style={{ backgroundColor: cat.color + '15' }}
                  >
                    {cat.icon}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <h3 className="font-semibold text-ink-900 text-sm line-clamp-1 leading-snug">
                        {order.task.title}
                      </h3>
                      <StatusBadge status={order.status} />
                    </div>
                    <div className="flex items-center gap-1.5 mt-1.5">
                      <span
                        className="text-[11px] px-1.5 py-0.5 rounded font-medium"
                        style={{ color: cat.color, backgroundColor: cat.color + '12' }}
                      >
                        {cat.label}
                      </span>
                      <span className="text-[11px] text-ink-400">订单号 {order.id}</span>
                    </div>
                    {counterparty && (
                      <div className="flex items-center gap-1.5 mt-2">
                        <Avatar src={counterparty.avatar} name={counterparty.nickname} size={18} />
                        <span className="text-[11px] text-ink-500">
                          {isAccepter ? '发布者' : '接单者'}：{counterparty.nickname}
                        </span>
                        <span className="text-[11px] text-ink-300">·</span>
                        <span className="text-[11px] text-ink-400">{lastTime}</span>
                      </div>
                    )}
                  </div>
                  <div className="text-right shrink-0">
                    <div className="text-lg font-bold text-warning-600 font-display">
                      ¥{formatPrice(order.amount)}
                    </div>
                    <div className="flex items-center justify-end text-[11px] text-ink-400 mt-1">
                      详情 <ChevronRight size={12} />
                    </div>
                  </div>
                </div>
              </Link>
            );
          })
        )}
      </div>
    </div>
  );
}
