import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Star, MapPin, Clock, CheckCircle2, AlertCircle, XCircle } from 'lucide-react';
import PageHeader from '@/components/PageHeader';
import Avatar from '@/components/Avatar';
import StatusBadge from '@/components/StatusBadge';
import RatingModal from '@/components/RatingModal';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { formatPrice, categoryConfig, statusConfig } from '@/data/mock';
import { cn } from '@/lib/utils';
import type { TaskStatus } from '@/types';

const ACTIVE_STATUSES: TaskStatus[] = ['OPEN', 'ACCEPTED', 'IN_PROGRESS', 'WAITING_CONFIRM'];

export default function OrderDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getOrder, transitionOrder, showToast, user } = useStore();
  const order = id ? getOrder(id) : undefined;
  const [ratingOpen, setRatingOpen] = useState(false);

  if (!order) {
    return (
      <div className="min-h-screen bg-ink-50">
        <PageHeader title="订单详情" />
        <Empty icon="🔍" title="订单不存在" desc="该订单可能已被删除" />
      </div>
    );
  }

  const task = order.task;
  const cat = categoryConfig[task.category];
  const isAccepter = order.accepterId === user.id;
  const counterparty = isAccepter ? task.publisher : task.accepter;
  const counterpartyLabel = isAccepter ? '发布者' : '接单者';
  const statusCfg = statusConfig[order.status] || { label: order.status, color: '#64748B', bg: '#F1F5F9' };
  const isActive = ACTIVE_STATUSES.includes(order.status);
  const canRate = order.status === 'COMPLETED' && !order.rating;

  const handleTransition = (to: TaskStatus, desc: string, msg: string) => {
    transitionOrder(order.id, to, desc);
    showToast(msg, 'success');
  };

  const BannerIcon = order.status === 'COMPLETED' ? CheckCircle2 :
    order.status === 'WAITING_CONFIRM' ? Clock :
    (order.status === 'REFUNDED' || order.status === 'CLOSED' || order.status === 'EXPIRED') ? XCircle : AlertCircle;

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      <PageHeader title="订单详情" />

      <div className="p-3 space-y-3">
        {/* 状态 Banner */}
        <div className="rounded-2xl p-4 animate-fade-in" style={{ backgroundColor: statusCfg.bg }}>
          <div className="flex items-center gap-2.5">
            <span className="w-9 h-9 rounded-full flex items-center justify-center text-white shrink-0" style={{ backgroundColor: statusCfg.color }}>
              <BannerIcon size={20} />
            </span>
            <div className="flex-1 min-w-0">
              <div className="font-display font-semibold text-base" style={{ color: statusCfg.color }}>{statusCfg.label}</div>
              <div className="text-xs text-ink-500 mt-0.5">{order.timeline[order.timeline.length - 1]?.desc || '订单进行中'}</div>
            </div>
            <StatusBadge status={order.status} size="md" />
          </div>
        </div>

        {/* 任务快照 */}
        <div className="bg-white rounded-2xl p-4 shadow-card animate-fade-in">
          <div className="flex items-center gap-2 mb-3">
            <span className="text-[11px] px-2 py-0.5 rounded font-medium" style={{ color: cat.color, backgroundColor: cat.color + '12' }}>{cat.icon} {cat.label}</span>
            <span className="text-[11px] text-ink-400">任务编号 {task.id}</span>
          </div>
          <h2 className="font-semibold text-ink-900 text-base leading-snug">{task.title}</h2>
          <div className="flex items-center gap-3 mt-2 text-[11px] text-ink-400">
            <span className="flex items-center gap-0.5"><MapPin size={12} />{task.location}</span>
            <span className="flex items-center gap-0.5"><Clock size={12} />{task.deadline}</span>
          </div>
          <div className="mt-3 pt-3 border-t border-ink-100 flex items-center justify-between">
            <span className="text-xs text-ink-500">任务金额</span>
            <span className="text-xl font-bold text-warning-600 font-display">¥{formatPrice(task.price)}</span>
          </div>
        </div>

        {/* 交易对手信息 */}
        {counterparty && (
          <div className="bg-white rounded-2xl p-4 shadow-card animate-fade-in">
            <div className="text-xs text-ink-400 mb-2.5">{counterpartyLabel}</div>
            <div className="flex items-center gap-3">
              <Avatar src={counterparty.avatar} name={counterparty.nickname} size={44} ring />
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-1.5">
                  <span className="font-semibold text-ink-900 text-sm">{counterparty.nickname}</span>
                  {counterparty.verified && <span className="text-[10px] px-1.5 py-0.5 rounded bg-success-100 text-success-600 font-medium">已认证</span>}
                </div>
                <div className="text-[11px] text-ink-400 mt-0.5">信誉 {counterparty.creditScore} · 完成率 {counterparty.completeRate}% · {counterparty.taskCount}单</div>
              </div>
              <button onClick={() => navigate('/messages')} className="px-3 py-1.5 rounded-full bg-primary-50 text-primary-600 text-xs font-medium btn-press">联系</button>
            </div>
          </div>
        )}

        {/* 费用明细 */}
        <div className="bg-white rounded-2xl p-4 shadow-card animate-fade-in">
          <div className="text-xs text-ink-400 mb-3">费用明细</div>
          <div className="space-y-2.5">
            <div className="flex items-center justify-between text-sm">
              <span className="text-ink-600">任务金额</span>
              <span className="text-ink-900 font-medium">¥{formatPrice(order.amount)}</span>
            </div>
            <div className="flex items-center justify-between text-sm">
              <span className="text-ink-600">平台服务费</span>
              <span className="text-ink-500">-¥{formatPrice(order.serviceFee)}</span>
            </div>
            <div className="flex items-center justify-between text-sm pt-2.5 border-t border-ink-100">
              <span className="text-ink-600">接单者收入</span>
              <span className="text-success-600 font-display font-bold text-base">¥{formatPrice(order.accepterIncome)}</span>
            </div>
          </div>
        </div>

        {/* 状态时间线 */}
        <div className="bg-white rounded-2xl p-4 shadow-card animate-fade-in">
          <div className="text-xs text-ink-400 mb-3">订单进度</div>
          <div className="relative">
            {order.timeline.map((item, idx) => {
              const isLast = idx === order.timeline.length - 1;
              const itemCfg = statusConfig[item.status] || { color: '#64748B', label: item.status };
              return (
                <div key={idx} className="flex gap-3 relative">
                  <div className="flex flex-col items-center">
                    <div className={cn('w-3 h-3 rounded-full mt-1 shrink-0')} style={{ backgroundColor: itemCfg.color, boxShadow: isLast ? `0 0 0 3px ${itemCfg.color}25` : 'none' }} />
                    {!isLast && <div className="w-0.5 flex-1 bg-ink-200 my-1" style={{ minHeight: 24 }} />}
                  </div>
                  <div className={cn('flex-1', isLast ? 'pb-0' : 'pb-4')}>
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-medium text-ink-900">{itemCfg.label}</span>
                      <span className="text-[11px] text-ink-400">{item.time}</span>
                    </div>
                    {item.desc && <div className="text-xs text-ink-500 mt-0.5">{item.desc}</div>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* 已有评价 */}
        {order.rating && (
          <div className="bg-white rounded-2xl p-4 shadow-card animate-fade-in">
            <div className="text-xs text-ink-400 mb-2">订单评价</div>
            <div className="flex items-center gap-1 mb-2">
              {[1, 2, 3, 4, 5].map(i => (
                <Star key={i} size={16} className={i <= order.rating!.score ? 'text-warning-500' : 'text-ink-200'} fill={i <= order.rating!.score ? 'currentColor' : 'none'} />
              ))}
              <span className="text-sm font-semibold text-ink-900 ml-1">{order.rating.score}.0</span>
            </div>
            {order.rating.tags.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mb-2">
                {order.rating.tags.map(tag => (
                  <span key={tag} className="text-[11px] px-2 py-0.5 rounded-full bg-warning-50 text-warning-600 font-medium">{tag}</span>
                ))}
              </div>
            )}
            {order.rating.comment && <p className="text-sm text-ink-600 leading-relaxed">{order.rating.comment}</p>}
          </div>
        )}
      </div>

      {/* 底部操作栏 */}
      <div className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-white border-t border-ink-100 p-3 z-30" style={{ paddingBottom: 'calc(0.75rem + var(--safe-bottom))' }}>
        <div className="flex items-center gap-2">
          {isActive && (
            <>
              <button onClick={() => showToast('已提交取消申请', 'info')} className="flex-1 py-2.5 rounded-xl border border-ink-200 text-ink-600 text-sm font-medium btn-press">申请取消</button>
              <button onClick={() => showToast('已提交申诉', 'info')} className="flex-1 py-2.5 rounded-xl border border-ink-200 text-ink-600 text-sm font-medium btn-press">申诉</button>
            </>
          )}
          {order.status === 'ACCEPTED' && (
            <button onClick={() => handleTransition('IN_PROGRESS', '接单者开始履约', '已开始履约')} className="flex-1 py-2.5 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold btn-press shadow-gradient">开始履约</button>
          )}
          {order.status === 'IN_PROGRESS' && (
            <button onClick={() => handleTransition('WAITING_CONFIRM', '接单者提交完成凭证', '已提交完成，等待验收')} className="flex-1 py-2.5 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold btn-press shadow-gradient">提交完成</button>
          )}
          {order.status === 'WAITING_CONFIRM' && (
            <button disabled className="flex-1 py-2.5 rounded-xl bg-ink-100 text-ink-400 text-sm font-semibold cursor-not-allowed">等待验收中…</button>
          )}
          {canRate && (
            <button onClick={() => setRatingOpen(true)} className="flex-1 py-2.5 rounded-xl bg-warning-500 text-white text-sm font-semibold btn-press shadow-sm">去评价</button>
          )}
          {!isActive && !canRate && (
            <button onClick={() => navigate(-1)} className="flex-1 py-2.5 rounded-xl bg-ink-100 text-ink-600 text-sm font-medium btn-press">返回</button>
          )}
        </div>
      </div>

      <RatingModal open={ratingOpen} orderId={order.id} onClose={() => setRatingOpen(false)} />
    </div>
  );
}
