import { useState } from 'react';
import { Lock, CheckCircle2, Trophy, Sparkles, TrendingUp } from 'lucide-react';
import PageHeader from '@/components/PageHeader';
import { achievements } from '@/data/mock';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

export default function Achievements() {
  const { user, showToast } = useStore();
  const [tab, setTab] = useState<'all' | 'unlocked' | 'locked'>('all');

  const unlocked = achievements.filter(a => a.unlocked);
  const locked = achievements.filter(a => !a.unlocked);
  const progressPercent = Math.round((unlocked.length / achievements.length) * 100);

  const display = tab === 'unlocked' ? unlocked : tab === 'locked' ? locked : achievements;

  return (
    <div className="min-h-screen bg-ink-50 pb-6">
      <PageHeader title="我的成就" back />

      <div className="px-3 pt-3 space-y-3">
        {/* 成就总览卡 - 渐变 */}
        <div className="bg-gradient-blue-purple text-white rounded-2xl p-4 shadow-gradient-lg animate-slide-up">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-1.5">
              <Trophy size={18} />
              <span className="font-display font-semibold text-sm">成就总览</span>
            </div>
            <span className="text-white/80 text-xs">{unlocked.length}/{achievements.length}</span>
          </div>
          {/* 进度条 */}
          <div className="h-2.5 rounded-full bg-white/20 overflow-hidden mb-2">
            <div
              className="h-full rounded-full bg-white transition-all duration-700"
              style={{ width: `${progressPercent}%` }}
            />
          </div>
          <div className="flex items-center justify-between text-xs">
            <span className="text-white/80">已解锁 {progressPercent}%</span>
            <span className="text-white/80">还差 {locked.length} 个</span>
          </div>
        </div>

        {/* 等级与经验 */}
        <div className="bg-white rounded-2xl p-4 shadow-card border border-ink-100 animate-slide-up">
          <div className="flex items-center gap-3">
            <div className="w-14 h-14 rounded-2xl bg-gradient-blue-purple flex items-center justify-center shadow-gradient shrink-0">
              <span className="font-display text-xl font-bold text-white">Lv.{user.level}</span>
            </div>
            <div className="flex-1">
              <div className="flex items-center justify-between mb-1">
                <span className="text-sm font-semibold text-ink-900">当前等级</span>
                <span className="text-xs text-ink-400">经验 {user.exp}</span>
              </div>
              {/* 经验进度 */}
              <div className="h-2 rounded-full bg-ink-100 overflow-hidden">
                <div className="h-full rounded-full bg-gradient-blue-purple" style={{ width: `${Math.min(100, (user.exp % 1000) / 10)}%` }} />
              </div>
              <p className="text-[10px] text-ink-400 mt-1">距下一级还需 {1000 - (user.exp % 1000)} 经验</p>
            </div>
          </div>
        </div>

        {/* Tab 筛选 */}
        <div className="flex gap-2">
          {([
            { key: 'all', label: '全部', count: achievements.length },
            { key: 'unlocked', label: '已解锁', count: unlocked.length },
            { key: 'locked', label: '未解锁', count: locked.length },
          ] as const).map(t => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={cn(
                'flex-1 py-2 rounded-xl text-xs font-medium border transition-all btn-press',
                tab === t.key ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
              )}
            >
              {t.label} ({t.count})
            </button>
          ))}
        </div>

        {/* 成就列表 */}
        <div className="grid grid-cols-2 gap-2.5">
          {display.map(ach => (
            <AchievementCard key={ach.id} achievement={ach} onClick={() => showToast(`${ach.name}：${ach.desc}`, 'info')} />
          ))}
        </div>

        {/* 成就说明 */}
        <div className="bg-white rounded-2xl p-4 shadow-card border border-ink-100">
          <div className="flex items-center gap-1.5 mb-2">
            <Sparkles size={14} className="text-primary-600" />
            <h3 className="text-sm font-bold text-ink-900">成就说明</h3>
          </div>
          <ul className="space-y-1.5 text-[11px] text-ink-500 leading-relaxed">
            <li className="flex items-start gap-1.5">
              <span className="text-primary-500 mt-0.5">·</span>
              完成任务、获得好评、参与社区均可解锁成就
            </li>
            <li className="flex items-start gap-1.5">
              <span className="text-primary-500 mt-0.5">·</span>
              部分成就需要累计完成多次，进度可查看
            </li>
            <li className="flex items-start gap-1.5">
              <span className="text-primary-500 mt-0.5">·</span>
              解锁成就会获得经验值奖励，助力等级提升
            </li>
            <li className="flex items-start gap-1.5">
              <span className="text-primary-500 mt-0.5">·</span>
              <span className="text-warning-600 font-medium">社区领袖</span>：创建的吧台转为永久并保持活跃即可解锁
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
}

function AchievementCard({ achievement, onClick }: { achievement: typeof achievements[0]; onClick: () => void }) {
  const { unlocked, name, desc, icon, unlockedAt, progress } = achievement;

  return (
    <button
      onClick={onClick}
      className={cn(
        'rounded-2xl p-3.5 shadow-card border text-left btn-press hover-lift relative overflow-hidden',
        unlocked ? 'bg-white border-ink-100' : 'bg-ink-50 border-ink-100'
      )}
    >
      {/* 已解锁标记 */}
      {unlocked && (
        <div className="absolute top-2 right-2">
          <CheckCircle2 size={14} className="text-success-500 fill-success-50" />
        </div>
      )}

      {/* 图标 */}
      <div className={cn(
        'w-14 h-14 rounded-2xl flex items-center justify-center text-3xl mb-2 mx-auto',
        unlocked ? 'bg-gradient-blue-purple-soft' : 'bg-ink-100 grayscale opacity-60'
      )}>
        {unlocked ? icon : <Lock size={22} className="text-ink-400" />}
      </div>

      {/* 名称 */}
      <h3 className={cn('text-sm font-bold text-center mb-1', unlocked ? 'text-ink-900' : 'text-ink-400')}>
        {name}
      </h3>

      {/* 描述 */}
      <p className={cn('text-[10px] text-center leading-tight line-clamp-2', unlocked ? 'text-ink-500' : 'text-ink-400')}>
        {desc}
      </p>

      {/* 进度/解锁时间 */}
      {unlocked ? (
        <div className="mt-2 pt-2 border-t border-ink-100 text-center">
          <span className="text-[10px] text-success-600 font-medium flex items-center justify-center gap-0.5">
            <TrendingUp size={9} /> {unlockedAt} 解锁
          </span>
        </div>
      ) : progress !== undefined ? (
        <div className="mt-2 pt-2 border-t border-ink-100">
          <div className="flex items-center justify-between text-[10px] mb-1">
            <span className="text-ink-400">进度</span>
            <span className="text-primary-600 font-semibold">{progress}/5</span>
          </div>
          <div className="h-1.5 rounded-full bg-ink-100 overflow-hidden">
            <div className="h-full rounded-full bg-gradient-blue-purple" style={{ width: `${(progress / 5) * 100}%` }} />
          </div>
        </div>
      ) : (
        <div className="mt-2 pt-2 border-t border-ink-100 text-center">
          <span className="text-[10px] text-ink-400">未开始</span>
        </div>
      )}
    </button>
  );
}
