import { useState } from 'react';
import {
  Smartphone, History, UserX, Globe, Search, Eye, Sparkles,
  Bell, MessageSquare, Info, Moon, Languages, Palette,
  FileText, Shield, ChevronRight, LogOut, type LucideIcon,
} from 'lucide-react';
import { useStore } from '@/store';
import PageHeader from '@/components/PageHeader';
import { cn } from '@/lib/utils';

export default function Settings() {
  const { showToast } = useStore();

  const [privacy, setPrivacy] = useState({
    publicProfile: true,
    searchable: true,
    onlineStatus: false,
    personalized: true,
  });
  const [notif, setNotif] = useState({
    task: true,
    chat: true,
    system: false,
    dnd: false,
  });

  return (
    <div className="min-h-screen pb-6 bg-ink-50">
      <PageHeader title="设置" back />

      <div className="px-3 py-3 space-y-3">
        {/* 账号安全 */}
        <Section title="账号安全">
          <RowItem icon={Smartphone} label="设备管理" onClick={() => showToast('当前仅1台设备在线（iPhone）', 'info')} />
          <RowItem icon={History} label="登录记录" onClick={() => showToast('最近登录：今天 14:32 · 清华大学', 'info')} />
          <RowItem icon={UserX} label="注销账号" danger onClick={() => showToast('注销功能请联系客服处理', 'info')} />
        </Section>

        {/* 隐私设置 */}
        <Section title="隐私设置">
          <ToggleRow
            icon={Globe}
            label="公开主页"
            checked={privacy.publicProfile}
            onChange={v => setPrivacy({ ...privacy, publicProfile: v })}
          />
          <ToggleRow
            icon={Search}
            label="允许搜索"
            checked={privacy.searchable}
            onChange={v => setPrivacy({ ...privacy, searchable: v })}
          />
          <ToggleRow
            icon={Eye}
            label="在线状态"
            checked={privacy.onlineStatus}
            onChange={v => setPrivacy({ ...privacy, onlineStatus: v })}
          />
          <ToggleRow
            icon={Sparkles}
            label="个性化推荐"
            checked={privacy.personalized}
            onChange={v => setPrivacy({ ...privacy, personalized: v })}
          />
        </Section>

        {/* 通知设置 */}
        <Section title="通知设置">
          <ToggleRow
            icon={Bell}
            label="任务通知"
            checked={notif.task}
            onChange={v => setNotif({ ...notif, task: v })}
          />
          <ToggleRow
            icon={MessageSquare}
            label="聊天通知"
            checked={notif.chat}
            onChange={v => setNotif({ ...notif, chat: v })}
          />
          <ToggleRow
            icon={Info}
            label="系统通知"
            checked={notif.system}
            onChange={v => setNotif({ ...notif, system: v })}
          />
          <ToggleRow
            icon={Moon}
            label="免打扰时段"
            checked={notif.dnd}
            onChange={v => setNotif({ ...notif, dnd: v })}
          />
        </Section>

        {/* 通用 */}
        <Section title="通用">
          <RowItem icon={Languages} label="语言" value="简体中文" onClick={() => showToast('当前仅支持简体中文', 'info')} />
          <RowItem icon={Palette} label="主题" value="浅色" onClick={() => showToast('当前为浅色主题', 'info')} />
        </Section>

        {/* 关于 */}
        <Section title="关于">
          <RowItem icon={FileText} label="用户协议" onClick={() => showToast('用户协议 v2.0 已更新', 'info')} />
          <RowItem icon={Shield} label="隐私政策" onClick={() => showToast('隐私政策 v2.0 已更新', 'info')} />
          <RowItem icon={Info} label="版本信息" value="v1.0.0" onClick={() => showToast('校园Pro v1.0.0', 'info')} />
        </Section>

        {/* 退出登录 */}
        <button
          onClick={() => showToast('已退出登录（Demo）', 'success')}
          className="w-full bg-white rounded-2xl p-4 shadow-card flex items-center justify-center gap-2 text-danger-500 font-medium btn-press"
        >
          <LogOut size={18} />
          退出登录
        </button>

        <p className="text-center text-[11px] text-ink-400 pt-2">校园Pro © 2026 · 让校园生活更高效</p>
      </div>
    </div>
  );
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <div>
      <p className="text-xs text-ink-400 font-medium px-1 mb-1.5">{title}</p>
      <div className="bg-white rounded-2xl shadow-card overflow-hidden">{children}</div>
    </div>
  );
}

function RowItem({
  icon: Icon, label, value, danger, onClick,
}: { icon: LucideIcon; label: string; value?: string; danger?: boolean; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="w-full flex items-center gap-3 p-3.5 btn-press border-b border-ink-100 last:border-b-0"
    >
      <Icon size={18} className={cn(danger ? 'text-danger-500' : 'text-ink-500')} />
      <span className={cn('flex-1 text-left text-sm', danger ? 'text-danger-500' : 'text-ink-800')}>{label}</span>
      {value && <span className="text-xs text-ink-400">{value}</span>}
      <ChevronRight size={16} className="text-ink-300" />
    </button>
  );
}

function ToggleRow({
  icon: Icon, label, checked, onChange,
}: { icon: LucideIcon; label: string; checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <div className="flex items-center gap-3 p-3.5 border-b border-ink-100 last:border-b-0">
      <Icon size={18} className="text-ink-500" />
      <span className="flex-1 text-sm text-ink-800">{label}</span>
      <button
        onClick={() => onChange(!checked)}
        className={cn(
          'relative w-11 h-6 rounded-full transition-colors btn-press',
          checked ? 'bg-gradient-blue-purple' : 'bg-ink-200'
        )}
      >
        <span
          className={cn(
            'absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform',
            checked && 'translate-x-5'
          )}
        />
      </button>
    </div>
  );
}
