import { useEffect } from 'react';
import { CheckCircle2, XCircle, Info } from 'lucide-react';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

export default function Toast() {
  const toast = useStore(s => s.toast);
  const hideToast = useStore(s => s.hideToast);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(hideToast, 2500);
      return () => clearTimeout(timer);
    }
  }, [toast, hideToast]);

  if (!toast) return null;

  const icons = {
    success: <CheckCircle2 size={18} className="text-success-500" />,
    error: <XCircle size={18} className="text-danger-300" />,
    info: <Info size={18} className="text-primary-500" />,
  };

  return (
    <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[100] animate-slide-down">
      <div className={cn(
        'flex items-center gap-2.5 px-4 py-3 rounded-2xl glass-strong shadow-float max-w-[360px]',
      )}>
        {icons[toast.type]}
        <span className="text-sm text-ink-800 font-medium">{toast.message}</span>
      </div>
    </div>
  );
}
