import { type ReactNode } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChevronLeft } from 'lucide-react';
import { cn } from '@/lib/utils';

interface PageHeaderProps {
  title?: string;
  back?: boolean;
  right?: ReactNode;
  className?: string;
  bg?: string;
  children?: ReactNode;
}

export default function PageHeader({ title, back = true, right, className, bg = 'bg-header-sci-fi-blue', children }: PageHeaderProps) {
  const navigate = useNavigate();
  return (
    <header
      className={cn('sticky top-0 z-40 text-white', bg, className)}
      style={{ paddingTop: 'var(--safe-top)' }}
    >
      <div className="flex items-center justify-between h-14 px-4">
        <div className="flex items-center gap-2 min-w-0">
          {back && (
            <button onClick={() => navigate(-1)} className="p-1.5 -ml-1.5 rounded-xl hover:bg-white/20 btn-press shrink-0">
              <ChevronLeft size={20} className="text-white" />
            </button>
          )}
          {title && <h1 className="font-display font-semibold text-white text-base tracking-tight truncate">{title}</h1>}
        </div>
        {right && <div className="shrink-0">{right}</div>}
      </div>
      {children}
    </header>
  );
}
