import { useState } from 'react';
import { Gavel, Eye, Clock, ArrowRight } from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import Avatar from '@/components/Avatar';
import StatusBadge from '@/components/StatusBadge';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { adminOrders, getUser, formatPrice, statusConfig } from '@/data/mock';
import { cn } from '@/lib/utils';

const tabs = [
  { label: '全部', value: 'ALL' },
  { label: '待接单', value: 'OPEN' },
  { label: '履约中', value: 'IN_PROGRESS' },
  { label: '待验收', value: 'WAITING_CONFIRM' },
  { label: '已完成', value: 'COMPLETED' },
  { label: '申诉中', value: 'DISPUTED' },
];

export default function AdminOrders() {
  const showToast = useStore(s => s.showToast);
  const [tab, setTab] = useState('ALL');

  const filtered = adminOrders.filter(o => tab === 'ALL' || o.status === tab);

  return (
    <AdminLayout>
      {/* 状态筛选 */}
      <div className="bg-white rounded-2xl p-3 shadow-card">
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
          {tabs.map(t => (
            <button
              key={t.value}
              onClick={() => setTab(t.value)}
              className={cn(
                'px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors',
                tab === t.value ? 'bg-primary-600 text-white' : 'bg-ink-100 text-ink-500'
              )}
            >
              {t.label}
            </button>
          ))}
        </div>
      </div>

      {/* 订单列表 */}
      <div className="mt-3 bg-white rounded-2xl shadow-card overflow-hidden">
        <div className="px-4 py-3 border-b border-ink-100 flex items-center justify-between">
          <h2 className="font-display font-semibold text-ink-900 text-sm">订单列表</h2>
          <span className="text-xs text-ink-400">共 {filtered.length} 条</span>
        </div>

        {filtered.length === 0 ? (
          <Empty icon="📋" title="暂无订单" desc="该状态下没有订单" />
        ) : (
          <div className="divide-y divide-ink-100">
            {filtered.map(order => {
              const publisher = getUser(order.publisherId);
              const accepter = order.accepterId ? getUser(order.accepterId) : null;
              const isDisputed = order.status === 'DISPUTED';
              const lastTimeline = order.timeline[order.timeline.length - 1];

              return (
                <div key={order.id} className="p-3.5 hover:bg-ink-50/50 transition-colors">
                  {/* 订单头部 */}
                  <div className="flex items-center justify-between gap-2">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-mono text-ink-500">{order.id}</span>
                      <StatusBadge status={order.status} />
                    </div>
                    <span className="text-[11px] text-ink-400">{order.createdAt}</span>
                  </div>

                  {/* 任务标题 + 金额 */}
                  <div className="mt-2 flex items-start justify-between gap-2">
                    <h3 className="font-semibold text-ink-900 text-sm line-clamp-1 flex-1">
                      {order.task.title}
                    </h3>
                    <div className="text-right shrink-0">
                      <div className="text-base font-bold text-warning-600 font-display">¥{formatPrice(order.amount)}</div>
                      <div className="text-[10px] text-ink-400">服务费 ¥{formatPrice(order.serviceFee)}</div>
                    </div>
                  </div>

                  {/* 双方信息 */}
                  <div className="mt-2 flex items-center gap-2 text-[11px] text-ink-500">
                    <span className="flex items-center gap-1">
                      <Avatar src={publisher.avatar} name={publisher.nickname} size={16} />
                      {publisher.nickname}
                    </span>
                    <ArrowRight size={12} className="text-ink-300" />
                    {accepter ? (
                      <span className="flex items-center gap-1">
                        <Avatar src={accepter.avatar} name={accepter.nickname} size={16} />
                        {accepter.nickname}
                      </span>
                    ) : (
                      <span className="text-ink-400">待接单</span>
                    )}
                  </div>

                  {/* 时间线预览 */}
                  {lastTimeline && (
                    <div className="mt-2 flex items-center gap-1.5 text-[11px] text-ink-400 bg-ink-50 rounded-lg px-2 py-1.5">
                      <Clock size={12} />
                      <span style={{ color: statusConfig[order.status]?.color }}>
                        {lastTimeline.desc}
                      </span>
                      <span>· {lastTimeline.time}</span>
                    </div>
                  )}

                  {/* 操作按钮 */}
                  <div className="mt-2.5 flex items-center gap-1.5">
                    {isDisputed ? (
                      <button
                        onClick={() => showToast(`已介入仲裁订单 ${order.id}`, 'info')}
                        className="flex items-center gap-1 px-3 py-1 rounded-lg bg-danger-500 text-white text-xs font-medium hover:bg-danger-600 btn-press"
                      >
                        <Gavel size={13} /> 仲裁
                      </button>
                    ) : null}
                    <button
                      onClick={() => showToast(`查看订单 ${order.id} 详情`, 'info')}
                      className="flex items-center gap-1 px-3 py-1 rounded-lg bg-ink-100 text-ink-700 text-xs font-medium hover:bg-ink-200 btn-press"
                    >
                      <Eye size={13} /> 查看详情
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
