import { type ReactNode } from 'react';
import { cn } from '@/lib/utils';

interface EmptyProps {
  icon?: ReactNode;
  title?: string;
  desc?: string;
  action?: ReactNode;
  className?: string;
}

export default function Empty({ icon, title = '暂无内容', desc, action, className }: EmptyProps) {
  return (
    <div className={cn('flex flex-col items-center justify-center py-16 px-6 text-center', className)}>
      <div className="w-16 h-16 rounded-2xl bg-ink-200 flex items-center justify-center text-3xl mb-4 opacity-50">{icon || '📭'}</div>
      <h3 className="text-ink-600 font-medium text-sm">{title}</h3>
      {desc && <p className="text-ink-400 text-xs mt-1 max-w-[200px]">{desc}</p>}
      {action && <div className="mt-4">{action}</div>}
    </div>
  );
}
