import { Link } from 'react-router-dom';
import {
  Users, UserPlus, ListTodo, FilePlus2, TrendingUp, DollarSign,
  CheckCircle2, AlertTriangle, ShieldAlert, Gavel, Wallet, ArrowRight, ClipboardList,
} from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import { adminStats } from '@/data/mock';
import { cn } from '@/lib/utils';

const statCards = [
  { label: '总用户数', value: adminStats.totalUsers.toLocaleString(), icon: Users, color: '#2563EB', bg: '#DBEAFE', today: `今日 +${adminStats.todayNewUsers}` },
  { label: '总任务数', value: adminStats.totalTasks.toLocaleString(), icon: ListTodo, color: '#10B981', bg: '#D1FAE5', today: `今日 +${adminStats.todayNewTasks}` },
  { label: '总成交额', value: `¥${adminStats.totalGMV.toLocaleString()}`, icon: DollarSign, color: '#F59E0B', bg: '#FEF3C7', today: `今日 ¥${adminStats.todayGMV.toLocaleString()}` },
  { label: '今日新增用户', value: adminStats.todayNewUsers, icon: UserPlus, color: '#8B5CF6', bg: '#EDE9FE', today: '实时统计' },
  { label: '今日新增任务', value: adminStats.todayNewTasks, icon: FilePlus2, color: '#06B6D4', bg: '#CFFAFE', today: '实时统计' },
  { label: '今日成交额', value: `¥${adminStats.todayGMV.toLocaleString()}`, icon: TrendingUp, color: '#EC4899', bg: '#FCE7F3', today: '实时统计' },
];

const todos = [
  { label: '待审核任务', value: adminStats.pendingReviews, link: '/admin/tasks', icon: ListTodo, color: 'text-warning-600', bg: 'bg-warning-50' },
  { label: '待处理申诉', value: adminStats.pendingAppeals, link: '/admin/orders', icon: Gavel, color: 'text-danger-600', bg: 'bg-danger-50' },
  { label: '财务异常', value: adminStats.financialAnomalies, link: '/admin/finance', icon: ShieldAlert, color: 'text-danger-600', bg: 'bg-danger-50' },
];

export default function AdminDashboard() {
  const hasAnomalies = adminStats.financialAnomalies > 0;

  return (
    <AdminLayout>
      {/* 统计卡片 */}
      <section className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        {statCards.map(card => (
          <div key={card.label} className="bg-white rounded-xl p-3.5 shadow-card">
            <div className="flex items-center justify-between">
              <div
                className="w-9 h-9 rounded-lg flex items-center justify-center"
                style={{ backgroundColor: card.bg }}
              >
                <card.icon size={18} style={{ color: card.color }} />
              </div>
            </div>
            <div className="mt-2.5">
              <div className="text-xl font-bold text-ink-900 font-display">{card.value}</div>
              <div className="text-xs text-ink-500 mt-0.5">{card.label}</div>
              <div className="text-[11px] text-ink-400 mt-1">{card.today}</div>
            </div>
          </div>
        ))}
      </section>

      {/* 关键指标 + 待办 */}
      <section className="grid grid-cols-1 lg:grid-cols-3 gap-4 mt-4">
        {/* 关键指标 */}
        <div className="lg:col-span-2 bg-white rounded-2xl p-4 shadow-card">
          <h2 className="font-display font-semibold text-ink-900 text-sm mb-3">关键运营指标</h2>
          <div className="grid grid-cols-2 gap-3">
            {/* 完成率 */}
            <div className="border border-ink-100 rounded-xl p-3">
              <div className="flex items-center justify-between">
                <span className="text-xs text-ink-500 flex items-center gap-1">
                  <CheckCircle2 size={14} className="text-success-500" />订单完成率
                </span>
                <span className="text-sm font-bold text-success-600 font-display">{adminStats.completeRate}%</span>
              </div>
              <div className="mt-2 h-2 bg-ink-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-success-500 rounded-full transition-all"
                  style={{ width: `${adminStats.completeRate}%` }}
                />
              </div>
            </div>
            {/* 争议率 */}
            <div className="border border-ink-100 rounded-xl p-3">
              <div className="flex items-center justify-between">
                <span className="text-xs text-ink-500 flex items-center gap-1">
                  <AlertTriangle size={14} className="text-warning-500" />订单争议率
                </span>
                <span className="text-sm font-bold text-warning-600 font-display">{adminStats.disputeRate}%</span>
              </div>
              <div className="mt-2 h-2 bg-ink-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-warning-500 rounded-full transition-all"
                  style={{ width: `${Math.min(adminStats.disputeRate * 10, 100)}%` }}
                />
              </div>
            </div>
            {/* 待审核 */}
            <div className="border border-ink-100 rounded-xl p-3 flex items-center justify-between">
              <span className="text-xs text-ink-500">待审核任务</span>
              <span className="text-lg font-bold text-warning-600 font-display">{adminStats.pendingReviews}</span>
            </div>
            {/* 待申诉 */}
            <div className="border border-ink-100 rounded-xl p-3 flex items-center justify-between">
              <span className="text-xs text-ink-500">待处理申诉</span>
              <span className="text-lg font-bold text-danger-600 font-display">{adminStats.pendingAppeals}</span>
            </div>
          </div>
        </div>

        {/* 待办事项 */}
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <h2 className="font-display font-semibold text-ink-900 text-sm mb-3">待办事项</h2>
          <div className="space-y-2">
            {todos.map(todo => (
              <Link
                key={todo.label}
                to={todo.link}
                className="flex items-center justify-between p-2.5 rounded-xl hover:bg-ink-50 transition-colors group"
              >
                <div className="flex items-center gap-2.5">
                  <div className={cn('w-8 h-8 rounded-lg flex items-center justify-center', todo.bg)}>
                    <todo.icon size={16} className={todo.color} />
                  </div>
                  <span className="text-sm text-ink-700">{todo.label}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className={cn('text-sm font-bold font-display', todo.color)}>{todo.value}</span>
                  <ArrowRight size={14} className="text-ink-300 group-hover:text-ink-500 transition-colors" />
                </div>
              </Link>
            ))}
          </div>
        </div>
      </section>

      {/* 风险预警 */}
      {hasAnomalies && (
        <section className="mt-4 bg-gradient-to-r from-danger-50 to-warning-50 border border-danger-100 rounded-2xl p-4">
          <div className="flex items-start gap-3">
            <div className="w-10 h-10 rounded-xl bg-danger-500 flex items-center justify-center shrink-0">
              <ShieldAlert size={20} className="text-white" />
            </div>
            <div className="flex-1">
              <h2 className="font-display font-semibold text-danger-600 text-sm">风险预警</h2>
              <p className="text-xs text-ink-600 mt-1">
                检测到 <span className="font-bold text-danger-600">{adminStats.financialAnomalies}</span> 笔财务异常交易，请及时核查处理。
              </p>
              <Link
                to="/admin/finance"
                className="inline-flex items-center gap-1 mt-2 text-xs font-medium text-danger-600 hover:underline"
              >
                立即处理 <ArrowRight size={12} />
              </Link>
            </div>
          </div>
        </section>
      )}

      {/* 快捷入口 */}
      <section className="mt-4 grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: '任务管理', link: '/admin/tasks', icon: ListTodo, color: '#2563EB' },
          { label: '订单管理', link: '/admin/orders', icon: ClipboardList, color: '#10B981' },
          { label: '用户管理', link: '/admin/users', icon: Users, color: '#8B5CF6' },
          { label: '财务管理', link: '/admin/finance', icon: Wallet, color: '#F59E0B' },
        ].map(item => (
          <Link
            key={item.label}
            to={item.link}
            className="bg-white rounded-xl p-3 shadow-card flex items-center gap-2.5 hover:shadow-soft transition-shadow btn-press"
          >
            <div
              className="w-9 h-9 rounded-lg flex items-center justify-center"
              style={{ backgroundColor: item.color + '15' }}
            >
              <item.icon size={18} style={{ color: item.color }} />
            </div>
            <span className="text-sm font-medium text-ink-700">{item.label}</span>
          </Link>
        ))}
      </section>
    </AdminLayout>
  );
}
