import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Heart, Trash2, Search } from 'lucide-react';
import PageHeader from '@/components/PageHeader';
import TaskCard from '@/components/TaskCard';
import Empty from '@/components/Empty';
import { tasks, categoryConfig } from '@/data/mock';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';
import type { TaskCategory } from '@/types';

export default function Favorites() {
  const navigate = useNavigate();
  const { showToast, favorites, toggleFavorite } = useStore();
  // 收藏列表从 store 的 favorites 读取
  const favTasks = tasks.filter(t => favorites.includes(t.id));
  const [filter, setFilter] = useState<TaskCategory | 'all'>('all');
  const [keyword, setKeyword] = useState('');

  const categories = Array.from(new Set(favTasks.map(t => t.category)));
  const filtered = favTasks
    .filter(t => filter === 'all' || t.category === filter)
    .filter(t => !keyword || t.title.toLowerCase().includes(keyword.toLowerCase()));

  const removeFav = (id: string) => {
    toggleFavorite(id);
    showToast('已取消收藏', 'info');
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-6">
      <PageHeader title="我的收藏" back />

      {/* 搜索栏 */}
      <div className="px-3 pt-3">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-400" />
          <input
            value={keyword}
            onChange={e => setKeyword(e.target.value)}
            placeholder="搜索收藏的任务"
            className="w-full h-10 pl-9 pr-3 rounded-xl bg-white border border-ink-200 text-sm focus:outline-none focus:border-primary-400"
          />
        </div>
      </div>

      {/* 分类筛选 */}
      {categories.length > 0 && (
        <div className="px-3 pt-3 flex gap-2 overflow-x-auto no-scrollbar">
          <button
            onClick={() => setFilter('all')}
            className={cn(
              'shrink-0 px-3 py-1.5 rounded-full text-xs font-medium border transition-all btn-press',
              filter === 'all' ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
            )}
          >
            全部 ({favTasks.length})
          </button>
          {categories.map(cat => {
            const c = categoryConfig[cat];
            const count = favTasks.filter(t => t.category === cat).length;
            return (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={cn(
                  'shrink-0 px-3 py-1.5 rounded-full text-xs font-medium border transition-all btn-press flex items-center gap-1',
                  filter === cat ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
                )}
              >
                <span>{c.icon}</span> {c.label} ({count})
              </button>
            );
          })}
        </div>
      )}

      {/* 收藏列表 */}
      <div className="px-3 pt-3 space-y-2.5">
        {filtered.length === 0 ? (
          <Empty
            icon="💔"
            title={favTasks.length === 0 ? '还没有收藏' : '未找到匹配任务'}
            desc={favTasks.length === 0 ? '去任务市场收藏感兴趣的 task 吧' : '试试换个关键词'}
            action={
              favTasks.length === 0 && (
                <button onClick={() => navigate('/tasks')} className="px-4 py-2 rounded-full bg-gradient-blue-purple text-white text-sm shadow-gradient">
                  去任务市场
                </button>
              )
            }
          />
        ) : (
          filtered.map(task => (
            <div key={task.id} className="relative group">
              <TaskCard task={task} />
              <button
                onClick={() => removeFav(task.id)}
                className="absolute top-2 right-2 w-8 h-8 rounded-full bg-white/90 backdrop-blur shadow-card flex items-center justify-center btn-press hover:bg-danger-50"
                aria-label="取消收藏"
              >
                <Trash2 size={14} className="text-danger-500" />
              </button>
            </div>
          ))
        )}
      </div>

      {/* 底部统计 */}
      {favTasks.length > 0 && (
        <div className="px-3 pt-4">
          <div className="bg-white rounded-xl p-3 shadow-card flex items-center justify-between text-xs text-ink-500">
            <span className="flex items-center gap-1">
              <Heart size={12} className="text-danger-500 fill-danger-500" />
              共收藏 {favTasks.length} 个任务
            </span>
            <button
              onClick={() => { favTasks.forEach(t => toggleFavorite(t.id)); showToast('已清空收藏', 'info'); }}
              className="text-danger-500 font-medium btn-press"
            >
              清空收藏
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
