import { useState, useMemo } from 'react';
import {
  ArrowDownCircle, ArrowUpCircle, Percent, RotateCcw, Banknote,
  TrendingUp, TrendingDown,
} from 'lucide-react';
import { walletTransactions } from '@/data/mock';
import { useStore } from '@/store';
import type { WalletTransaction } from '@/types';
import PageHeader from '@/components/PageHeader';
import Empty from '@/components/Empty';
import { formatPrice } from '@/data/mock';
import { cn } from '@/lib/utils';

const typeConfig: Record<WalletTransaction['type'], { icon: typeof ArrowDownCircle; color: string; bg: string; label: string }> = {
  income: { icon: ArrowDownCircle, color: '#10B981', bg: '#ECFDF5', label: '收入' },
  pay: { icon: ArrowUpCircle, color: '#EF4444', bg: '#FEF2F2', label: '支出' },
  fee: { icon: Percent, color: '#F59E0B', bg: '#FFFBEB', label: '手续费' },
  refund: { icon: RotateCcw, color: '#3B82F6', bg: '#EFF6FF', label: '退款' },
  withdraw: { icon: Banknote, color: '#8B5CF6', bg: '#F5F3FF', label: '提现' },
  adjust: { icon: Percent, color: '#64748B', bg: '#F1F5F9', label: '调整' },
};

const filters = [
  { key: 'all', label: '全部' },
  { key: 'income', label: '收入' },
  { key: 'expense', label: '支出' },
] as const;

export default function Wallet() {
  const { user, showToast } = useStore();
  const [filter, setFilter] = useState<typeof filters[number]['key']>('all');
  const [withdrawOpen, setWithdrawOpen] = useState(false);
  const [withdrawAmount, setWithdrawAmount] = useState('');

  const filtered = useMemo(() => {
    if (filter === 'all') return walletTransactions;
    if (filter === 'income') return walletTransactions.filter(t => t.amount > 0);
    return walletTransactions.filter(t => t.amount < 0);
  }, [filter]);

  // 按日期分组
  const groups = useMemo(() => {
    const map = new Map<string, WalletTransaction[]>();
    filtered.forEach(t => {
      const date = t.createdAt.split(' ')[0];
      if (!map.has(date)) map.set(date, []);
      map.get(date)!.push(t);
    });
    return Array.from(map.entries());
  }, [filtered]);

  return (
    <div className="min-h-screen pb-6 bg-ink-50">
      <PageHeader title="我的钱包" back />

      <div className="px-3 py-3 space-y-3">
        {/* 余额卡片 - 蓝紫渐变 */}
        <div className="bg-gradient-blue-purple text-white rounded-2xl p-4 shadow-gradient-lg animate-slide-up">
          <p className="text-white/70 text-xs">可用余额（元）</p>
          <p className="font-display text-3xl font-bold mt-1">{formatPrice(user.balance)}</p>
          <div className="flex gap-4 mt-3 pt-3 border-t border-white/20">
            <div>
              <p className="text-white/70 text-[11px]">待结算</p>
              <p className="font-semibold text-sm">{formatPrice(user.pendingSettle)}</p>
            </div>
            <div>
              <p className="text-white/70 text-[11px]">冻结金额</p>
              <p className="font-semibold text-sm">{formatPrice(user.frozen)}</p>
            </div>
          </div>
          <button
            onClick={() => setWithdrawOpen(true)}
            className="w-full mt-3 py-2.5 rounded-xl bg-white text-primary-600 text-sm font-semibold btn-press shadow-sm"
          >
            提现
          </button>
        </div>

        {/* 收支汇总 */}
        <div className="grid grid-cols-2 gap-3">
          <div className="bg-gradient-card rounded-2xl p-3.5 shadow-soft-xs border border-white">
            <div className="flex items-center gap-1.5 text-success-500">
              <TrendingUp size={16} />
              <span className="text-xs text-ink-500">累计收入</span>
            </div>
            <p className="font-display text-lg font-bold text-ink-900 mt-1">¥{formatPrice(user.totalIncome)}</p>
          </div>
          <div className="bg-gradient-card rounded-2xl p-3.5 shadow-soft-xs border border-white">
            <div className="flex items-center gap-1.5 text-danger-500">
              <TrendingDown size={16} />
              <span className="text-xs text-ink-500">累计支出</span>
            </div>
            <p className="font-display text-lg font-bold text-ink-900 mt-1">¥{formatPrice(user.totalExpense)}</p>
          </div>
        </div>

        {/* 流水筛选 */}
        <div className="flex gap-2">
          {filters.map(f => (
            <button
              key={f.key}
              onClick={() => setFilter(f.key)}
              className={cn(
                'px-3 py-1.5 rounded-full text-xs font-medium transition-colors btn-press',
                filter === f.key ? 'bg-gradient-blue-purple text-white shadow-gradient' : 'bg-white text-ink-600 shadow-soft-xs'
              )}
            >
              {f.label}
            </button>
          ))}
        </div>

        {/* 流水列表 */}
        {groups.length === 0 ? (
          <Empty icon="💸" title="暂无记录" />
        ) : (
          <div className="space-y-3">
            {groups.map(([date, items]) => (
              <div key={date}>
                <p className="text-xs text-ink-400 font-medium px-1 mb-1.5">{date}</p>
                <div className="bg-white rounded-2xl shadow-card overflow-hidden">
                  {items.map((t, i) => (
                    <TxItem key={t.id} tx={t} last={i === items.length - 1} />
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* 提现弹窗 */}
      {withdrawOpen && (
        <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center" onClick={() => setWithdrawOpen(false)}>
          <div className="absolute inset-0 bg-black/40 animate-fade-in" />
          <div
            className="relative bg-white w-full max-w-[430px] rounded-t-3xl md:rounded-3xl p-5 animate-slide-up"
            onClick={e => e.stopPropagation()}
          >
            <h3 className="font-display font-bold text-base text-ink-900 mb-4">提现到银行卡</h3>
            <div className="bg-ink-50 rounded-xl p-3 mb-4">
              <p className="text-[11px] text-ink-400">可提现余额</p>
              <p className="font-display text-2xl font-bold text-gradient">¥{formatPrice(user.balance)}</p>
            </div>
            <div className="mb-3">
              <label className="text-xs text-ink-500 mb-1.5 block">提现金额（元）</label>
              <input
                type="number"
                value={withdrawAmount}
                onChange={e => setWithdrawAmount(e.target.value)}
                placeholder={`最多可提 ${formatPrice(user.balance)}`}
                className="w-full h-11 px-3 rounded-xl bg-ink-50 border border-ink-200 text-sm focus:outline-none focus:border-primary-400"
              />
            </div>
            <div className="mb-4">
              <label className="text-xs text-ink-500 mb-1.5 block">收款银行卡</label>
              <div className="h-11 px-3 rounded-xl bg-ink-50 border border-ink-200 flex items-center text-sm text-ink-600">
                招商银行 ****8866
              </div>
            </div>
            <p className="text-[11px] text-ink-400 mb-4">预计 2 小时内到账，单笔最低 1 元，手续费 0.1%</p>
            <button
              onClick={() => {
                const amt = parseFloat(withdrawAmount) || 0;
                if (amt <= 0) { showToast('请输入提现金额', 'error'); return; }
                if (amt * 100 > user.balance) { showToast('余额不足', 'error'); return; }
                showToast(`提现申请已提交，¥${amt.toFixed(2)} 预计2小时到账`, 'success');
                setWithdrawOpen(false);
                setWithdrawAmount('');
              }}
              className="w-full py-3 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold shadow-gradient btn-press"
            >
              确认提现
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function TxItem({ tx, last }: { tx: WalletTransaction; last: boolean }) {
  const cfg = typeConfig[tx.type];
  const Icon = cfg.icon;
  const isIncome = tx.amount > 0;

  return (
    <div className={cn('flex items-center gap-3 p-3', !last && 'border-b border-ink-100')}>
      <div
        className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0"
        style={{ backgroundColor: cfg.bg }}
      >
        <Icon size={20} style={{ color: cfg.color }} />
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm text-ink-800 font-medium truncate">{tx.desc}</p>
        <p className="text-[11px] text-ink-400 mt-0.5">{tx.createdAt} · 余额 ¥{formatPrice(tx.balanceAfter)}</p>
      </div>
      <div className="text-right shrink-0">
        <p
          className="font-display font-bold text-sm"
          style={{ color: isIncome ? '#10B981' : '#EF4444' }}
        >
          {isIncome ? '+' : ''}{formatPrice(tx.amount)}
        </p>
        <p className="text-[10px] text-ink-400">{cfg.label}</p>
      </div>
    </div>
  );
}
