import { NavLink, useLocation } from 'react-router-dom';
import { Home, ListTodo, MessageCircle, LayoutGrid, User } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useStore } from '@/store';

const tabs = [
  { to: '/', icon: Home, label: '首页' },
  { to: '/tasks', icon: ListTodo, label: '任务' },
  { to: '/messages', icon: MessageCircle, label: '消息' },
  { to: '/plaza', icon: LayoutGrid, label: '广场' },
  { to: '/profile', icon: User, label: '我的' },
];

export default function TabBar() {
  const location = useLocation();
  const conversations = useStore(s => s.conversations);
  const notifications = useStore(s => s.notifications);
  const unreadMsg = conversations.reduce((sum, c) => sum + c.unread, 0);
  const unreadNotif = notifications.filter(n => !n.read).length;
  const unread = unreadMsg + unreadNotif;

  return (
    <nav
      className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] glass-strong z-50"
      style={{ paddingBottom: 'var(--safe-bottom)', borderTop: '1px solid #EAE6DE' }}
    >
      <div className="flex items-stretch justify-around h-14">
        {tabs.map(tab => {
          const isActive = tab.to === '/' ? location.pathname === '/' : location.pathname.startsWith(tab.to);
          const showBadge = (tab.to === '/messages' && unread > 0);
          return (
            <NavLink key={tab.to} to={tab.to} className="flex-1 flex flex-col items-center justify-center gap-0.5 relative btn-press">
              <div className="relative">
                <tab.icon
                  size={21}
                  className={cn('transition-all', isActive ? 'text-primary-500' : 'text-ink-400')}
                  strokeWidth={isActive ? 2.4 : 1.8}
                />
                {showBadge && (
                  <span className="absolute -top-1.5 -right-2 min-w-[16px] h-4 px-1 bg-gradient-rose text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-sm">
                    {unread > 99 ? '99+' : unread}
                  </span>
                )}
              </div>
              <span className={cn('text-[10px] transition-all tracking-wide', isActive ? 'text-primary-500 font-semibold' : 'text-ink-400')}>
                {tab.label}
              </span>
              {isActive && <span className="absolute top-0 w-7 h-1 rounded-full bg-gradient-blue-purple" />}
            </NavLink>
          );
        })}
      </div>
    </nav>
  );
}
