import { useState, useRef, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ChevronLeft, Send, Image as ImageIcon, MoreVertical } from 'lucide-react';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

export default function Chat() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { conversations, messages, sendMessage, markRead, user } = useStore();

  const conversation = conversations.find(c => c.id === id);
  const msgList = id ? (messages[id] || []) : [];

  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // 进入会话时标记已读
  useEffect(() => {
    if (id) markRead(id);
  }, [id, markRead]);

  // 新消息自动滚动到底部
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [msgList.length]);

  if (!conversation) {
    return (
      <div className="min-h-screen bg-ink-50">
        <header className="sticky top-0 z-40 bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
          <div className="flex items-center justify-between h-14 px-3">
            <button onClick={() => navigate(-1)} className="p-1 rounded-full hover:bg-white/20 btn-press">
              <ChevronLeft size={22} className="text-white" />
            </button>
            <h1 className="font-display font-semibold text-white text-base">会话</h1>
            <div className="w-8" />
          </div>
        </header>
        <Empty icon="🔍" title="会话不存在" desc="该会话可能已被删除" />
      </div>
    );
  }

  const peer = conversation.peer;

  const handleSend = () => {
    const content = input.trim();
    if (!content || !id) return;
    sendMessage(id, content);
    setInput('');
  };

  return (
    <div className="min-h-screen bg-ink-50 flex flex-col">
      {/* 自定义头部 - 科幻蓝 */}
      <header
        className="sticky top-0 z-40 bg-header-sci-fi-blue text-white"
        style={{ paddingTop: 'var(--safe-top)' }}
      >
        <div className="flex items-center gap-2 h-14 px-3">
          <button onClick={() => navigate(-1)} className="p-1 rounded-full hover:bg-white/20 btn-press">
            <ChevronLeft size={22} className="text-white" />
          </button>
          <Avatar src={peer.avatar} name={peer.nickname} size={32} />
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-1.5">
              <span className="font-semibold text-white text-sm truncate">{peer.nickname}</span>
              {conversation.online && (
                <span className="flex items-center gap-0.5 text-[10px] text-success-300">
                  <span className="w-1.5 h-1.5 rounded-full bg-success-400" />
                  在线
                </span>
              )}
            </div>
            <div className="text-[11px] text-white/70 truncate">{conversation.source}</div>
          </div>
          <button className="p-1.5 rounded-full hover:bg-white/20 btn-press">
            <MoreVertical size={18} className="text-white/80" />
          </button>
        </div>
      </header>

      {/* 消息列表 */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto px-3 py-4 space-y-3">
        <div className="text-center">
          <span className="text-[11px] text-ink-400 px-2 py-0.5 rounded-full bg-ink-100">
            会话来源于「{conversation.source}」
          </span>
        </div>
        {msgList.map(msg => {
          const isMine = msg.senderId === user.id;

          if (msg.type === 'system') {
            return (
              <div key={msg.id} className="text-center">
                <span className="text-[11px] text-ink-400 px-2 py-0.5 rounded-full bg-ink-100">
                  {msg.content}
                </span>
              </div>
            );
          }

          if (msg.type === 'image') {
            const sender = isMine ? user : peer;
            return (
              <div key={msg.id} className={cn('flex items-end gap-2', isMine ? 'flex-row-reverse' : '')}>
                <Avatar src={sender.avatar} name={sender.nickname} size={28} />
                <div className={cn('max-w-[70%]', isMine ? 'items-end' : 'items-start', 'flex flex-col')}>
                  <div className="w-40 h-40 rounded-xl bg-ink-100 flex items-center justify-center text-ink-400 border border-ink-200">
                    <div className="flex flex-col items-center gap-1">
                      <ImageIcon size={28} />
                      <span className="text-[11px]">[图片]</span>
                    </div>
                  </div>
                  <span className="text-[10px] text-ink-400 mt-1">{msg.createdAt}</span>
                </div>
              </div>
            );
          }

          const sender = isMine ? user : peer;
          return (
            <div key={msg.id} className={cn('flex items-end gap-2', isMine ? 'flex-row-reverse' : '')}>
              <Avatar src={sender.avatar} name={sender.nickname} size={28} />
              <div className={cn('max-w-[70%] flex flex-col', isMine ? 'items-end' : 'items-start')}>
                <div
                  className={cn(
                    'px-3 py-2 rounded-2xl text-sm leading-relaxed break-words',
                    isMine
                      ? 'bg-primary-600 text-white rounded-br-md'
                      : 'bg-white text-ink-900 rounded-bl-md shadow-card'
                  )}
                >
                  {msg.content}
                </div>
                <span className="text-[10px] text-ink-400 mt-1 px-1">{msg.createdAt}</span>
              </div>
            </div>
          );
        })}
      </div>

      {/* 底部输入栏 */}
      <div
        className="sticky bottom-0 bg-white border-t border-ink-100 p-2.5"
        style={{ paddingBottom: 'calc(0.625rem + var(--safe-bottom))' }}
      >
        <div className="flex items-center gap-2">
          <button className="p-2 rounded-full hover:bg-ink-100 btn-press shrink-0">
            <ImageIcon size={20} className="text-ink-500" />
          </button>
          <input
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') handleSend();
            }}
            placeholder="输入消息…"
            className="flex-1 h-9 px-3 rounded-full bg-ink-100 text-sm text-ink-900 placeholder:text-ink-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-primary-200 transition-all"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim()}
            className={cn(
              'w-9 h-9 rounded-full flex items-center justify-center shrink-0 btn-press transition-all',
              input.trim()
                ? 'bg-gradient-blue-purple text-white shadow-gradient'
                : 'bg-ink-200 text-ink-400 cursor-not-allowed'
            )}
          >
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
}
