import { useState } from 'react';
import { Search, Eye, Flag, Check, X, Ban, FileSearch } from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import Avatar from '@/components/Avatar';
import StatusBadge from '@/components/StatusBadge';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { adminTasks, categoryConfig, formatPrice } from '@/data/mock';
import type { TaskCategory } from '@/types';
import { cn } from '@/lib/utils';

const statusFilters = [
  { label: '全部', value: 'ALL' },
  { label: '待审核', value: 'PENDING_REVIEW' },
  { label: '待接单', value: 'OPEN' },
  { label: '已接单', value: 'ACCEPTED' },
  { label: '已完成', value: 'COMPLETED' },
];

export default function AdminTasks() {
  const showToast = useStore(s => s.showToast);
  const [keyword, setKeyword] = useState('');
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [categoryFilter, setCategoryFilter] = useState<'ALL' | TaskCategory>('ALL');

  const filtered = adminTasks.filter(t => {
    const matchKw = !keyword || t.title.includes(keyword) || t.publisher.nickname.includes(keyword);
    const matchStatus = statusFilter === 'ALL' || t.status === statusFilter;
    const matchCat = categoryFilter === 'ALL' || t.category === categoryFilter;
    return matchKw && matchStatus && matchCat;
  });

  return (
    <AdminLayout>
      {/* 搜索 + 筛选 */}
      <div className="bg-white rounded-2xl p-3 shadow-card space-y-3">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-400" />
          <input
            value={keyword}
            onChange={e => setKeyword(e.target.value)}
            placeholder="搜索任务标题或发布者"
            className="w-full pl-9 pr-3 py-2 bg-ink-50 rounded-lg text-sm text-ink-800 placeholder:text-ink-400 focus:outline-none focus:ring-2 focus:ring-primary-500"
          />
        </div>
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
          {statusFilters.map(s => (
            <button
              key={s.value}
              onClick={() => setStatusFilter(s.value)}
              className={cn(
                'px-2.5 py-1 rounded-full text-xs font-medium whitespace-nowrap transition-colors',
                statusFilter === s.value ? 'bg-primary-600 text-white' : 'bg-ink-100 text-ink-500'
              )}
            >
              {s.label}
            </button>
          ))}
        </div>
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
          <button
            onClick={() => setCategoryFilter('ALL')}
            className={cn(
              'px-2.5 py-1 rounded-full text-xs font-medium whitespace-nowrap',
              categoryFilter === 'ALL' ? 'bg-ink-800 text-white' : 'bg-ink-100 text-ink-500'
            )}
          >
            全部分类
          </button>
          {Object.entries(categoryConfig).map(([key, cfg]) => (
            <button
              key={key}
              onClick={() => setCategoryFilter(key as TaskCategory)}
              className={cn(
                'px-2.5 py-1 rounded-full text-xs font-medium whitespace-nowrap',
                categoryFilter === key ? 'bg-ink-800 text-white' : 'bg-ink-100 text-ink-500'
              )}
            >
              {cfg.icon} {cfg.label}
            </button>
          ))}
        </div>
      </div>

      {/* 任务列表 */}
      <div className="mt-3 bg-white rounded-2xl shadow-card overflow-hidden">
        <div className="px-4 py-3 border-b border-ink-100 flex items-center justify-between">
          <h2 className="font-display font-semibold text-ink-900 text-sm">任务列表</h2>
          <span className="text-xs text-ink-400">共 {filtered.length} 条</span>
        </div>

        {filtered.length === 0 ? (
          <Empty icon="🔍" title="未找到匹配的任务" desc="尝试调整筛选条件" />
        ) : (
          <div className="divide-y divide-ink-100">
            {filtered.map(task => {
              const cat = categoryConfig[task.category];
              const isPending = task.status === 'PENDING_REVIEW';
              return (
                <div key={task.id} className="p-3.5 hover:bg-ink-50/50 transition-colors">
                  <div className="flex items-start gap-3">
                    <div
                      className="w-10 h-10 rounded-lg flex items-center justify-center text-lg shrink-0"
                      style={{ backgroundColor: cat.color + '15' }}
                    >
                      {cat.icon}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <h3 className="font-semibold text-ink-900 text-sm line-clamp-1">{task.title}</h3>
                        <StatusBadge status={task.status} />
                      </div>
                      <div className="flex items-center gap-2 mt-1.5 flex-wrap text-[11px] text-ink-500">
                        <span className="flex items-center gap-1">
                          <Avatar src={task.publisher.avatar} name={task.publisher.nickname} size={14} />
                          {task.publisher.nickname}
                        </span>
                        <span style={{ color: cat.color }}>· {cat.label}</span>
                        <span>· {task.createdAt}</span>
                      </div>
                      <div className="flex items-center gap-3 mt-1.5 text-[11px] text-ink-400">
                        <span className="text-warning-600 font-bold font-display">¥{formatPrice(task.price)}</span>
                        <span className="flex items-center gap-0.5"><Eye size={12} />{task.views}</span>
                        <span className="flex items-center gap-0.5"><Flag size={12} />{task.reportCount}</span>
                      </div>

                      {/* 操作按钮 */}
                      <div className="flex items-center gap-1.5 mt-2.5">
                        {isPending ? (
                          <>
                            <button
                              onClick={() => showToast(`已通过任务「${task.title}」的审核`, 'success')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-success-500 text-white text-xs font-medium hover:bg-success-600 btn-press"
                            >
                              <Check size={13} /> 通过
                            </button>
                            <button
                              onClick={() => showToast(`已驳回任务「${task.title}」`, 'error')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-danger-500 text-white text-xs font-medium hover:bg-danger-600 btn-press"
                            >
                              <X size={13} /> 驳回
                            </button>
                          </>
                        ) : (
                          <>
                            <button
                              onClick={() => showToast(`正在审核任务「${task.title}」`, 'info')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-ink-100 text-ink-700 text-xs font-medium hover:bg-ink-200 btn-press"
                            >
                              <FileSearch size={13} /> 审核
                            </button>
                            <button
                              onClick={() => showToast(`已下架任务「${task.title}」`, 'info')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-warning-100 text-warning-600 text-xs font-medium hover:bg-warning-500 hover:text-white btn-press"
                            >
                              <Ban size={13} /> 下架
                            </button>
                            <button
                              onClick={() => showToast(`已关闭任务「${task.title}」`, 'error')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-danger-100 text-danger-600 text-xs font-medium hover:bg-danger-500 hover:text-white btn-press"
                            >
                              <X size={13} /> 关闭
                            </button>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
