import { useState } from 'react';
import { Eye, Clock, Megaphone, X } from 'lucide-react';
import { newsList } from '@/data/mock';
import type { News } from '@/types';
import PageHeader from '@/components/PageHeader';
import Empty from '@/components/Empty';
import { cn } from '@/lib/utils';

const categories = ['全部', '教务通知', '校园活动', '校园通知', '推广'];

export default function NewsList() {
  const [active, setActive] = useState('全部');
  const [selected, setSelected] = useState<News | null>(null);

  const filtered = active === '全部' ? newsList : newsList.filter(n => n.category === active);
  const [feature, ...rest] = filtered;

  return (
    <div className="min-h-screen bg-ink-50 pb-6">
      <PageHeader title="校园资讯" back />

      {/* 分类 Tab */}
      <div className="sticky top-14 z-30 bg-white border-b border-ink-100">
        <div className="flex gap-1 px-3 py-2 overflow-x-auto no-scrollbar">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setActive(cat)}
              className={cn(
                'px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors btn-press',
                active === cat ? 'bg-gradient-blue-purple text-white shadow-gradient' : 'bg-ink-100 text-ink-600'
              )}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="px-3 py-3">
        {filtered.length === 0 ? (
          <Empty icon="📰" title="暂无资讯" desc="换个分类看看吧" />
        ) : (
          <div className="space-y-3">
            {feature && <FeatureCard news={feature} onClick={() => setSelected(feature)} />}
            {rest.map(n => (
              <NewsCard key={n.id} news={n} onClick={() => setSelected(n)} />
            ))}
          </div>
        )}
      </div>

      {/* 资讯详情弹窗 */}
      {selected && <NewsDetailModal news={selected} onClose={() => setSelected(null)} />}
    </div>
  );
}

function NewsDetailModal({ news, onClose }: { news: News; onClose: () => void }) {
  return (
    <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center" onClick={onClose}>
      <div className="absolute inset-0 bg-black/40 animate-fade-in" />
      <div
        className="relative bg-white w-full max-w-[430px] max-h-[85vh] rounded-t-3xl md:rounded-3xl overflow-hidden animate-slide-up flex flex-col"
        onClick={e => e.stopPropagation()}
      >
        {/* 顶部渐变封面 */}
        <div className="h-32 bg-gradient-to-br from-primary-500 via-primary-600 to-purple-600 relative flex items-end p-4 shrink-0">
          <button onClick={onClose} className="absolute top-3 right-3 w-8 h-8 rounded-full bg-black/20 backdrop-blur flex items-center justify-center btn-press">
            <X size={16} className="text-white" />
          </button>
          {news.isAd && (
            <span className="absolute top-3 left-3 px-2 py-0.5 rounded bg-warning-500 text-white text-[10px] font-bold flex items-center gap-1">
              <Megaphone size={10} /> 广告
            </span>
          )}
          <div className="relative z-10">
            <span className="inline-block px-2 py-0.5 rounded bg-white/20 backdrop-blur text-white text-[11px] font-medium mb-1.5">
              {news.category}
            </span>
            <h2 className="text-white font-display font-bold text-base leading-snug line-clamp-2">{news.title}</h2>
          </div>
        </div>

        {/* 内容区 */}
        <div className="overflow-y-auto p-4 flex-1">
          <div className="flex items-center gap-3 text-[11px] text-ink-400 mb-3 pb-3 border-b border-ink-100">
            <span className="font-medium text-ink-600">{news.author}</span>
            <span className="flex items-center gap-0.5"><Clock size={11} />{news.publishedAt}</span>
            <span className="flex items-center gap-0.5"><Eye size={11} />{news.views} 阅读</span>
          </div>
          <p className="text-sm text-ink-500 mb-3 leading-relaxed">{news.summary}</p>
          <div className="text-sm text-ink-700 leading-relaxed whitespace-pre-line">{news.content}</div>
        </div>
      </div>
    </div>
  );
}

function FeatureCard({ news, onClick }: { news: News; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="block w-full text-left rounded-2xl overflow-hidden shadow-soft btn-press animate-slide-up"
    >
      {/* 封面图（渐变占位） */}
      <div className="h-40 bg-gradient-to-br from-primary-500 via-primary-600 to-purple-600 relative flex items-end p-4">
        <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
        {news.isAd && (
          <span className="absolute top-3 right-3 px-2 py-0.5 rounded bg-warning-500 text-white text-[10px] font-bold flex items-center gap-1">
            <Megaphone size={10} /> 广告
          </span>
        )}
        <div className="relative z-10">
          <span className="inline-block px-2 py-0.5 rounded bg-white/20 backdrop-blur text-white text-[11px] font-medium mb-1.5">
            {news.category}
          </span>
          <h2 className="text-white font-display font-bold text-lg leading-snug line-clamp-2">{news.title}</h2>
        </div>
      </div>
      {/* 摘要 */}
      <div className="bg-white p-3">
        <p className="text-sm text-ink-600 line-clamp-2 leading-relaxed">{news.summary}</p>
        <div className="flex items-center gap-3 mt-2 text-[11px] text-ink-400">
          <span>{news.author}</span>
          <span className="flex items-center gap-0.5"><Clock size={11} />{news.publishedAt}</span>
          <span className="flex items-center gap-0.5"><Eye size={11} />{news.views}</span>
        </div>
      </div>
    </button>
  );
}

function NewsCard({ news, onClick }: { news: News; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="block w-full text-left bg-white rounded-2xl p-3.5 shadow-card hover:shadow-soft transition-shadow btn-press animate-slide-up"
    >
      <div className="flex items-start gap-3">
        {/* 缩略图（渐变占位） */}
        <div className="w-20 h-20 rounded-xl bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center shrink-0">
          <span className="text-white/80 text-2xl">📰</span>
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5">
            <span className="text-[11px] px-1.5 py-0.5 rounded bg-primary-50 text-primary-600 font-medium">{news.category}</span>
            {news.isAd && (
              <span className="text-[10px] px-1.5 py-0.5 rounded bg-warning-100 text-warning-600 font-bold flex items-center gap-0.5">
                <Megaphone size={9} />广告
              </span>
            )}
          </div>
          <h3 className="font-semibold text-ink-900 text-sm mt-1 leading-snug line-clamp-2">{news.title}</h3>
          <p className="text-xs text-ink-500 mt-1 line-clamp-1">{news.summary}</p>
          <div className="flex items-center gap-3 mt-1.5 text-[11px] text-ink-400">
            <span>{news.author}</span>
            <span className="flex items-center gap-0.5"><Clock size={11} />{news.publishedAt}</span>
            <span className="flex items-center gap-0.5"><Eye size={11} />{news.views}</span>
          </div>
        </div>
      </div>
    </button>
  );
}
