import { useState, useMemo } from 'react';
import { CheckCheck } from 'lucide-react';
import PageHeader from '@/components/PageHeader';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';
import type { Notification } from '@/types';

type FilterKey = 'all' | 'task' | 'pay' | 'social' | 'system';

const FILTERS: { key: FilterKey; label: string }[] = [
  { key: 'all', label: '全部' },
  { key: 'task', label: '任务' },
  { key: 'pay', label: '支付' },
  { key: 'social', label: '社交' },
  { key: 'system', label: '系统' },
];

const TYPE_ICON: Record<Notification['type'], string> = {
  task: '📋',
  pay: '💰',
  social: '💬',
  chat: '💬',
  system: '🔔',
};

const TYPE_BG: Record<Notification['type'], string> = {
  task: 'bg-primary-50',
  pay: 'bg-success-100',
  social: 'bg-warning-100',
  chat: 'bg-warning-100',
  system: 'bg-ink-100',
};

export default function Notifications() {
  const { notifications, markNotificationRead, markAllNotificationsRead, showToast } = useStore();
  const [filter, setFilter] = useState<FilterKey>('all');

  const filtered = useMemo(() => {
    if (filter === 'all') return notifications;
    return notifications.filter(n => n.type === filter);
  }, [notifications, filter]);

  const unreadCount = notifications.filter(n => !n.read).length;

  const handleMarkAll = () => {
    if (unreadCount === 0) {
      showToast('暂无未读通知', 'info');
      return;
    }
    markAllNotificationsRead();
    showToast('已全部标记为已读', 'success');
  };

  const handleClick = (n: Notification) => {
    if (!n.read) markNotificationRead(n.id);
  };

  return (
    <div className="min-h-screen bg-ink-50">
      <PageHeader
        title="通知"
        right={
          <button
            onClick={handleMarkAll}
            className="flex items-center gap-1 px-2.5 py-1.5 rounded-full hover:bg-ink-100 btn-press text-primary-600"
          >
            <CheckCheck size={15} />
            <span className="text-xs font-medium">全部已读</span>
          </button>
        }
      >
        <div className="flex gap-1.5 px-3 pb-2.5 overflow-x-auto no-scrollbar">
          {FILTERS.map(f => {
            const count = f.key === 'all'
              ? unreadCount
              : notifications.filter(n => n.type === f.key && !n.read).length;
            return (
              <button
                key={f.key}
                onClick={() => setFilter(f.key)}
                className={cn(
                  'shrink-0 px-3.5 py-1.5 rounded-full text-xs font-medium transition-all btn-press flex items-center gap-1',
                  filter === f.key
                    ? 'bg-gradient-blue-purple text-white shadow-gradient'
                    : 'bg-white text-ink-500 border border-ink-200'
                )}
              >
                {f.label}
                {count > 0 && (
                  <span
                    className={cn(
                      'inline-flex items-center justify-center min-w-[16px] h-4 px-1 rounded-full text-[10px] font-semibold',
                      filter === f.key ? 'bg-white/25 text-white' : 'bg-danger-500 text-white'
                    )}
                  >
                    {count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </PageHeader>

      <div className="p-3 space-y-2">
        {filtered.length === 0 ? (
          <Empty icon="🔔" title="暂无通知" desc="新的通知会显示在这里" />
        ) : (
          filtered.map(n => (
            <button
              key={n.id}
              onClick={() => handleClick(n)}
              className={cn(
                'w-full bg-white rounded-2xl p-3.5 shadow-card flex items-start gap-3 btn-press animate-fade-in text-left',
                !n.read && 'ring-1 ring-primary-100'
              )}
            >
              <div
                className={cn(
                  'w-10 h-10 rounded-xl flex items-center justify-center text-lg shrink-0',
                  TYPE_BG[n.type]
                )}
              >
                {TYPE_ICON[n.type]}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between gap-2">
                  <span className={cn('text-sm font-semibold truncate', n.read ? 'text-ink-700' : 'text-ink-900')}>
                    {n.title}
                  </span>
                  <span className="text-[11px] text-ink-400 shrink-0">{n.time}</span>
                </div>
                <p className={cn('text-xs mt-1 line-clamp-2', n.read ? 'text-ink-400' : 'text-ink-600')}>
                  {n.content}
                </p>
              </div>
              {!n.read && (
                <span className="w-2 h-2 rounded-full bg-danger-500 shrink-0 mt-1.5" />
              )}
            </button>
          ))
        )}
      </div>
    </div>
  );
}
