import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ImagePlus, X, Minus, Plus, ChevronRight } from 'lucide-react';
import { useStore } from '@/store';
import { categoryConfig, formatPrice } from '@/data/mock';
import type { TaskCategory } from '@/types';
import PageHeader from '@/components/PageHeader';
import { cn } from '@/lib/utils';

const deliveryMethods = ['当面交付', '线上交付', '线下/线上'];
const deadlineOptions = ['今天内', '明天', '本周内', '本周末', '下周', '一个月内', '长期有效'];

export default function Publish() {
  const navigate = useNavigate();
  const { publishTask, showToast } = useStore();

  const [category, setCategory] = useState<TaskCategory>('errand');
  const [title, setTitle] = useState('');
  const [desc, setDesc] = useState('');
  const [images, setImages] = useState<number>(0);
  const [price, setPrice] = useState('');
  const [headcount, setHeadcount] = useState(1);
  const [location, setLocation] = useState('');
  const [deadline, setDeadline] = useState(deadlineOptions[0]);
  const [delivery, setDelivery] = useState(deliveryMethods[0]);
  const [deadlineOpen, setDeadlineOpen] = useState(false);

  const priceYuan = parseFloat(price) || 0;
  const priceCents = Math.round(priceYuan * 100);
  const serviceFee = Math.max(50, Math.min(2000, Math.round(priceCents * 0.05)));
  const total = priceCents + serviceFee;

  const categories = Object.entries(categoryConfig) as [TaskCategory, typeof categoryConfig[TaskCategory]][];

  const handleSubmit = () => {
    if (!title.trim()) { showToast('请填写任务标题', 'error'); return; }
    if (priceYuan <= 0) { showToast('请填写有效的任务赏金', 'error'); return; }
    const newId = publishTask({
      title: title.trim(),
      category,
      description: desc.trim(),
      images: Array.from({ length: images }, (_, i) => `mock-${i}.jpg`),
      price: priceCents,
      headcount,
      location: location.trim(),
      deadline,
      deliveryMethod: delivery,
      tags: [categoryConfig[category].label],
    });
    showToast('任务发布成功！', 'success');
    navigate(`/tasks/${newId}`, { replace: true });
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-28">
      <PageHeader title="发布任务" />

      <div className="px-4 py-3 space-y-3">
        {/* 分类选择 */}
        <Section title="任务分类" required>
          <div className="grid grid-cols-4 gap-2">
            {categories.map(([key, cfg]) => (
              <button
                key={key}
                onClick={() => setCategory(key)}
                className={cn(
                  'flex flex-col items-center gap-1 py-2.5 rounded-xl border transition-colors btn-press',
                  category === key ? 'border-primary-600 bg-primary-50' : 'border-ink-200 bg-white'
                )}
              >
                <span className="text-xl">{cfg.icon}</span>
                <span className={cn('text-[10px] font-medium', category === key ? 'text-primary-600' : 'text-ink-500')}>
                  {cfg.label}
                </span>
              </button>
            ))}
          </div>
        </Section>

        {/* 标题 */}
        <Section title="任务标题" required>
          <input
            value={title}
            onChange={e => setTitle(e.target.value.slice(0, 30))}
            placeholder="一句话描述你的需求，如：代取快递送到宿舍"
            className="w-full bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:ring-2 focus:ring-primary-200"
          />
          <div className="text-right text-[11px] text-ink-400 mt-1">{title.length}/30</div>
        </Section>

        {/* 描述 */}
        <Section title="详细描述">
          <textarea
            value={desc}
            onChange={e => setDesc(e.target.value.slice(0, 500))}
            placeholder="详细说明任务要求、注意事项等，越详细越容易匹配到合适的人…"
            rows={4}
            className="w-full bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:ring-2 focus:ring-primary-200 resize-none"
          />
          <div className="text-right text-[11px] text-ink-400 mt-1">{desc.length}/500</div>
        </Section>

        {/* 图片上传 */}
        <Section title="配图（可选）">
          <div className="grid grid-cols-5 gap-2">
            {Array.from({ length: 9 }).map((_, i) => (
              i < images ? (
                <div key={i} className="relative aspect-square rounded-xl bg-ink-200 flex items-center justify-center">
                  <ImagePlus size={20} className="text-ink-400" />
                  <button
                    onClick={() => setImages(n => n - 1)}
                    className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-danger-500 text-white rounded-full flex items-center justify-center"
                  >
                    <X size={12} />
                  </button>
                </div>
              ) : i === images ? (
                <button
                  key={i}
                  onClick={() => setImages(n => Math.min(n + 1, 9))}
                  className="aspect-square rounded-xl border-2 border-dashed border-ink-300 flex items-center justify-center text-ink-400 hover:border-primary-400 hover:text-primary-500 btn-press"
                >
                  <ImagePlus size={20} />
                </button>
              ) : (
                <div key={i} className="aspect-square rounded-xl border-2 border-dashed border-ink-200" />
              )
            ))}
          </div>
        </Section>

        {/* 赏金 */}
        <Section title="任务赏金" required>
          <div className="flex items-center bg-ink-100 rounded-xl px-3.5 py-2.5 focus-within:ring-2 focus-within:ring-primary-200">
            <span className="text-warning-600 font-bold text-lg mr-1">¥</span>
            <input
              type="number"
              inputMode="decimal"
              value={price}
              onChange={e => setPrice(e.target.value)}
              placeholder="0.00"
              className="flex-1 bg-transparent text-sm text-ink-800 placeholder:text-ink-400 outline-none"
            />
            <span className="text-sm text-ink-400">元</span>
          </div>
        </Section>

        {/* 人数 */}
        <Section title="需要人数">
          <div className="flex items-center gap-3">
            <button
              onClick={() => setHeadcount(n => Math.max(1, n - 1))}
              className="w-9 h-9 rounded-lg bg-ink-100 flex items-center justify-center text-ink-600 btn-press disabled:opacity-40"
              disabled={headcount <= 1}
            >
              <Minus size={16} />
            </button>
            <span className="w-10 text-center font-semibold text-ink-800">{headcount}</span>
            <button
              onClick={() => setHeadcount(n => Math.min(99, n + 1))}
              className="w-9 h-9 rounded-lg bg-ink-100 flex items-center justify-center text-ink-600 btn-press"
            >
              <Plus size={16} />
            </button>
            <span className="text-xs text-ink-400 ml-1">人</span>
          </div>
        </Section>

        {/* 地点 */}
        <Section title="任务地点">
          <input
            value={location}
            onChange={e => setLocation(e.target.value)}
            placeholder="如：紫荆公寓13号楼 / 线上"
            className="w-full bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:ring-2 focus:ring-primary-200"
          />
        </Section>

        {/* 截止时间 */}
        <Section title="截止时间">
          <button
            onClick={() => setDeadlineOpen(true)}
            className="w-full flex items-center justify-between bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 btn-press"
          >
            <span>{deadline}</span>
            <ChevronRight size={16} className="text-ink-400" />
          </button>
        </Section>

        {/* 交付方式 */}
        <Section title="交付方式">
          <div className="flex flex-wrap gap-2">
            {deliveryMethods.map(m => (
              <button
                key={m}
                onClick={() => setDelivery(m)}
                className={cn(
                  'text-xs px-3.5 py-1.5 rounded-full font-medium border transition-colors',
                  delivery === m ? 'bg-gradient-blue-purple text-white shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
                )}
              >
                {m}
              </button>
            ))}
          </div>
        </Section>

        {/* 费用预览 */}
        <div className="bg-white rounded-2xl p-4 shadow-card">
          <h3 className="text-sm font-semibold text-ink-900 mb-3">费用预览</h3>
          <div className="space-y-2 text-sm">
            <FeeRow label="任务赏金" value={`¥${formatPrice(priceCents)}`} />
            <FeeRow label="平台服务费（5%）" value={`¥${formatPrice(serviceFee)}`} hint="最低0.50元，最高20元" />
            <div className="border-t border-ink-100 pt-2 mt-2">
              <FeeRow label="合计需支付" value={`¥${formatPrice(total)}`} highlight />
            </div>
          </div>
        </div>
      </div>

      {/* 底部提交 */}
      <div className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-white border-t border-ink-100 px-4 py-3 z-40" style={{ paddingBottom: 'calc(var(--safe-bottom) + 12px)' }}>
        <button
          onClick={handleSubmit}
          className="w-full py-3 rounded-xl bg-gradient-blue-purple text-white font-semibold text-sm btn-press shadow-gradient-lg"
        >
          发布并支付 ¥{formatPrice(total)}
        </button>
      </div>

      {/* 截止时间选择 */}
      {deadlineOpen && (
        <div className="fixed inset-0 z-[90] flex" onClick={() => setDeadlineOpen(false)}>
          <div className="absolute inset-0 bg-ink-900/50 backdrop-blur-sm animate-fade-in" />
          <div className="relative bg-white w-full max-w-[430px] mx-auto mt-auto rounded-t-3xl animate-slide-up" onClick={e => e.stopPropagation()} style={{ paddingBottom: 'var(--safe-bottom)' }}>
            <div className="flex items-center justify-between px-5 py-4 border-b border-ink-100">
              <h3 className="font-display font-semibold text-ink-900">选择截止时间</h3>
              <button onClick={() => setDeadlineOpen(false)} className="p-1 rounded-full hover:bg-ink-100"><X size={20} className="text-ink-500" /></button>
            </div>
            <div className="py-2">
              {deadlineOptions.map(o => (
                <button
                  key={o}
                  onClick={() => { setDeadline(o); setDeadlineOpen(false); }}
                  className={cn(
                    'w-full flex items-center justify-between px-5 py-3.5 hover:bg-ink-50 btn-press',
                    deadline === o && 'text-primary-600 font-medium'
                  )}
                >
                  <span className="text-sm">{o}</span>
                  {deadline === o && <span className="text-primary-600">✓</span>}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Section({ title, required, children }: { title: string; required?: boolean; children: React.ReactNode }) {
  return (
    <div className="bg-white rounded-2xl p-4 shadow-card">
      <h3 className="text-sm font-semibold text-ink-900 mb-2.5">
        {title}{required && <span className="text-danger-500 ml-0.5">*</span>}
      </h3>
      {children}
    </div>
  );
}

function FeeRow({ label, value, hint, highlight }: { label: string; value: string; hint?: string; highlight?: boolean }) {
  return (
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-1.5">
        <span className={cn('text-ink-500', highlight && 'text-ink-900 font-semibold')}>{label}</span>
        {hint && <span className="text-[10px] text-ink-400">({hint})</span>}
      </div>
      <span className={cn('font-medium', highlight ? 'text-warning-600 font-display font-bold text-lg' : 'text-ink-800')}>
        {value}
      </span>
    </div>
  );
}
