// 专业→技能推断
const MAJOR_SKILLS: Record<string, string[]> = {
  '计算机': ['编程', 'python', '前端'],
  '软件': ['编程', 'java', '前端'],
  '设计': ['设计', 'ps', 'ppt'],
  '艺术': ['设计', '摄影', 'ps'],
  '外语': ['英语', '翻译'],
  '英语': ['英语', '翻译'],
  '数学': ['数学', '编程'],
  '物理': ['物理', '数学'],
  '传媒': ['写作', '视频', '剪辑'],
  '新闻': ['写作', '视频'],
  '经济': ['写作', 'ppt'],
  '管理': ['ppt', '写作'],
};

const HOBBY_SKILLS: Record<string, string[]> = {
  '摄影': ['摄影', '修图'],
  '音乐': ['音乐'],
  '吉他': ['吉他'],
  '钢琴': ['音乐'],
  '运动': ['运动'],
  '健身': ['运动'],
  '阅读': ['写作'],
  '游戏': ['视频', '剪辑'],
  '电影': ['视频', '剪辑'],
  '旅行': ['摄影'],
};

const DEMAND_LABEL = { high: '旺盛', medium: '稳定', low: '小众' };
const DIFFICULTY_LABEL = { easy: '上手快', medium: '需基础', hard: '有门槛' };

export function diagnoseMonetization(input: DiagnosisInput): MonetizationPlan[] {
  // 汇总所有技能关键词
  const allSkills = new Set<string>();
  input.skills.forEach(s => {
    const lower = s.toLowerCase();
    Object.keys(SKILL_MAP).forEach(key => {
      if (lower.includes(key)) allSkills.add(key);
    });
  });
  // 专业推断
  const majorLower = input.major.toLowerCase();
  Object.entries(MAJOR_SKILLS).forEach(([key, skills]) => {
    if (majorLower.includes(key)) skills.forEach(s => allSkills.add(s));
  });
  // 兴趣推断
  input.hobbies.forEach(h => {
    const lower = h.toLowerCase();
    Object.entries(HOBBY_SKILLS).forEach(([key, skills]) => {
      if (lower.includes(key)) skills.forEach(s => allSkills.add(s));
    });
  });

  // 兜底：至少给跑腿类
  if (allSkills.size === 0) {
    allSkills.add('运动');
  }

  // 生成方案
  const plans: MonetizationPlan[] = [];
  const usedServices = new Set<string>();

  Array.from(allSkills).forEach((skill, idx) => {
    const map = SKILL_MAP[skill];
    if (!map || usedServices.has(map.service)) return;
    usedServices.add(map.service);

    // 价格浮动
    const timeMultiplier = input.freeTime === 'rich' ? 1.15 : input.freeTime === 'tight' ? 0.85 : 1;
    const base = Math.round(map.basePrice * timeMultiplier);
    const priceRange: [number, number] = [Math.round(base * 0.8), Math.round(base * 1.3)];

    // 匹配度：直接技能>专业推断>兴趣推断
    let matchScore = 70 + idx * 3;
    if (input.skills.some(s => s.toLowerCase().includes(skill))) matchScore = 88 + Math.floor(Math.random() * 10);
    else if (input.major.toLowerCase().includes(skill)) matchScore = 80 + Math.floor(Math.random() * 8);
    else matchScore = 72 + Math.floor(Math.random() * 8);

    const reasoning = buildReasoning(skill, input, map.demand);
    const tips = buildTips(map.difficulty, map.demand, input.freeTime);

    plans.push({
      serviceName: map.service,
      category: map.category,
      priceRange,
      difficulty: map.difficulty,
      demand: map.demand,
      matchScore,
      reasoning,
      tips,
    });
  });

  // 按匹配度排序，取前 5
  return plans.sort((a, b) => b.matchScore - a.matchScore).slice(0, 5);
}

function buildReasoning(skill: string, input: DiagnosisInput, demand: 'high' | 'medium' | 'low'): string {
  const source = input.skills.some(s => s.toLowerCase().includes(skill))
    ? '你已具备该技能'
    : input.major.toLowerCase().includes(skill)
    ? `你的专业背景与该方向高度契合`
    : '由你的兴趣推断';
  return `${source}，校园内该类需求${DEMAND_LABEL[demand]}，变现路径清晰。`;
}

function buildTips(difficulty: 'easy' | 'medium' | 'hard', demand: 'high' | 'medium' | 'low', freeTime: string): string {
  let tip = '';
  if (difficulty === 'easy') tip = '门槛低，可快速接单积累信誉。';
  else if (difficulty === 'hard') tip = '建议先完善作品集，从低价单起步建立口碑。';
  else tip = '有一定基础即可接单，注意把控交付质量。';
  if (freeTime === 'tight') tip += '空闲较少，建议优先接短时高效的单。';
  if (demand === 'low') tip += '需求偏小众，可结合社团资源主动获客。';
  return tip;
}

// ============ AI 校园人格名片 ============

export interface PersonalityCard {
  title: string;          // 人格称号
  subtitle: string;       // 副标题
  tags: string[];         // 人格标签
  description: string;    // AI 描述
  traits: { name: string; score: number; label: string }[]; // 五维特质
  vibe: string;           // 一句话氛围
  color: string;          // 主题色
}

// 五维特质定义
const TRAITS = [
  { key: 'action', name: '行动力', high: '雷厉风行', mid: '稳扎稳打', low: '佛系随缘' },
  { key: 'tech', name: '技术力', high: '硬核技术', mid: '技能扎实', low: '通用型选手' },
  { key: 'social', name: '社交力', high: '社牛本牛', mid: '友善可亲', low: '独狼玩家' },
  { key: 'reliability', name: '靠谱度', high: '铁打的靠谱', mid: '值得信赖', low: '仍在成长' },
  { key: 'creativity', name: '创造力', high: '脑洞大开', mid: '灵感冒友', low: '执行派' },
];

export function generatePersonalityCard(user: User): PersonalityCard {
  // 基于用户数据计算五维分数
  const taskCount = user.taskCount;
  const completeRate = user.completeRate;
  const creditScore = user.creditScore;
  const skillCount = user.skills.length;
  const hasTechSkill = user.skills.some(s => /编程|python|java|前端|开发/i.test(s.name));
  const hasCreativeSkill = user.skills.some(s => /设计|摄影|ps|视频|剪辑|音乐/i.test(s.name));

  const traits = TRAITS.map(t => {
    let score = 50;
    if (t.key === 'action') score = Math.min(95, 40 + taskCount * 1.5);
    if (t.key === 'tech') score = Math.min(95, hasTechSkill ? 75 + skillCount * 5 : 45 + skillCount * 3);
    if (t.key === 'social') score = Math.min(95, 50 + (user.achievements.length * 4) + (user.bio.length > 10 ? 8 : 0));
    if (t.key === 'reliability') score = Math.min(98, creditScore + Math.floor(completeRate / 5));
    if (t.key === 'creativity') score = Math.min(95, hasCreativeSkill ? 72 + skillCount * 4 : 48 + skillCount * 2);
    score = Math.max(30, Math.round(score));
    const label = score >= 75 ? t.high : score >= 55 ? t.mid : t.low;
    return { name: t.name, score, label };
  });

  // 生成称号
  const topTrait = traits.reduce((max, t) => t.score > max.score ? t : max);
  const titles = buildTitles(traits, user);
  const title = titles[0];
  const subtitle = titles[1];

  // 生成标签
  const tags: string[] = [];
  traits.forEach(t => {
    if (t.score >= 75) tags.push(t.label);
  });
  if (user.verified) tags.push('已认证');
  if (user.level >= 5) tags.push(`Lv.${user.level} 老玩家`);
  if (completeRate >= 90) tags.push('高完成率');
  if (tags.length < 3) tags.push('潜力新人');
  const finalTags = Array.from(new Set(tags)).slice(0, 5);

  // 描述
  const description = buildDescription(traits, user);

  // 氛围语
  const vibe = buildVibe(topTrait, user);

  // 主题色
  const color = pickColor(traits);

  return { title, subtitle, tags: finalTags, description, traits, vibe, color };
}

function buildTitles(traits: { name: string; score: number; label: string }[], user: User): string[] {
  const top = traits.reduce((max, t) => t.score > max.score ? t : max);
  const reliable = traits.find(t => t.name === '靠谱度')!;
  const action = traits.find(t => t.name === '行动力')!;

  // 称号组合逻辑
  if (top.name === '技术力' && top.score >= 75) {
    return ['校园技术宅', '代码与咖啡的守护者'];
  }
  if (top.name === '创造力' && top.score >= 75) {
    return ['灵感制造机', '审美在线的创意达人'];
  }
  if (top.name === '社交力' && top.score >= 75) {
    return ['校园社牛', '人脉比课表还满的连接者'];
  }
  if (top.name === '行动力' && top.score >= 75) {
    return ['行动派队长', '说干就干的效率机器'];
  }
  if (reliable.score >= 85) {
    return ['靠谱天花板', '把"放心"写进 DNA 的人'];
  }
  if (action.score >= 65 && reliable.score >= 70) {
    return ['校园全能王', '又快又稳的多面手'];
  }
  return ['校园探索者', '正在解锁更多可能'];
}

function buildDescription(traits: { name: string; score: number; label: string }[], user: User): string {
  const top = traits.reduce((max, t) => t.score > max.score ? t : max);
  const low = traits.reduce((min, t) => t.score < min.score ? t : min);
  const parts: string[] = [];

  parts.push(`这是一位${top.label}的${user.school}同学，`);
  parts.push(`已完成 ${user.taskCount} 次任务，完成率 ${user.completeRate}%，信誉 ${user.creditScore} 分。`);
  if (top.score >= 80) {
    parts.push(`在「${top.name}」维度表现突出（${top.score}分），是团队中不可多得的${top.label}型选手。`);
  }
  if (low.score < 55) {
    parts.push(`「${low.name}」还有成长空间，建议多参与相关活动解锁潜能。`);
  }
  parts.push(`综合来看，是一位${user.verifyLevel}认证的${user.level >= 5 ? '资深' : '活跃'}校园成员。`);
  return parts.join('');
}

function buildVibe(topTrait: { name: string; score: number; label: string }, user: User): string {
  const vibes: Record<string, string[]> = {
    '行动力': ['风风火火，今日事今日毕', '走路带风，执行力拉满'],
    '技术力': ['用代码改变校园', '键盘敲击声是最好的BGM'],
    '社交力': ['朋友圈覆盖半个学校', '没有他认识不到的人'],
    '靠谱度': ['交给他就两个字：放心', ' deadline 永远提前'],
    '创造力': ['脑洞比黑洞还大', '审美永远在线'],
  };
  const list = vibes[topTrait.name] || ['正在散发独特魅力'];
  return list[Math.floor(Math.random() * list.length)];
}

function pickColor(traits: { name: string; score: number }[]): string {
  const top = traits.reduce((max, t) => t.score > max.score ? t : max);
  const colors: Record<string, string> = {
    '行动力': '#F59E0B',
    '技术力': '#6366F1',
    '社交力': '#EC4899',
    '靠谱度': '#10B981',
    '创造力': '#A855F7',
  };
  return colors[top.name] || '#6366F1';
}

export { DEMAND_LABEL, DIFFICULTY_LABEL };
