import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Heart, Eye, MessageCircle, Send, Image as ImageIcon } from 'lucide-react';
import { useStore } from '@/store';
import type { Post, Comment } from '@/types';
import PageHeader from '@/components/PageHeader';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { cn } from '@/lib/utils';

export default function PostDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { showToast, posts, togglePostLike } = useStore();
  const post = posts.find(p => p.id === id);

  const [commentText, setCommentText] = useState('');

  if (!post) {
    return (
      <div className="min-h-screen bg-ink-50">
        <PageHeader title="帖子详情" back />
        <Empty icon="🔍" title="帖子不存在" desc="可能已被删除" action={
          <button onClick={() => navigate('/plaza')} className="px-4 py-2 rounded-full bg-gradient-blue-purple text-white text-sm shadow-gradient">返回广场</button>
        } />
      </div>
    );
  }

  const name = post.anonymous ? '匿名同学' : post.author.nickname;
  const avatar = post.anonymous ? '' : post.author.avatar;

  const toggleLike = () => {
    togglePostLike(post.id);
  };

  const submitComment = () => {
    if (!commentText.trim()) return;
    showToast('评论已发送（Demo）');
    setCommentText('');
  };

  return (
    <div className="min-h-screen pb-24 bg-ink-50">
      <PageHeader title="帖子详情" back />

      <div className="px-3 py-3 space-y-3">
        {/* 作者卡片 */}
        <div className="bg-white rounded-2xl p-3.5 shadow-card animate-fade-in">
          <div className="flex items-center gap-2.5">
            <Avatar src={avatar} name={name} size={42} ring />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1.5">
                <span className="font-semibold text-ink-900 text-sm">{name}</span>
                {post.anonymous && (
                  <span className="text-[10px] px-1 py-0.5 rounded bg-ink-100 text-ink-500">匿名</span>
                )}
              </div>
              <div className="flex items-center gap-1.5 text-[11px] text-ink-400 mt-0.5">
                <span className="px-1.5 py-0.5 rounded bg-primary-50 text-primary-600 font-medium">{post.topic}</span>
                <span>·</span>
                <span>{post.createdAt}</span>
              </div>
            </div>
          </div>
        </div>

        {/* 帖子正文 */}
        <div className="bg-white rounded-2xl p-3.5 shadow-card animate-slide-up">
          <h1 className="font-display font-bold text-ink-900 text-lg leading-snug">{post.title}</h1>
          <p className="text-sm text-ink-700 mt-2 leading-relaxed whitespace-pre-wrap">{post.content}</p>

          {/* 图片区域 */}
          {post.images.length > 0 ? (
            <div className="grid grid-cols-3 gap-1.5 mt-3">
              {post.images.map((img, i) => (
                <img key={i} src={img} alt="" className="w-full aspect-square object-cover rounded-lg" />
              ))}
            </div>
          ) : (
            <div className="mt-3 h-32 rounded-xl bg-gradient-to-br from-ink-100 to-ink-200 flex items-center justify-center text-ink-400">
              <ImageIcon size={28} />
            </div>
          )}

          {/* 统计栏 */}
          <div className="flex items-center gap-5 mt-3 pt-3 border-t border-ink-100 text-xs text-ink-500">
            <span className="flex items-center gap-1"><Eye size={14} />{post.views}</span>
            <span className="flex items-center gap-1"><MessageCircle size={14} />{post.comments.length}</span>
          </div>
        </div>

        {/* 点赞按钮 */}
        <button
          onClick={toggleLike}
          className={cn(
            'w-full bg-white rounded-2xl p-3 shadow-card flex items-center justify-center gap-2 btn-press transition-colors',
            post.liked && 'bg-danger-50'
          )}
        >
          <Heart size={20} className={post.liked ? 'text-danger-500' : 'text-ink-400'} fill={post.liked ? 'currentColor' : 'none'} />
          <span className={cn('text-sm font-medium', post.liked ? 'text-danger-500' : 'text-ink-600')}>
            {post.likes} 人点赞
          </span>
        </button>

        {/* 评论区 */}
        <div className="bg-white rounded-2xl p-3.5 shadow-card animate-slide-up">
          <h3 className="font-display font-semibold text-ink-900 text-sm mb-3">
            评论 <span className="text-ink-400 font-normal">({post.comments.length})</span>
          </h3>
          {post.comments.length === 0 ? (
            <Empty icon="💬" title="暂无评论" desc="快来抢沙发" className="py-8" />
          ) : (
            <div className="space-y-3">
              {post.comments.map(c => (
                <CommentItem key={c.id} comment={c} />
              ))}
            </div>
          )}
        </div>
      </div>

      {/* 评论输入框 */}
      <div className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-white border-t border-ink-100 p-3 z-40" style={{ paddingBottom: 'calc(0.75rem + var(--safe-bottom))' }}>
        <div className="flex items-center gap-2">
          <input
            value={commentText}
            onChange={e => setCommentText(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && submitComment()}
            placeholder="写下你的评论..."
            className="flex-1 h-10 px-4 rounded-full bg-ink-100 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:bg-ink-50 focus:ring-2 focus:ring-primary-200"
          />
          <button
            onClick={submitComment}
            disabled={!commentText.trim()}
            className="w-10 h-10 rounded-full bg-gradient-blue-purple text-white flex items-center justify-center btn-press disabled:opacity-40 shadow-gradient"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

function CommentItem({ comment }: { comment: Comment }) {
  const [liked, setLiked] = useState(false);
  const [count, setCount] = useState(comment.likes);

  return (
    <div className="flex gap-2.5">
      <Avatar src={comment.author.avatar} name={comment.author.nickname} size={32} />
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5">
          <span className="text-sm font-medium text-ink-800">{comment.author.nickname}</span>
          <span className="text-[11px] text-ink-400">{comment.createdAt}</span>
        </div>
        <p className="text-sm text-ink-700 mt-0.5 leading-relaxed">{comment.content}</p>
        <button
          onClick={() => {
            setLiked(!liked);
            setCount(liked ? count - 1 : count + 1);
          }}
          className={cn('flex items-center gap-1 mt-1 text-[11px] btn-press', liked ? 'text-danger-500' : 'text-ink-400')}
        >
          <Heart size={12} fill={liked ? 'currentColor' : 'none'} />{count}
        </button>
      </div>
    </div>
  );
}
