import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Task, Order, TaskStatus, Conversation, Message, Notification, Post, Circle } from '@/types';
import {
  currentUser, tasks as initialTasks, orders as initialOrders,
  conversations as initialConversations, messages as initialMessages,
  notifications as initialNotifications, getUser,
  posts as initialPosts, circles as initialCircles,
} from '@/data/mock';

export interface CircleMessage {
  id: string;
  circleId: string;
  senderId: string;
  senderName: string;
  senderAvatar: string;
  content: string;
  createdAt: string;
}

interface AppState {
  // 用户
  user: typeof currentUser;
  currentSchool: string;
  setSchool: (school: string) => void;

  // 端切换
  mode: 'user' | 'admin';
  setMode: (mode: 'user' | 'admin') => void;

  // 任务
  tasks: Task[];
  publishTask: (task: Partial<Task>) => string;
  acceptTask: (taskId: string) => boolean;
  getTask: (id: string) => Task | undefined;

  // 订单
  orders: Order[];
  getOrder: (id: string) => Order | undefined;
  transitionOrder: (orderId: string, to: TaskStatus, desc?: string) => void;
  rateOrder: (orderId: string, score: number, comment: string, tags: string[]) => void;

  // 收藏
  favorites: string[];
  toggleFavorite: (taskId: string) => void;

  // 消息
  conversations: Conversation[];
  messages: Record<string, Message[]>;
  sendMessage: (conversationId: string, content: string) => void;
  markRead: (conversationId: string) => void;

  // 帖子
  posts: Post[];
  publishPost: (title: string, content: string, topic: string, anonymous: boolean) => void;
  togglePostLike: (postId: string) => void;

  // 吧台
  circles: Circle[];
  joinedCircles: string[];
  createCircle: (data: Partial<Circle>) => string;
  joinCircle: (circleId: string) => void;
  leaveCircle: (circleId: string) => void;
  circleMessages: Record<string, CircleMessage[]>;
  sendCircleMessage: (circleId: string, content: string) => void;

  // 通知
  notifications: Notification[];
  markNotificationRead: (id: string) => void;
  markAllNotificationsRead: () => void;

  // Toast
  toast: { message: string; type: 'success' | 'error' | 'info' } | null;
  showToast: (message: string, type?: 'success' | 'error' | 'info') => void;
  hideToast: () => void;
}

export const useStore = create<AppState>()(
  persist(
    (set, get) => ({
      user: currentUser,
      currentSchool: '清华大学',
      setSchool: (school) => set({ currentSchool: school }),

      mode: 'user',
      setMode: (mode) => set({ mode }),

      tasks: initialTasks,
      publishTask: (taskData) => {
        const id = 't' + Date.now();
        const newTask: Task = {
          id,
          title: taskData.title || '未命名任务',
          category: taskData.category || 'other',
          price: taskData.price || 0,
          location: taskData.location || '',
          deadline: taskData.deadline || '',
          status: 'OPEN',
          publisherId: currentUser.id,
          publisher: currentUser,
          images: taskData.images || [],
          description: taskData.description || '',
          createdAt: '刚刚',
          views: 0,
          favorites: 0,
          tags: taskData.tags || [],
          headcount: taskData.headcount || 1,
          deliveryMethod: taskData.deliveryMethod || '当面交付',
          hot: 0,
        };
        set(state => ({ tasks: [newTask, ...state.tasks] }));

        const newOrder: Order = {
          id: 'o' + Date.now(),
          taskId: id,
          task: newTask,
          status: 'OPEN',
          publisherId: currentUser.id,
          amount: newTask.price,
          serviceFee: Math.max(50, Math.min(2000, Math.round(newTask.price * 0.05))),
          accepterIncome: newTask.price - Math.max(50, Math.min(2000, Math.round(newTask.price * 0.05))),
          timeline: [{ status: 'OPEN', time: '刚刚', desc: '任务发布，等待接单' }],
          createdAt: '刚刚',
          updatedAt: '刚刚',
        };
        set(state => ({ orders: [newOrder, ...state.orders] }));
        return id;
      },
      acceptTask: (taskId) => {
        const task = get().tasks.find(t => t.id === taskId);
        if (!task || task.status !== 'OPEN') return false;
        if (task.publisherId === currentUser.id) return false;

        set(state => ({
          tasks: state.tasks.map(t =>
            t.id === taskId ? { ...t, status: 'ACCEPTED', accepterId: currentUser.id, accepter: currentUser } : t
          ),
        }));

        const existingOrder = get().orders.find(o => o.taskId === taskId);
        if (existingOrder) {
          set(state => ({
            orders: state.orders.map(o =>
              o.taskId === taskId ? {
                ...o,
                status: 'ACCEPTED',
                accepterId: currentUser.id,
                timeline: [...o.timeline, { status: 'ACCEPTED', time: '刚刚', desc: '你接取了任务' }],
                updatedAt: '刚刚',
              } : o
            ),
          }));
        }
        return true;
      },
      getTask: (id) => get().tasks.find(t => t.id === id),

      orders: initialOrders,
      getOrder: (id) => get().orders.find(o => o.id === id),
      transitionOrder: (orderId, to, desc) => {
        set(state => ({
          orders: state.orders.map(o => {
            if (o.id !== orderId) return o;
            const newTimeline = [...o.timeline, { status: to, time: '刚刚', desc: desc || '' }];
            return { ...o, status: to, timeline: newTimeline, updatedAt: '刚刚' };
          }),
          tasks: state.tasks.map(t =>
            t.id === get().orders.find(o => o.id === orderId)?.taskId ? { ...t, status: to } : t
          ),
        }));
      },
      rateOrder: (orderId, score, comment, tags) => {
        set(state => ({
          orders: state.orders.map(o =>
            o.id === orderId ? {
              ...o,
              rating: { score, comment, tags, fromRole: 'publisher' },
            } : o
          ),
        }));
      },

      favorites: ['t3', 't5'],
      toggleFavorite: (taskId) => {
        set(state => ({
          favorites: state.favorites.includes(taskId)
            ? state.favorites.filter(id => id !== taskId)
            : [...state.favorites, taskId],
        }));
      },

      conversations: initialConversations,
      messages: initialMessages,
      sendMessage: (conversationId, content) => {
        const newMsg: Message = {
          id: 'm' + Date.now(),
          conversationId,
          senderId: currentUser.id,
          content,
          type: 'text',
          createdAt: '刚刚',
          read: true,
        };
        set(state => ({
          messages: {
            ...state.messages,
            [conversationId]: [...(state.messages[conversationId] || []), newMsg],
          },
          conversations: state.conversations.map(c =>
            c.id === conversationId ? { ...c, lastMessage: content, lastTime: '刚刚' } : c
          ),
        }));

        setTimeout(() => {
          const replies = ['好的，收到', '没问题', '嗯嗯', '辛苦了', '我看看', '稍等一下'];
          const reply: Message = {
            id: 'm' + Date.now() + 1,
            conversationId,
            senderId: 'u3',
            content: replies[Math.floor(Math.random() * replies.length)],
            type: 'text',
            createdAt: '刚刚',
            read: false,
          };
          set(state => ({
            messages: {
              ...state.messages,
              [conversationId]: [...(state.messages[conversationId] || []), reply],
            },
            conversations: state.conversations.map(c =>
              c.id === conversationId ? { ...c, lastMessage: reply.content, lastTime: '刚刚', unread: c.unread + 1 } : c
            ),
          }));
        }, 1500);
      },
      markRead: (conversationId) => {
        set(state => ({
          conversations: state.conversations.map(c =>
            c.id === conversationId ? { ...c, unread: 0 } : c
          ),
          messages: {
            ...state.messages,
            [conversationId]: (state.messages[conversationId] || []).map(m => ({ ...m, read: true })),
          },
        }));
      },

      // 帖子
      posts: initialPosts,
      publishPost: (title, content, topic, anonymous) => {
        const newPost: Post = {
          id: 'p' + Date.now(),
          title,
          content,
          author: currentUser,
          images: [],
          likes: 0,
          liked: false,
          comments: [],
          views: 0,
          createdAt: '刚刚',
          topic,
          anonymous,
        };
        set(state => ({ posts: [newPost, ...state.posts] }));
      },
      togglePostLike: (postId) => {
        set(state => ({
          posts: state.posts.map(p =>
            p.id === postId ? { ...p, liked: !p.liked, likes: p.liked ? p.likes - 1 : p.likes + 1 } : p
          ),
        }));
      },

      // 吧台
      circles: initialCircles,
      joinedCircles: ['cir1', 'cir2', 'cir4'],
      createCircle: (data) => {
        const id = 'cir' + Date.now();
        const now = Date.now();
        const newCircle: Circle = {
          id,
          name: data.name || '未命名吧台',
          desc: data.desc || '',
          icon: data.icon || '🎪',
          tags: data.tags || [],
          ownerId: currentUser.id,
          owner: currentUser,
          members: [currentUser],
          memberLimit: data.memberLimit || 8,
          isPublic: data.isPublic ?? true,
          lifecycle: 'evaluating',
          createdAt: '刚刚',
          evaluateDeadline: now + 1000 * 60 * 60 * 24,
          activityScore: 10,
          activityThreshold: 80,
          lastMessage: '吧台刚创建，快来聊天',
          lastTime: '刚刚',
          unread: 0,
          hot: 30,
        };
        set(state => ({
          circles: [newCircle, ...state.circles],
          joinedCircles: [...state.joinedCircles, id],
          circleMessages: {
            ...state.circleMessages,
            [id]: [{ id: 'cm' + now, circleId: id, senderId: currentUser.id, senderName: currentUser.nickname, senderAvatar: currentUser.avatar, content: '吧台创建成功，欢迎聊天！', createdAt: '刚刚' }],
          },
        }));
        return id;
      },
      joinCircle: (circleId) => {
        const circle = get().circles.find(c => c.id === circleId);
        if (!circle) return;
        if (get().joinedCircles.includes(circleId)) return;
        if (circle.members.length >= circle.memberLimit) return;

        set(state => ({
          joinedCircles: [...state.joinedCircles, circleId],
          circles: state.circles.map(c =>
            c.id === circleId ? { ...c, members: [...c.members, currentUser], activityScore: c.activityScore + 5 } : c
          ),
        }));
      },
      leaveCircle: (circleId) => {
        set(state => ({
          joinedCircles: state.joinedCircles.filter(id => id !== circleId),
          circles: state.circles.map(c =>
            c.id === circleId ? { ...c, members: c.members.filter(m => m.id !== currentUser.id) } : c
          ),
        }));
      },
      circleMessages: {},
      sendCircleMessage: (circleId, content) => {
        const newMsg: CircleMessage = {
          id: 'cm' + Date.now(),
          circleId,
          senderId: currentUser.id,
          senderName: currentUser.nickname,
          senderAvatar: currentUser.avatar,
          content,
          createdAt: '刚刚',
        };
        set(state => ({
          circleMessages: {
            ...state.circleMessages,
            [circleId]: [...(state.circleMessages[circleId] || []), newMsg],
          },
          circles: state.circles.map(c =>
            c.id === circleId ? { ...c, lastMessage: content, lastTime: '刚刚', activityScore: c.activityScore + 2, unread: 0 } : c
          ),
        }));

        // 模拟群友回复
        setTimeout(() => {
          const replies = ['同感！', '哈哈', '说得对', '+1', '我也觉得', '不错不错'];
          const members = get().circles.find(c => c.id === circleId)?.members || [];
          const randomMember = members[Math.floor(Math.random() * Math.max(1, members.length))];
          if (!randomMember || randomMember.id === currentUser.id) return;
          const reply: CircleMessage = {
            id: 'cm' + Date.now() + 1,
            circleId,
            senderId: randomMember.id,
            senderName: randomMember.nickname,
            senderAvatar: randomMember.avatar,
            content: replies[Math.floor(Math.random() * replies.length)],
            createdAt: '刚刚',
          };
          set(state => ({
            circleMessages: {
              ...state.circleMessages,
              [circleId]: [...(state.circleMessages[circleId] || []), reply],
            },
            circles: state.circles.map(c =>
              c.id === circleId ? { ...c, lastMessage: reply.content, lastTime: '刚刚', activityScore: c.activityScore + 2 } : c
            ),
          }));
        }, 2000);
      },

      notifications: initialNotifications,
      markNotificationRead: (id) => {
        set(state => ({
          notifications: state.notifications.map(n => n.id === id ? { ...n, read: true } : n),
        }));
      },
      markAllNotificationsRead: () => {
        set(state => ({
          notifications: state.notifications.map(n => ({ ...n, read: true })),
        }));
      },

      toast: null,
      showToast: (message, type = 'success') => {
        set({ toast: { message, type } });
        setTimeout(() => set({ toast: null }), 2500);
      },
      hideToast: () => set({ toast: null }),
    }),
    {
      name: 'campus-pro-store',
      partialize: (state) => ({
        tasks: state.tasks,
        orders: state.orders,
        favorites: state.favorites,
        posts: state.posts,
        circles: state.circles,
        joinedCircles: state.joinedCircles,
        circleMessages: state.circleMessages,
        notifications: state.notifications,
      }),
    }
  )
);
