import { type ReactNode, useEffect } from 'react';
import { X } from 'lucide-react';
import { cn } from '@/lib/utils';

interface ModalProps {
  open: boolean;
  onClose: () => void;
  title?: string;
  children: ReactNode;
  position?: 'center' | 'bottom';
}

export default function Modal({ open, onClose, title, children, position = 'bottom' }: ModalProps) {
  useEffect(() => {
    if (open) {
      document.body.style.overflow = 'hidden';
      return () => { document.body.style.overflow = ''; };
    }
  }, [open]);

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-[90] flex" onClick={onClose}>
      <div className="absolute inset-0 bg-ink-900/20 backdrop-blur-sm animate-fade-in" />
      <div
        className={cn(
          'relative bg-white w-full max-w-[430px] mx-auto animate-slide-up shadow-float',
          position === 'bottom' ? 'mt-auto rounded-t-3xl' : 'm-auto rounded-3xl'
        )}
        onClick={e => e.stopPropagation()}
        style={position === 'bottom' ? { paddingBottom: 'var(--safe-bottom)', borderTop: '1px solid #EAE6DE' } : { border: '1px solid #EAE6DE' }}
      >
        {title && (
          <div className="flex items-center justify-between px-5 py-4 border-b border-ink-300">
            <h3 className="font-display font-semibold text-ink-900 tracking-tight">{title}</h3>
            <button onClick={onClose} className="p-1.5 rounded-xl hover:bg-ink-200 btn-press">
              <X size={18} className="text-ink-500" />
            </button>
          </div>
        )}
        {children}
      </div>
    </div>
  );
}
