import { useState, useRef, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Users, Flame, Lock, Clock, Infinity as InfinityIcon, Crown, Send, MessageCircle, ChevronDown } from 'lucide-react';
import { useCountdown } from '@/lib/useCountdown';
import { useStore } from '@/store';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { cn } from '@/lib/utils';
import type { Circle } from '@/types';

export default function CircleDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { showToast, circles, joinedCircles, circleMessages, sendCircleMessage, joinCircle, leaveCircle } = useStore();
  const circle = id ? circles.find(c => c.id === id) : undefined;
  const [chatExpanded, setChatExpanded] = useState(false);
  const [messageInput, setMessageInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  const messages = id ? (circleMessages[id] || []) : [];

  useEffect(() => {
    if (chatExpanded && chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatExpanded, messages.length]);

  if (!circle) {
    return (
      <div className="min-h-screen bg-ink-50">
        <header className="sticky top-0 z-40 bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
          <div className="flex items-center h-14 px-4">
            <button onClick={() => navigate(-1)} className="p-1.5 -ml-1.5 rounded-full hover:bg-white/20 btn-press">
              <ArrowLeft size={20} />
            </button>
            <h1 className="font-display font-semibold text-base ml-2">吧台详情</h1>
          </div>
        </header>
        <Empty icon="🔍" title="吧台不存在" desc="该吧台可能已解散" />
      </div>
    );
  }

  const progress = circle.activityScore / circle.activityThreshold;
  const isOwner = circle.ownerId === 'u1';
  const isJoined = joinedCircles.includes(circle.id);

  const handleSend = () => {
    const content = messageInput.trim();
    if (!content) return;
    sendCircleMessage(circle.id, content);
    setMessageInput('');
  };

  const handleJoin = () => {
    joinCircle(circle.id);
    showToast('已加入吧台', 'success');
  };

  const handleLeave = () => {
    leaveCircle(circle.id);
    showToast('已退出吧台', 'info');
  };

  // 群聊为空时展示的模拟初始消息
  const displayMessages = messages.length > 0
    ? messages
    : [
        { id: 'init-1', circleId: circle.id, senderId: circle.ownerId, senderName: circle.owner.nickname, senderAvatar: circle.owner.avatar, content: circle.lastMessage, createdAt: circle.lastTime },
        ...(circle.members[1] ? [{ id: 'init-2', circleId: circle.id, senderId: circle.members[1].id, senderName: circle.members[1].nickname, senderAvatar: circle.members[1].avatar, content: '收到，我稍后回复', createdAt: '刚才' }] : []),
      ];

  return (
    <div className="min-h-screen bg-ink-50 pb-32">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="flex items-center h-14 px-4">
          <button onClick={() => navigate(-1)} className="p-1.5 -ml-1.5 rounded-full hover:bg-white/20 btn-press">
            <ArrowLeft size={20} />
          </button>
          <h1 className="font-display font-semibold text-base ml-2">吧台详情</h1>
        </div>

        {/* 吧台信息卡 */}
        <div className="px-4 pb-4">
          <div className="flex items-start gap-3">
            <div className="w-16 h-16 rounded-2xl bg-white/20 backdrop-blur flex items-center justify-center text-3xl shrink-0">
              {circle.icon}
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1.5 mb-1">
                {!circle.isPublic && <Lock size={12} className="text-white/70" />}
                <h2 className="font-display text-lg font-bold truncate">{circle.name}</h2>
              </div>
              <p className="text-white/80 text-xs leading-relaxed line-clamp-2">{circle.desc}</p>
              <div className="flex flex-wrap gap-1 mt-1.5">
                {circle.tags.map(tag => (
                  <span key={tag} className="text-[10px] px-1.5 py-0.5 rounded bg-white/20 backdrop-blur">#{tag}</span>
                ))}
              </div>
            </div>
          </div>

          {/* 统计 */}
          <div className="grid grid-cols-3 gap-2 mt-3">
            <div className="bg-white/15 backdrop-blur rounded-xl py-2 text-center">
              <div className="flex items-center justify-center gap-1 text-white/70 text-[10px] mb-0.5">
                <Users size={10} /> 成员
              </div>
              <div className="font-display font-bold text-sm">{circle.members.length}/{circle.memberLimit}</div>
            </div>
            <div className="bg-white/15 backdrop-blur rounded-xl py-2 text-center">
              <div className="flex items-center justify-center gap-1 text-white/70 text-[10px] mb-0.5">
                <Flame size={10} /> 热度
              </div>
              <div className="font-display font-bold text-sm">{circle.hot}</div>
            </div>
            <div className="bg-white/15 backdrop-blur rounded-xl py-2 text-center">
              <div className="flex items-center justify-center gap-1 text-white/70 text-[10px] mb-0.5">
                <Clock size={10} /> 状态
              </div>
              <div className="font-display font-bold text-sm">
                {circle.lifecycle === 'permanent' ? '永久' : circle.lifecycle === 'expiring' ? '即将解散' : '评估中'}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="p-3 space-y-3 -mt-1">
        {/* 生命周期面板 - 核心创新点展示 */}
        {circle.lifecycle !== 'permanent' && circle.evaluateDeadline ? (
          <LifecyclePanel circle={circle} progress={progress} />
        ) : (
          <div className="bg-white rounded-2xl p-4 shadow-card border border-ink-100 flex items-center gap-3">
            <div className="w-12 h-12 rounded-xl bg-success-50 flex items-center justify-center">
              <InfinityIcon size={24} className="text-success-500" />
            </div>
            <div>
              <p className="text-sm font-bold text-ink-900">永久吧台</p>
              <p className="text-[11px] text-ink-400">该吧台已通过活跃度评估，转为永久群组</p>
            </div>
          </div>
        )}

        {/* 成员列表 */}
        <div className="bg-white rounded-2xl p-4 shadow-card border border-ink-100">
          <div className="flex items-center justify-between mb-3">
            <h3 className="text-sm font-bold text-ink-900">成员 ({circle.members.length})</h3>
            <span className="text-[11px] text-ink-400">上限 {circle.memberLimit} 人</span>
          </div>
          <div className="grid grid-cols-5 gap-3">
            {circle.members.map(member => (
              <div key={member.id} className="flex flex-col items-center gap-1">
                <div className="relative">
                  <Avatar src={member.avatar} name={member.nickname} size={40} />
                  {member.id === circle.ownerId && (
                    <span className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-warning-500 flex items-center justify-center">
                      <Crown size={9} className="text-white" />
                    </span>
                  )}
                </div>
                <span className="text-[10px] text-ink-600 truncate max-w-full">{member.nickname}</span>
              </div>
            ))}
            {/* 空位 */}
            {Array.from({ length: Math.max(0, circle.memberLimit - circle.members.length) }).slice(0, 3).map((_, i) => (
              <div key={`empty-${i}`} className="flex flex-col items-center gap-1">
                <div className="w-10 h-10 rounded-full border-2 border-dashed border-ink-200 flex items-center justify-center">
                  <Users size={14} className="text-ink-300" />
                </div>
                <span className="text-[10px] text-ink-300">空位</span>
              </div>
            ))}
          </div>
        </div>

        {/* 群聊动态 */}
        <div id="chat-section" className="bg-white rounded-2xl p-4 shadow-card border border-ink-100">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-1.5">
              <MessageCircle size={15} className="text-primary-600" />
              <h3 className="text-sm font-bold text-ink-900">群聊动态</h3>
            </div>
            <button
              onClick={() => setChatExpanded(v => !v)}
              className="flex items-center gap-0.5 text-[11px] text-primary-600 font-medium btn-press"
            >
              {chatExpanded ? '收起' : '展开完整群聊'}
              <ChevronDown size={12} className={cn('transition-transform', chatExpanded && 'rotate-180')} />
            </button>
          </div>

          {chatExpanded ? (
            <>
              {/* 消息列表 */}
              <div className="space-y-2.5 max-h-[50vh] overflow-y-auto pr-1">
                {displayMessages.map(msg => (
                  <ChatBubble
                    key={msg.id}
                    sender={{ id: msg.senderId, nickname: msg.senderName, avatar: msg.senderAvatar }}
                    content={msg.content}
                    time={msg.createdAt}
                  />
                ))}
                <div ref={chatEndRef} />
              </div>

              {/* 输入框 */}
              <div className="mt-3 flex items-center gap-2 pt-3 border-t border-ink-100">
                <input
                  value={messageInput}
                  onChange={e => setMessageInput(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter') handleSend(); }}
                  placeholder={isJoined ? '说点什么…' : '加入吧台后即可发言'}
                  disabled={!isJoined}
                  className="flex-1 px-3 py-2 rounded-full bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-300 focus:outline-none focus:border-primary-400 focus:bg-white transition-colors disabled:opacity-60"
                />
                <button
                  onClick={handleSend}
                  disabled={!isJoined || !messageInput.trim()}
                  className="w-9 h-9 rounded-full bg-gradient-blue-purple text-white flex items-center justify-center btn-press disabled:opacity-40 disabled:shadow-none shadow-gradient"
                >
                  <Send size={16} />
                </button>
              </div>
            </>
          ) : (
            <div className="space-y-2.5">
              <ChatBubble
                sender={{ id: circle.ownerId, nickname: circle.owner.nickname, avatar: circle.owner.avatar }}
                content={circle.lastMessage}
                time={circle.lastTime}
              />
              {circle.members[1] && (
                <ChatBubble
                  sender={{ id: circle.members[1].id, nickname: circle.members[1].nickname, avatar: circle.members[1].avatar }}
                  content="收到，我稍后回复"
                  time="刚才"
                />
              )}
            </div>
          )}
        </div>

        {/* 创建信息 */}
        <div className="bg-white rounded-2xl p-4 shadow-card border border-ink-100">
          <div className="flex items-center justify-between text-xs">
            <div>
              <span className="text-ink-400">创建者</span>
              <span className="text-ink-700 font-medium ml-1">{circle.owner.nickname}</span>
            </div>
            <div>
              <span className="text-ink-400">创建于</span>
              <span className="text-ink-700 font-medium ml-1">{circle.createdAt}</span>
            </div>
          </div>
          {circle.lifecycle !== 'permanent' && (
            <div className="mt-2 pt-2 border-t border-ink-100 text-[11px] text-ink-400 leading-relaxed">
              限时吧台规则：创建后进入 24 小时评估期，活跃度达到 {circle.activityThreshold} 分即可转为永久吧台；未达标将在评估截止后自动解散，解散后群聊只读保留 7 天。
            </div>
          )}
        </div>
      </div>

      {/* 底部操作栏 */}
      <div className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-white/95 backdrop-blur border-t border-ink-100 p-3 z-40" style={{ paddingBottom: 'calc(var(--safe-bottom) + 12px)' }}>
        {isJoined ? (
          <div className="flex gap-2">
            <button
              onClick={() => {
                setChatExpanded(true);
                setTimeout(() => {
                  document.getElementById('chat-section')?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                }, 50);
              }}
              className="flex-1 py-3 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold shadow-gradient flex items-center justify-center gap-1.5 btn-press"
            >
              <Send size={16} /> 进入群聊
            </button>
            {!isOwner && (
              <button
                onClick={handleLeave}
                className="px-4 py-3 rounded-xl bg-ink-100 text-ink-600 text-sm font-medium btn-press"
              >
                退出
              </button>
            )}
          </div>
        ) : (
          <button
            onClick={handleJoin}
            className="w-full py-3.5 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold shadow-gradient-lg btn-press"
          >
            {circle.isPublic ? '加入吧台' : '申请加入'}
          </button>
        )}
      </div>
    </div>
  );
}

function LifecyclePanel({ circle, progress }: { circle: Circle; progress: number }) {
  const { hours, minutes, seconds, expired } = useCountdown(circle.evaluateDeadline);
  if (expired) return null;

  const timeStr = `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
  const isExpiring = circle.lifecycle === 'expiring';
  const reachedThreshold = progress >= 1;

  return (
    <div className={cn('rounded-2xl p-4 shadow-card border', isExpiring ? 'bg-danger-50 border-danger-100' : 'bg-white border-ink-100')}>
      <div className="flex items-center gap-1.5 mb-3">
        <Clock size={15} className={isExpiring ? 'text-danger-500' : 'text-primary-600'} />
        <h3 className="text-sm font-bold text-ink-900">
          {isExpiring ? '即将解散倒计时' : '生命周期评估'}
        </h3>
      </div>

      {/* 大号倒计时 */}
      <div className="text-center my-3">
        <div className={cn('font-display font-bold font-mono text-3xl tracking-wider', isExpiring ? 'text-danger-600' : 'text-gradient')}>
          {timeStr}
        </div>
        <p className={cn('text-[11px] mt-1', isExpiring ? 'text-danger-500' : 'text-ink-400')}>
          {isExpiring ? '距离自动解散' : '距离评估截止'}
        </p>
      </div>

      {/* 活跃度进度 */}
      <div className="mb-2">
        <div className="flex items-center justify-between text-[11px] mb-1.5">
          <span className="text-ink-500">活跃度</span>
          <span className={cn('font-bold', reachedThreshold ? 'text-success-600' : isExpiring ? 'text-danger-600' : 'text-primary-600')}>
            {circle.activityScore} / {circle.activityThreshold}
          </span>
        </div>
        <div className="h-2.5 rounded-full bg-ink-100 overflow-hidden">
          <div
            className={cn('h-full rounded-full transition-all duration-700', reachedThreshold ? 'bg-gradient-success' : isExpiring ? 'bg-gradient-rose' : 'bg-gradient-blue-purple')}
            style={{ width: `${Math.min(100, progress * 100)}%` }}
          />
        </div>
      </div>

      {/* 状态提示 */}
      <div className={cn('rounded-lg px-3 py-2 text-[11px] leading-relaxed', reachedThreshold ? 'bg-success-50 text-success-700' : isExpiring ? 'bg-danger-50/50 text-danger-600' : 'bg-primary-50 text-primary-700')}>
        {reachedThreshold ? (
          '已达到活跃阈值，评估截止后将自动转为永久吧台'
        ) : isExpiring ? (
          `活跃度不足，距阈值还差 ${circle.activityThreshold - circle.activityScore} 分，到期后将自动解散`
        ) : (
          `还需 ${circle.activityThreshold - circle.activityScore} 分活跃度即可转为永久，多发消息、邀请成员可提升活跃度`
        )}
      </div>
    </div>
  );
}

function ChatBubble({ sender, content, time }: { sender: { id: string; nickname: string; avatar: string }; content: string; time: string }) {
  const isMe = sender.id === 'u1';
  return (
    <div className={cn('flex items-start gap-2', isMe && 'flex-row-reverse')}>
      <Avatar src={sender.avatar} name={sender.nickname} size={28} />
      <div className={cn('flex-1 max-w-[75%]', isMe && 'flex flex-col items-end')}>
        <div className="flex items-center gap-1.5 mb-0.5">
          <span className="text-[10px] text-ink-400">{sender.nickname}</span>
          <span className="text-[10px] text-ink-300">{time}</span>
        </div>
        <div className={cn('inline-block px-3 py-2 rounded-2xl text-xs', isMe ? 'bg-primary-600 text-white rounded-tr-sm' : 'bg-ink-50 text-ink-700 rounded-tl-sm')}>
          {content}
        </div>
      </div>
    </div>
  );
}
