import { useState, useEffect, useMemo, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Bell, Search, ChevronDown, Plus, Flame, MessageCircle, Heart, Eye, X, TrendingUp, ArrowLeft } from 'lucide-react';
import { useStore } from '@/store';
import { banners, categoryConfig, posts, schools } from '@/data/mock';
import type { TaskCategory } from '@/types';
import TaskCard from '@/components/TaskCard';
import Modal from '@/components/Modal';
import Avatar from '@/components/Avatar';
import { cn } from '@/lib/utils';

const HOT_KEYWORDS = ['代取快递', '高数辅导', '二手自行车', '海报设计', '兼职', '英语润色'];

export default function Home() {
  const navigate = useNavigate();
  const { currentSchool, setSchool, tasks, notifications, showToast } = useStore();
  const [schoolOpen, setSchoolOpen] = useState(false);
  const [bannerIdx, setBannerIdx] = useState(0);
  const [searchOpen, setSearchOpen] = useState(false);
  const [keyword, setKeyword] = useState('');
  const [recentSearches, setRecentSearches] = useState<string[]>(() => {
    try { return JSON.parse(localStorage.getItem('recent-searches') || '[]'); } catch { return []; }
  });
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const t = setInterval(() => setBannerIdx(i => (i + 1) % banners.length), 3500);
    return () => clearInterval(t);
  }, []);

  const searchResults = useMemo(() => {
    if (!keyword.trim()) return [];
    const kw = keyword.toLowerCase();
    return tasks.filter(t =>
      t.title.toLowerCase().includes(kw) ||
      t.description.toLowerCase().includes(kw) ||
      t.tags.some(tag => tag.toLowerCase().includes(kw)) ||
      t.location.toLowerCase().includes(kw)
    ).slice(0, 10);
  }, [keyword, tasks]);

  const openSearch = () => {
    setSearchOpen(true);
    setTimeout(() => searchInputRef.current?.focus(), 100);
  };

  const saveRecent = (kw: string) => {
    const updated = [kw, ...recentSearches.filter(s => s !== kw)].slice(0, 6);
    setRecentSearches(updated);
    localStorage.setItem('recent-searches', JSON.stringify(updated));
  };

  const closeSearch = () => {
    if (keyword.trim()) saveRecent(keyword.trim());
    setSearchOpen(false);
    setKeyword('');
  };

  const pickKeyword = (kw: string) => {
    setKeyword(kw);
    searchInputRef.current?.focus();
  };

  const openTasks = tasks.filter(t => t.status === 'OPEN').slice(0, 5);
  const hotPosts = posts.slice(0, 3);
  const unreadCount = notifications.filter(n => !n.read).length;
  const categories = Object.entries(categoryConfig) as [TaskCategory, typeof categoryConfig[TaskCategory]][];

  return (
    <div className="min-h-screen bg-ink-50">
      {/* 顶部渐变区 - 科幻蓝 */}
      <div className="bg-header-sci-fi-blue text-white pb-6" style={{ paddingTop: 'calc(var(--safe-top) + 12px)' }}>
        <div className="px-4">
          {/* 顶栏：学校 + 通知 */}
          <div className="flex items-center justify-between">
            <button
              onClick={() => setSchoolOpen(true)}
              className="flex items-center gap-1 font-display font-semibold text-base btn-press"
            >
              <span className="text-lg">📍</span>
              <span>{currentSchool}</span>
              <ChevronDown size={16} className="opacity-90" />
            </button>
            <Link to="/notifications" className="relative p-1.5 rounded-full bg-white/20 backdrop-blur btn-press">
              <Bell size={18} />
              {unreadCount > 0 && (
                <span className="absolute -top-0.5 -right-0.5 min-w-[15px] h-[15px] px-1 bg-danger-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center ring-2 ring-white/30">
                  {unreadCount}
                </span>
              )}
            </Link>
          </div>

          {/* 搜索栏 */}
          <button
            onClick={openSearch}
            className="mt-3 w-full flex items-center gap-2 bg-white/95 rounded-full px-4 py-2.5 text-ink-400 text-sm btn-press shadow-lg"
          >
            <Search size={16} className="text-primary-500" />
            <span>搜索任务、服务、用户…</span>
          </button>
        </div>

        {/* Banner 轮播 */}
        <div className="mt-4 px-4">
          <div className="relative h-28 rounded-2xl overflow-hidden shadow-lg">
            {banners.map((b, i) => (
              <Link
                key={b.id}
                to={b.link}
                className={cn(
                  'absolute inset-0 bg-gradient-to-br p-4 flex flex-col justify-center transition-opacity duration-500',
                  b.color,
                  i === bannerIdx ? 'opacity-100' : 'opacity-0 pointer-events-none'
                )}
              >
                <h3 className="font-display font-bold text-lg leading-tight drop-shadow-sm">{b.title}</h3>
                <p className="text-xs text-white/90 mt-1">{b.subtitle}</p>
              </Link>
            ))}
          </div>
          <div className="flex items-center justify-center gap-1.5 mt-2.5">
            {banners.map((_, i) => (
              <button
                key={i}
                onClick={() => setBannerIdx(i)}
                className={cn(
                  'h-1.5 rounded-full transition-all',
                  i === bannerIdx ? 'w-4 bg-white' : 'w-1.5 bg-white/50'
                )}
              />
            ))}
          </div>
        </div>
      </div>

      {/* 快捷分类 */}
      <div className="px-4 -mt-2">
        <div className="bg-white rounded-2xl shadow-card p-3.5 border border-ink-100">
          <div className="grid grid-cols-4 gap-3">
            {categories.map(([key, cfg]) => (
              <Link
                key={key}
                to={`/tasks?cat=${key}`}
                className="flex flex-col items-center gap-1.5 btn-press"
              >
                <div
                  className="w-11 h-11 rounded-xl flex items-center justify-center text-xl"
                  style={{ backgroundColor: cfg.color + '15', boxShadow: `0 2px 8px ${cfg.color}10` }}
                >
                  {cfg.icon}
                </div>
                <span className="text-[11px] text-ink-600 font-medium">{cfg.label}</span>
              </Link>
            ))}
          </div>
        </div>
      </div>

      {/* 推荐任务 */}
      <div className="px-4 mt-5">
        <div className="flex items-center justify-between mb-3">
          <h2 className="font-display font-semibold text-ink-900 text-base flex items-center gap-1.5">
            <Flame size={18} className="text-warning-500" /> 推荐任务
          </h2>
          <Link to="/tasks" className="text-xs text-primary-600 font-medium">查看全部 ›</Link>
        </div>
        <div className="space-y-2.5">
          {openTasks.map(t => <TaskCard key={t.id} task={t} />)}
        </div>
      </div>

      {/* 校园热议 */}
      <div className="px-4 mt-6">
        <div className="flex items-center justify-between mb-3">
          <h2 className="font-display font-semibold text-ink-900 text-base flex items-center gap-1.5">
            <MessageCircle size={18} className="text-primary-600" /> 校园热议
          </h2>
          <Link to="/plaza" className="text-xs text-primary-600 font-medium">去广场 ›</Link>
        </div>
        <div className="space-y-2.5">
          {hotPosts.map(p => (
            <Link
              key={p.id}
              to={`/plaza/post/${p.id}`}
              className="block bg-gradient-card rounded-2xl p-3.5 shadow-soft-xs btn-press border border-white"
            >
              <div className="flex items-start gap-2.5">
                <Avatar src={p.author.avatar} name={p.author.nickname} size={32} />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-1.5">
                    <span className="text-xs font-medium text-ink-700">
                      {p.anonymous ? '匿名同学' : p.author.nickname}
                    </span>
                    <span className="text-[10px] px-1.5 py-0.5 rounded badge-gradient font-medium">
                      {p.topic}
                    </span>
                  </div>
                  <h3 className="text-sm font-semibold text-ink-900 mt-1 line-clamp-1">{p.title}</h3>
                  <p className="text-xs text-ink-500 mt-0.5 line-clamp-2">{p.content}</p>
                  <div className="flex items-center gap-3 mt-2 text-[11px] text-ink-400">
                    <span className="flex items-center gap-0.5"><Heart size={12} />{p.likes}</span>
                    <span className="flex items-center gap-0.5"><MessageCircle size={12} />{p.comments.length}</span>
                    <span className="flex items-center gap-0.5"><Eye size={12} />{p.views}</span>
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>

      <div className="h-24" />

      {/* 发布任务浮动按钮 - 渐变 */}
      <button
        onClick={() => navigate('/publish')}
        className="fixed bottom-20 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-gradient-blue-purple text-white px-5 py-3 rounded-full shadow-gradient-lg btn-press z-30"
      >
        <Plus size={20} strokeWidth={2.5} />
        <span className="font-semibold text-sm">发布任务</span>
      </button>

      {/* 学校切换 */}
      <Modal open={schoolOpen} onClose={() => setSchoolOpen(false)} title="选择学校">
        <div className="py-2 max-h-[50vh] overflow-y-auto">
          {schools.map(s => (
            <button
              key={s.id}
              disabled={!s.opened}
              onClick={() => {
                setSchool(s.name);
                setSchoolOpen(false);
                showToast(`已切换到${s.name}`, 'success');
              }}
              className={cn(
                'w-full flex items-center gap-3 px-5 py-3.5 hover:bg-ink-50 transition-colors btn-press',
                !s.opened && 'opacity-40',
                currentSchool === s.name && 'bg-primary-50'
              )}
            >
              <span className="text-2xl">{s.logo}</span>
              <span className="flex-1 text-left font-medium text-ink-800">{s.name}</span>
              {!s.opened && <span className="text-xs text-ink-400">即将开放</span>}
              {s.opened && currentSchool === s.name && <span className="text-primary-600 text-sm">✓</span>}
            </button>
          ))}
        </div>
      </Modal>

      {/* 搜索弹窗 */}
      {searchOpen && (
        <div className="fixed inset-0 z-50 bg-white flex flex-col animate-fade-in">
          {/* 搜索头 */}
          <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
            <div className="flex items-center gap-2 px-4 py-3">
              <button onClick={closeSearch} className="p-1.5 -ml-1.5 rounded-full hover:bg-white/20 btn-press">
                <ArrowLeft size={20} />
              </button>
              <div className="flex-1 flex items-center gap-2 bg-white/95 rounded-full px-3.5 py-2">
                <Search size={16} className="text-primary-500 shrink-0" />
                <input
                  ref={searchInputRef}
                  value={keyword}
                  onChange={e => setKeyword(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter' && keyword.trim()) saveRecent(keyword.trim()); }}
                  placeholder="搜索任务、服务、地点…"
                  className="flex-1 bg-transparent text-sm text-ink-800 placeholder:text-ink-400 focus:outline-none"
                />
                {keyword && (
                  <button onClick={() => setKeyword('')} className="p-0.5 rounded-full hover:bg-ink-100">
                    <X size={14} className="text-ink-400" />
                  </button>
                )}
              </div>
            </div>
          </div>

          {/* 搜索内容区 */}
          <div className="flex-1 overflow-y-auto bg-ink-50">
            {!keyword.trim() ? (
              <div className="p-4 space-y-5">
                {/* 最近搜索 */}
                {recentSearches.length > 0 && (
                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-xs font-semibold text-ink-500">最近搜索</span>
                      <button
                        onClick={() => { setRecentSearches([]); localStorage.removeItem('recent-searches'); }}
                        className="text-[11px] text-ink-400"
                      >
                        清空
                      </button>
                    </div>
                    <div className="flex flex-wrap gap-2">
                      {recentSearches.map(s => (
                        <button
                          key={s}
                          onClick={() => pickKeyword(s)}
                          className="px-3 py-1.5 rounded-full bg-white text-ink-600 text-xs font-medium border border-ink-200 btn-press"
                        >
                          {s}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
                {/* 热门搜索 */}
                <div>
                  <div className="flex items-center gap-1 mb-2">
                    <TrendingUp size={13} className="text-danger-500" />
                    <span className="text-xs font-semibold text-ink-500">热门搜索</span>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {HOT_KEYWORDS.map(s => (
                      <button
                        key={s}
                        onClick={() => pickKeyword(s)}
                        className="px-3 py-1.5 rounded-full bg-white text-ink-600 text-xs font-medium border border-ink-200 btn-press"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            ) : searchResults.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                <Search size={40} className="text-ink-200 mb-3" />
                <p className="text-sm text-ink-400">未找到"{keyword}"相关的任务</p>
                <p className="text-xs text-ink-300 mt-1">试试换个关键词</p>
              </div>
            ) : (
              <div className="p-3 space-y-2.5">
                <p className="text-xs text-ink-400 px-1">找到 {searchResults.length} 个相关任务</p>
                {searchResults.map(task => (
                  <div key={task.id} onClick={closeSearch}>
                    <TaskCard task={task} />
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
