import { useState } from 'react';
import {
  DollarSign, TrendingUp, Clock, RotateCcw, CheckCircle2, ShieldCheck,
} from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import Empty from '@/components/Empty';
import { adminFinance, adminStats, formatPrice } from '@/data/mock';
import { cn } from '@/lib/utils';

const summaryCards = [
  { label: '总成交额', value: `¥${adminStats.totalGMV.toLocaleString()}`, icon: DollarSign, color: '#2563EB', bg: '#DBEAFE' },
  { label: '平台收入', value: `¥${(adminStats.totalGMV * 0.05).toFixed(2)}`, icon: TrendingUp, color: '#10B981', bg: '#D1FAE5' },
  { label: '待结算', value: `¥${(adminStats.totalGMV * 0.12).toFixed(2)}`, icon: Clock, color: '#F59E0B', bg: '#FEF3C7' },
  { label: '退款金额', value: `¥${(adminStats.totalGMV * 0.02).toFixed(2)}`, icon: RotateCcw, color: '#EF4444', bg: '#FEE2E2' },
];

const tabs = [
  { label: '全部', value: 'ALL' },
  { label: '支付', value: 'pay' },
  { label: '退款', value: 'refund' },
  { label: '结算', value: 'income' },
  { label: '提现', value: 'withdraw' },
];

const typeConfig: Record<string, { label: string; color: string; bg: string }> = {
  pay: { label: '支付', color: '#2563EB', bg: '#DBEAFE' },
  income: { label: '结算', color: '#10B981', bg: '#D1FAE5' },
  fee: { label: '服务费', color: '#F59E0B', bg: '#FEF3C7' },
  refund: { label: '退款', color: '#EF4444', bg: '#FEE2E2' },
  withdraw: { label: '提现', color: '#8B5CF6', bg: '#EDE9FE' },
  adjust: { label: '调整', color: '#64748B', bg: '#F1F5F9' },
};

export default function AdminFinance() {
  const [tab, setTab] = useState('ALL');

  const filtered = adminFinance.filter(t => tab === 'ALL' || t.type === tab);

  return (
    <AdminLayout>
      {/* 汇总卡片 */}
      <section className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        {summaryCards.map(card => (
          <div key={card.label} className="bg-white rounded-xl p-3.5 shadow-card">
            <div
              className="w-9 h-9 rounded-lg flex items-center justify-center"
              style={{ backgroundColor: card.bg }}
            >
              <card.icon size={18} style={{ color: card.color }} />
            </div>
            <div className="mt-2.5">
              <div className="text-lg font-bold text-ink-900 font-display">{card.value}</div>
              <div className="text-xs text-ink-500 mt-0.5">{card.label}</div>
            </div>
          </div>
        ))}
      </section>

      {/* 对账状态 */}
      <section className="mt-3 bg-white rounded-2xl p-4 shadow-card">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-success-100 flex items-center justify-center">
              <ShieldCheck size={20} className="text-success-600" />
            </div>
            <div>
              <h2 className="font-display font-semibold text-ink-900 text-sm">对账状态</h2>
              <p className="text-xs text-ink-500 mt-0.5">今日已对账 · 差异 0 笔</p>
            </div>
          </div>
          <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-success-50">
            <CheckCircle2 size={14} className="text-success-500" />
            <span className="text-xs font-medium text-success-600">正常</span>
          </div>
        </div>
      </section>

      {/* 交易流水 */}
      <div className="mt-3 bg-white rounded-2xl shadow-card overflow-hidden">
        <div className="px-4 py-3 border-b border-ink-100">
          <h2 className="font-display font-semibold text-ink-900 text-sm">交易流水</h2>
        </div>
        <div className="px-3 py-2 border-b border-ink-100">
          <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
            {tabs.map(t => (
              <button
                key={t.value}
                onClick={() => setTab(t.value)}
                className={cn(
                  'px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors',
                  tab === t.value ? 'bg-primary-600 text-white' : 'bg-ink-100 text-ink-500'
                )}
              >
                {t.label}
              </button>
            ))}
          </div>
        </div>

        {filtered.length === 0 ? (
          <Empty icon="💰" title="暂无交易记录" />
        ) : (
          <div className="divide-y divide-ink-100">
            {filtered.map(tx => {
              const cfg = typeConfig[tx.type] || typeConfig.adjust;
              const isIncome = tx.amount > 0;
              return (
                <div key={tx.id} className="p-3.5 hover:bg-ink-50/50 transition-colors">
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex items-start gap-2.5 min-w-0">
                      <div
                        className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0"
                        style={{ backgroundColor: cfg.bg }}
                      >
                        <DollarSign size={16} style={{ color: cfg.color }} />
                      </div>
                      <div className="min-w-0">
                        <div className="flex items-center gap-1.5">
                          <span
                            className="text-[10px] px-1.5 py-0.5 rounded font-medium"
                            style={{ color: cfg.color, backgroundColor: cfg.bg }}
                          >
                            {cfg.label}
                          </span>
                          {tx.relatedOrder && (
                            <span className="text-[10px] text-ink-400 font-mono">{tx.relatedOrder}</span>
                          )}
                        </div>
                        <p className="text-sm text-ink-800 mt-1 line-clamp-1">{tx.desc}</p>
                        <p className="text-[11px] text-ink-400 mt-0.5">{tx.createdAt}</p>
                      </div>
                    </div>
                    <div className="text-right shrink-0">
                      <div className={cn(
                        'text-base font-bold font-display',
                        isIncome ? 'text-success-600' : 'text-danger-600'
                      )}>
                        {isIncome ? '+' : ''}¥{formatPrice(Math.abs(tx.amount))}
                      </div>
                      <div className="text-[10px] text-ink-400 mt-0.5">余额 ¥{formatPrice(tx.balanceAfter)}</div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
