import { useState } from 'react';
import { cn } from '@/lib/utils';

interface AvatarProps {
  src?: string;
  name: string;
  size?: number;
  className?: string;
  ring?: boolean;
}

export default function Avatar({ src, name, size = 40, className, ring }: AvatarProps) {
  const [imgError, setImgError] = useState(false);
  const initials = name.slice(0, 1);
  const colors = ['#2563EB', '#10B981', '#F59E0B', '#8B5CF6', '#EC4899', '#06B6D4'];
  const colorIdx = name.charCodeAt(0) % colors.length;

  return (
    <div
      className={cn('relative shrink-0 rounded-full overflow-hidden flex items-center justify-center text-white font-semibold', ring && 'ring-2 ring-white shadow-md', className)}
      style={{ width: size, height: size, backgroundColor: colors[colorIdx], fontSize: size * 0.4 }}
    >
      {src && !imgError ? (
        <img
          src={src}
          alt={name}
          className="w-full h-full object-cover"
          onError={() => setImgError(true)}
        />
      ) : (
        initials
      )}
    </div>
  );
}
