import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Sparkles, Loader2, Share2, RefreshCw } from 'lucide-react';
import { generatePersonalityCard, type PersonalityCard } from '@/services/ai';
import { useStore } from '@/store';
import Avatar from '@/components/Avatar';

export default function AIPersonality() {
  const navigate = useNavigate();
  const { user, showToast } = useStore();
  const [loading, setLoading] = useState(false);
  const [card, setCard] = useState<PersonalityCard | null>(null);
  const [seed, setSeed] = useState(0);

  const generate = () => {
    setLoading(true);
    setCard(null);
    setTimeout(() => {
      const result = generatePersonalityCard(user);
      setCard(result);
      setLoading(false);
    }, 1600);
  };

  // 首次进入自动生成
  useEffect(() => {
    if (!card && !loading && seed === 0) {
      setSeed(1);
      generate();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [card, loading, seed]);

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      {/* 顶部科幻蓝渐变区 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="flex items-center gap-3 h-14 px-4">
          <button onClick={() => navigate(-1)} className="p-1.5 -ml-1.5 rounded-full btn-press">
            <ArrowLeft size={20} />
          </button>
          <div className="flex items-center gap-1.5">
            <Sparkles size={18} />
            <h1 className="font-display font-semibold text-base">AI 校园人格名片</h1>
          </div>
        </div>
        <div className="px-4 pb-4">
          <p className="text-white/80 text-xs leading-relaxed">
            基于你的任务记录、技能、信誉与社区行为，AI 生成专属人格名片，用于社交破冰与信任建立。
          </p>
        </div>
      </div>

      <div className="px-3 -mt-2 space-y-3">
        {/* AI 思考 */}
        {loading && (
          <div className="bg-white rounded-2xl p-6 shadow-card animate-slide-up space-y-3">
            <div className="flex items-center justify-center gap-2 text-primary-600 mb-3">
              <Loader2 size={20} className="animate-spin" />
              <span className="text-sm font-medium">AI 正在解析你的校园画像…</span>
            </div>
            {['分析任务历史与完成表现', '评估技能与兴趣维度', '生成专属人格称号与特质'].map((t, i) => (
              <div key={t} className="flex items-center gap-2 text-ink-500">
                <div className="w-2 h-2 rounded-full bg-primary-500 animate-pulse" style={{ animationDelay: `${i * 0.4}s` }} />
                <span className="text-xs">{t}</span>
              </div>
            ))}
          </div>
        )}

        {/* 人格名片 */}
        {card && (
          <>
            {/* 主名片 */}
            <div
              className="rounded-3xl p-5 shadow-gradient-lg animate-slide-up relative overflow-hidden"
              style={{ background: `linear-gradient(135deg, ${card.color} 0%, ${card.color}CC 60%, #1e1b4b 100%)` }}
            >
              {/* 装饰光晕 */}
              <div className="absolute -top-10 -right-10 w-40 h-40 rounded-full bg-white/10 blur-2xl" />
              <div className="absolute -bottom-16 -left-10 w-48 h-48 rounded-full bg-white/5 blur-3xl" />

              <div className="relative">
                {/* 头部 */}
                <div className="flex items-center gap-3 mb-4">
                  <Avatar src={user.avatar} name={user.nickname} size={56} ring />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                      <h2 className="font-display text-lg font-bold text-white truncate">{user.nickname}</h2>
                      <Sparkles size={14} className="text-white/80" />
                    </div>
                    <p className="text-white/70 text-[11px]">{user.school} · Lv.{user.level}</p>
                  </div>
                  <span className="px-2 py-1 rounded-full bg-white/20 backdrop-blur text-[10px] font-medium text-white">
                    AI 生成
                  </span>
                </div>

                {/* 称号 */}
                <div className="text-center my-5">
                  <div className="text-[11px] text-white/60 mb-1 tracking-widest">YOUR CAMPUS TITLE</div>
                  <h1 className="font-display text-3xl font-bold text-white tracking-tight">{card.title}</h1>
                  <p className="text-white/80 text-sm mt-1.5">{card.subtitle}</p>
                </div>

                {/* 氛围语 */}
                <div className="bg-white/10 backdrop-blur rounded-xl px-4 py-2.5 text-center mb-4">
                  <p className="text-white/90 text-sm font-medium">"{card.vibe}"</p>
                </div>

                {/* 标签 */}
                <div className="flex flex-wrap gap-1.5 justify-center">
                  {card.tags.map(tag => (
                    <span key={tag} className="px-2.5 py-1 rounded-full bg-white/15 backdrop-blur text-[11px] font-medium text-white">
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            </div>

            {/* 五维特质雷达 */}
            <div className="bg-white rounded-2xl p-4 shadow-card animate-slide-up">
              <div className="flex items-center gap-1.5 mb-3">
                <Sparkles size={15} className="text-primary-600" />
                <h3 className="text-sm font-bold text-ink-900">五维人格特质</h3>
              </div>
              <div className="space-y-2.5">
                {card.traits.map(trait => (
                  <div key={trait.name}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-xs font-medium text-ink-700">{trait.name}</span>
                      <div className="flex items-center gap-1.5">
                        <span className="text-[10px] text-ink-400">{trait.label}</span>
                        <span className="text-xs font-bold text-gradient w-7 text-right">{trait.score}</span>
                      </div>
                    </div>
                    <div className="h-2 rounded-full bg-ink-100 overflow-hidden">
                      <div
                        className="h-full rounded-full bg-gradient-blue-purple transition-all duration-700"
                        style={{ width: `${trait.score}%` }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* AI 描述 */}
            <div className="bg-white rounded-2xl p-4 shadow-card animate-slide-up">
              <div className="flex items-center gap-1.5 mb-2">
                <div className="w-5 h-5 rounded-md bg-gradient-blue-purple flex items-center justify-center">
                  <Sparkles size={11} className="text-white" />
                </div>
                <h3 className="text-sm font-bold text-ink-900">AI 人格解读</h3>
              </div>
              <p className="text-xs text-ink-600 leading-relaxed">{card.description}</p>
            </div>

            {/* 操作 */}
            <div className="flex gap-2">
              <button
                onClick={() => { setSeed(s => s + 1); generate(); }}
                className="flex-1 py-3 rounded-xl bg-white text-ink-700 text-sm font-medium shadow-card flex items-center justify-center gap-1.5 btn-press border border-ink-200"
              >
                <RefreshCw size={15} />
                重新生成
              </button>
              <button
                onClick={() => showToast('名片已保存到相册（Demo）', 'success')}
                className="flex-1 py-3 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold shadow-gradient-lg flex items-center justify-center gap-1.5 btn-press"
              >
                <Share2 size={15} />
                分享名片
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
