import { useNavigate } from 'react-router-dom';
import {
  BadgeCheck, Wallet, ListOrdered, Heart, Award, Shield,
  FileText, Settings, ChevronRight, ArrowRight, Sparkles, IdCard,
} from 'lucide-react';
import { useStore } from '@/store';
import { formatPrice } from '@/data/mock';
import Avatar from '@/components/Avatar';
import { cn } from '@/lib/utils';

export default function Profile() {
  const { user, setMode } = useStore();
  const navigate = useNavigate();

  const creditLevel = user.creditScore >= 90 ? '优秀' : user.creditScore >= 80 ? '良好' : user.creditScore >= 60 ? '一般' : '较低';
  const creditColor = user.creditScore >= 90 ? '#10B981' : user.creditScore >= 80 ? '#2563EB' : user.creditScore >= 60 ? '#F59E0B' : '#EF4444';

  const entries = [
    { icon: ListOrdered, label: '我的订单', color: '#2563EB', to: '/orders' },
    { icon: Heart, label: '我的收藏', color: '#EF4444', to: '/profile/favorites' },
    { icon: Award, label: '我的成就', color: '#F59E0B', to: '/profile/achievements' },
    { icon: Shield, label: '信誉中心', color: '#10B981', to: '/profile/credit' },
    { icon: FileText, label: '技能简历', color: '#8B5CF6', to: '/profile/ai-skill' },
    { icon: Settings, label: '设置', color: '#64748B', to: '/profile/settings' },
  ];

  const enterAdmin = () => {
    setMode('admin');
    navigate('/admin');
  };

  // 信誉环
  const radius = 28;
  const circ = 2 * Math.PI * radius;
  const offset = circ - (user.creditScore / 100) * circ;

  return (
    <div className="min-h-screen pb-24 bg-ink-50">
      {/* 渐变头部 - 科幻蓝 */}
      <div className="bg-header-sci-fi-blue text-white relative" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="px-4 pt-6 pb-5">
          <div className="flex items-center gap-3">
            <Avatar src={user.avatar} name={user.nickname} size={64} ring />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1.5">
                <h1 className="font-display text-xl font-bold truncate">{user.nickname}</h1>
                {user.verified && <BadgeCheck size={18} className="text-success-500 fill-white/20" />}
              </div>
              <p className="text-white/80 text-xs mt-0.5">{user.school} · {user.verifyLevel}认证</p>
              <p className="text-white/70 text-xs mt-1 line-clamp-1">{user.bio}</p>
            </div>
            {/* 信誉环 */}
            <div className="relative shrink-0">
              <svg width="68" height="68" className="-rotate-90">
                <circle cx="34" cy="34" r={radius} fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="5" />
                <circle
                  cx="34" cy="34" r={radius} fill="none" stroke="white" strokeWidth="5"
                  strokeLinecap="round" strokeDasharray={circ} strokeDashoffset={offset}
                />
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-lg font-bold font-display leading-none">{user.creditScore}</span>
                <span className="text-[9px] text-white/80">信誉</span>
              </div>
            </div>
          </div>

          {/* 等级徽章 */}
          <div className="flex items-center gap-2 mt-3">
            <span className="px-2 py-0.5 rounded-full bg-white/20 backdrop-blur text-[11px] font-medium flex items-center gap-1">
              <span className="text-warning-500">⚡</span> Lv.{user.level}
            </span>
            <span className="px-2 py-0.5 rounded-full bg-white/20 backdrop-blur text-[11px] font-medium" style={{ color: creditColor === '#10B981' ? '#A7F3D0' : 'white' }}>
              信誉{creditLevel}
            </span>
            <span className="px-2 py-0.5 rounded-full bg-white/20 backdrop-blur text-[11px] font-medium">
              经验 {user.exp}
            </span>
          </div>
        </div>

        {/* 统计行 */}
        <div className="grid grid-cols-3 bg-white/15 backdrop-blur mx-4 rounded-xl py-3 mb-4">
          <Stat label="任务数" value={user.taskCount} />
          <Stat label="完成率" value={`${user.completeRate}%`} />
          <Stat label="信誉分" value={user.creditScore} />
        </div>
      </div>

      <div className="px-3 -mt-2 space-y-3">
        {/* AI 特色功能区 */}
        <div className="grid grid-cols-2 gap-2.5 animate-slide-up">
          <button
            onClick={() => navigate('/profile/ai-skill')}
            className="bg-white rounded-2xl p-3.5 shadow-card border border-ink-100 text-left btn-press hover-lift relative overflow-hidden"
          >
            <div className="absolute -top-6 -right-6 w-20 h-20 rounded-full bg-primary-50" />
            <div className="relative">
              <div className="w-10 h-10 rounded-xl bg-gradient-blue-purple flex items-center justify-center shadow-gradient mb-2">
                <Sparkles size={20} className="text-white" />
              </div>
              <p className="text-sm font-bold text-ink-900">AI 技能变现</p>
              <p className="text-[11px] text-ink-400 mt-0.5 leading-tight">诊断你的变现方向</p>
            </div>
          </button>
          <button
            onClick={() => navigate('/profile/ai-personality')}
            className="bg-white rounded-2xl p-3.5 shadow-card border border-ink-100 text-left btn-press hover-lift relative overflow-hidden"
          >
            <div className="absolute -top-6 -right-6 w-20 h-20 rounded-full bg-accent-50" />
            <div className="relative">
              <div className="w-10 h-10 rounded-xl bg-gradient-blue-purple flex items-center justify-center shadow-gradient mb-2">
                <IdCard size={20} className="text-white" />
              </div>
              <p className="text-sm font-bold text-ink-900">AI 人格名片</p>
              <p className="text-[11px] text-ink-400 mt-0.5 leading-tight">生成你的校园画像</p>
            </div>
          </button>
        </div>

        {/* 钱包卡片 - 蓝紫渐变 */}
        <button
          onClick={() => navigate('/profile/wallet')}
          className="w-full bg-gradient-blue-purple text-white rounded-2xl p-4 shadow-gradient-lg text-left btn-press animate-slide-up"
        >
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-1.5">
              <Wallet size={16} />
              <span className="text-sm font-medium">我的钱包</span>
            </div>
            <ChevronRight size={16} className="text-white/60" />
          </div>
          <div className="flex items-end justify-between mt-3">
            <div>
              <p className="text-white/70 text-[11px]">可用余额（元）</p>
              <p className="font-display text-2xl font-bold">{formatPrice(user.balance)}</p>
            </div>
            <div className="flex gap-4 text-right">
              <div>
                <p className="text-white/70 text-[11px]">待结算</p>
                <p className="font-semibold text-sm">{formatPrice(user.pendingSettle)}</p>
              </div>
              <div>
                <p className="text-white/70 text-[11px]">冻结</p>
                <p className="font-semibold text-sm">{formatPrice(user.frozen)}</p>
              </div>
            </div>
          </div>
        </button>

        {/* 快捷入口 */}
        <div className="bg-white rounded-2xl p-4 shadow-card animate-slide-up border border-ink-100">
          <div className="grid grid-cols-3 gap-y-4">
            {entries.map(e => (
              <button
                key={e.label}
                onClick={() => navigate(e.to)}
                className="flex flex-col items-center gap-1.5 btn-press"
              >
                <div
                  className="w-12 h-12 rounded-xl flex items-center justify-center"
                  style={{ backgroundColor: e.color + '15', boxShadow: `0 2px 8px ${e.color}10` }}
                >
                  <e.icon size={22} style={{ color: e.color }} />
                </div>
                <span className="text-xs text-ink-700 font-medium">{e.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* 进入管理后台 */}
        <button
          onClick={enterAdmin}
          className="w-full bg-white rounded-2xl p-4 shadow-card flex items-center justify-between btn-press animate-slide-up border border-ink-100"
        >
          <div className="flex items-center gap-2.5">
            <div className="w-10 h-10 rounded-xl bg-gradient-blue-purple flex items-center justify-center shadow-gradient">
              <Shield size={20} className="text-white" />
            </div>
            <div className="text-left">
              <p className="text-sm font-semibold text-ink-900">进入管理后台</p>
              <p className="text-[11px] text-ink-400">管理任务、订单、用户和内容</p>
            </div>
          </div>
          <ArrowRight size={18} className="text-ink-400" />
        </button>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: string | number }) {
  return (
    <div className="text-center">
      <p className="font-display text-lg font-bold">{value}</p>
      <p className="text-white/70 text-[11px]">{label}</p>
    </div>
  );
}
