import { statusConfig } from '@/data/mock';
import { cn } from '@/lib/utils';

interface StatusBadgeProps {
  status: string;
  size?: 'sm' | 'md';
  className?: string;
}

export default function StatusBadge({ status, size = 'sm', className }: StatusBadgeProps) {
  const config = statusConfig[status] || { label: status, color: '#64748B', bg: '#F1F5F9' };
  const isPrimary = status === 'OPEN' || status === 'ACCEPTED';
  return (
    <span
      className={cn(
        'inline-flex items-center rounded-full font-semibold whitespace-nowrap',
        size === 'sm' ? 'px-2 py-0.5 text-[11px]' : 'px-3 py-1 text-xs',
        isPrimary && 'badge-gradient',
        className
      )}
      style={!isPrimary ? { color: config.color, backgroundColor: config.bg } : undefined}
    >
      {config.label}
    </span>
  );
}
