import { useState } from 'react';
import { Search, Eye, Ban, ShieldCheck, ShieldX, AlertCircle } from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { adminUsers } from '@/data/mock';
import { cn } from '@/lib/utils';

const filters = [
  { label: '全部', value: 'ALL' },
  { label: '已认证', value: 'VERIFIED' },
  { label: '未认证', value: 'UNVERIFIED' },
  { label: '受限', value: 'RESTRICTED' },
];

const levelConfig: Record<string, { label: string; color: string; bg: string }> = {
  L0: { label: 'L0', color: '#64748B', bg: '#F1F5F9' },
  L1: { label: 'L1', color: '#0891B2', bg: '#CFFAFE' },
  L2: { label: 'L2', color: '#2563EB', bg: '#DBEAFE' },
  L3: { label: 'L3', color: '#7C3AED', bg: '#EDE9FE' },
};

export default function AdminUsers() {
  const showToast = useStore(s => s.showToast);
  const [keyword, setKeyword] = useState('');
  const [filter, setFilter] = useState('ALL');

  const filtered = adminUsers.filter(u => {
    const matchKw = !keyword || u.nickname.includes(keyword) || u.school.includes(keyword);
    const matchFilter =
      filter === 'ALL' ||
      (filter === 'VERIFIED' && u.verified) ||
      (filter === 'UNVERIFIED' && !u.verified) ||
      (filter === 'RESTRICTED' && u.creditScore < 80);
    return matchKw && matchFilter;
  });

  const handleBan = (nickname: string) => {
    showToast(`已封禁用户「${nickname}」`, 'error');
  };

  return (
    <AdminLayout>
      {/* 搜索 + 筛选 */}
      <div className="bg-white rounded-2xl p-3 shadow-card space-y-3">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-ink-400" />
          <input
            value={keyword}
            onChange={e => setKeyword(e.target.value)}
            placeholder="搜索昵称或学校"
            className="w-full pl-9 pr-3 py-2 bg-ink-50 rounded-lg text-sm text-ink-800 placeholder:text-ink-400 focus:outline-none focus:ring-2 focus:ring-primary-500"
          />
        </div>
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
          {filters.map(f => (
            <button
              key={f.value}
              onClick={() => setFilter(f.value)}
              className={cn(
                'px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors',
                filter === f.value ? 'bg-primary-600 text-white' : 'bg-ink-100 text-ink-500'
              )}
            >
              {f.label}
            </button>
          ))}
        </div>
      </div>

      {/* 用户列表 */}
      <div className="mt-3 bg-white rounded-2xl shadow-card overflow-hidden">
        <div className="px-4 py-3 border-b border-ink-100 flex items-center justify-between">
          <h2 className="font-display font-semibold text-ink-900 text-sm">用户列表</h2>
          <span className="text-xs text-ink-400">共 {filtered.length} 人</span>
        </div>

        {filtered.length === 0 ? (
          <Empty icon="👤" title="未找到用户" desc="尝试调整筛选条件" />
        ) : (
          <div className="divide-y divide-ink-100">
            {filtered.map(user => {
              const lvl = levelConfig[user.verifyLevel] || levelConfig.L0;
              const isRestricted = user.creditScore < 80;
              return (
                <div key={user.id} className="p-3.5 hover:bg-ink-50/50 transition-colors">
                  <div className="flex items-start gap-3">
                    <Avatar src={user.avatar} name={user.nickname} size={40} />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex items-center gap-1.5 min-w-0">
                          <h3 className="font-semibold text-ink-900 text-sm truncate">{user.nickname}</h3>
                          <span
                            className="text-[10px] px-1.5 py-0.5 rounded font-bold shrink-0"
                            style={{ color: lvl.color, backgroundColor: lvl.bg }}
                          >
                            {lvl.label}
                          </span>
                          {user.verified ? (
                            <ShieldCheck size={14} className="text-success-500 shrink-0" />
                          ) : (
                            <ShieldX size={14} className="text-ink-400 shrink-0" />
                          )}
                        </div>
                        {isRestricted && (
                          <span className="flex items-center gap-0.5 text-[10px] text-danger-600 bg-danger-50 px-1.5 py-0.5 rounded font-medium shrink-0">
                            <AlertCircle size={10} /> 受限
                          </span>
                        )}
                      </div>

                      <div className="flex items-center gap-2 mt-1 text-[11px] text-ink-500 flex-wrap">
                        <span>{user.school}</span>
                        <span className="text-ink-300">·</span>
                        <span>信誉 <span className={cn('font-semibold', isRestricted ? 'text-danger-600' : 'text-success-600')}>{user.creditScore}</span></span>
                        <span className="text-ink-300">·</span>
                        <span>Lv.{user.level}</span>
                        <span className="text-ink-300">·</span>
                        <span>{user.orderCount} 单</span>
                      </div>

                      <div className="text-[11px] text-ink-400 mt-0.5">注册时间：{user.registerTime}</div>

                      {/* 操作按钮 */}
                      <div className="flex items-center gap-1.5 mt-2.5">
                        <button
                          onClick={() => showToast(`查看用户「${user.nickname}」详情`, 'info')}
                          className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-ink-100 text-ink-700 text-xs font-medium hover:bg-ink-200 btn-press"
                        >
                          <Eye size={13} /> 查看
                        </button>
                        <button
                          onClick={() => handleBan(user.nickname)}
                          className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-danger-100 text-danger-600 text-xs font-medium hover:bg-danger-500 hover:text-white btn-press"
                        >
                          <Ban size={13} /> 封禁
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
