import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Heart, MessageCircle, Eye, PenSquare, Newspaper, Clock } from 'lucide-react';
import { circles } from '@/data/mock';
import { useStore } from '@/store';
import type { Post } from '@/types';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import Modal from '@/components/Modal';
import { cn } from '@/lib/utils';

const topicOptions = ['校园生活', '二手交易', '学习互助', '社团活动', '校园吐槽', '其他'];

export default function Plaza() {
  const navigate = useNavigate();
  const { posts, publishPost, showToast } = useStore();
  const [publishOpen, setPublishOpen] = useState(false);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [topic, setTopic] = useState(topicOptions[0]);
  const [anonymous, setAnonymous] = useState(false);

  const resetForm = () => {
    setTitle('');
    setContent('');
    setTopic(topicOptions[0]);
    setAnonymous(false);
  };

  const handleSubmit = () => {
    if (!title.trim()) { showToast('请填写标题', 'error'); return; }
    if (!content.trim()) { showToast('请填写正文', 'error'); return; }
    publishPost(title.trim(), content.trim(), topic, anonymous);
    showToast('发布成功', 'success');
    resetForm();
    setPublishOpen(false);
  };

  return (
    <div className="min-h-screen bg-ink-50 pb-24">
      {/* 顶部渐变区 - 科幻蓝 */}
      <div className="bg-header-sci-fi-blue text-white" style={{ paddingTop: 'var(--safe-top)' }}>
        <div className="px-4 pt-4 pb-3">
          <h1 className="font-display text-2xl font-bold">校园广场</h1>
          <p className="text-white/80 text-xs mt-0.5">分享校园生活 · 资讯一手掌握</p>
        </div>
        {/* Tab */}
        <div className="flex px-4 gap-1">
          <button
            className="px-4 py-2 rounded-t-xl text-sm font-semibold bg-white text-primary-600"
          >
            论坛
          </button>
          <button
            onClick={() => navigate('/plaza/news')}
            className="px-4 py-2 rounded-t-xl text-sm font-medium text-white/90 flex items-center gap-1 btn-press"
          >
            资讯 <Newspaper size={14} />
          </button>
          <button
            onClick={() => navigate('/plaza/circles')}
            className="px-4 py-2 rounded-t-xl text-sm font-medium text-white/90 flex items-center gap-1 btn-press"
          >
            吧台 <Clock size={14} />
          </button>
        </div>
      </div>

      {/* 限时吧台入口卡 - 创新功能 */}
      <div className="px-3 -mt-1">
        <button
          onClick={() => navigate('/plaza/circles')}
          className="w-full bg-gradient-blue-purple-soft rounded-2xl p-3.5 border border-primary-100 hover-lift btn-press text-left flex items-center gap-3"
        >
          <div className="w-11 h-11 rounded-xl bg-gradient-blue-purple flex items-center justify-center shadow-gradient shrink-0">
            <Clock size={20} className="text-white" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-1.5">
              <span className="text-sm font-bold text-ink-900">限时吧台</span>
              <span className="px-1.5 py-0.5 rounded bg-primary-100 text-primary-600 text-[9px] font-semibold">创新功能</span>
            </div>
            <p className="text-[11px] text-ink-500 mt-0.5">临时兴趣群组 · 24h评估 · 活跃转永久</p>
          </div>
          <div className="flex -space-x-2 shrink-0">
            {circles.slice(0, 3).map(c => (
              <div key={c.id} className="w-7 h-7 rounded-full bg-white border-2 border-white flex items-center justify-center text-sm shadow-sm">
                {c.icon}
              </div>
            ))}
            <div className="w-7 h-7 rounded-full bg-ink-100 border-2 border-white flex items-center justify-center text-[10px] font-semibold text-ink-500">
              {circles.length}
            </div>
          </div>
        </button>
      </div>

      {/* 论坛内容 */}
      <div className="bg-white rounded-t-2xl -mt-2 px-3 py-3 min-h-[60vh]">
        {posts.length === 0 ? (
          <Empty icon="📭" title="暂无帖子" desc="快来发第一帖吧" />
        ) : (
          <div className="space-y-3">
            {posts.map(post => (
              <PostCard key={post.id} post={post} />
            ))}
          </div>
        )}
      </div>

      {/* 发帖浮动按钮 - 渐变 */}
      <button
        onClick={() => setPublishOpen(true)}
        className="fixed bottom-24 z-30 w-14 h-14 rounded-full bg-gradient-blue-purple text-white shadow-gradient-lg flex items-center justify-center btn-press"
        style={{ right: 'max(16px, calc(50% - 215px + 16px))' }}
        aria-label="发帖"
      >
        <PenSquare size={24} />
      </button>

      {/* 发帖弹窗 */}
      <Modal open={publishOpen} onClose={() => setPublishOpen(false)} title="发布帖子">
        <div className="px-5 py-4 space-y-4">
          {/* 标题 */}
          <div>
            <h4 className="text-sm font-semibold text-ink-800 mb-2">标题</h4>
            <input
              value={title}
              onChange={e => setTitle(e.target.value.slice(0, 30))}
              placeholder="一句话概括你的帖子"
              className="w-full bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:ring-2 focus:ring-primary-200"
            />
            <div className="text-right text-[11px] text-ink-400 mt-1">{title.length}/30</div>
          </div>

          {/* 正文 */}
          <div>
            <h4 className="text-sm font-semibold text-ink-800 mb-2">正文</h4>
            <textarea
              value={content}
              onChange={e => setContent(e.target.value.slice(0, 500))}
              placeholder="分享你的想法、资讯或吐槽…"
              rows={4}
              className="w-full bg-ink-100 rounded-xl px-3.5 py-2.5 text-sm text-ink-800 placeholder:text-ink-400 outline-none focus:ring-2 focus:ring-primary-200 resize-none"
            />
            <div className="text-right text-[11px] text-ink-400 mt-1">{content.length}/500</div>
          </div>

          {/* 话题选择 */}
          <div>
            <h4 className="text-sm font-semibold text-ink-800 mb-2">话题</h4>
            <div className="flex flex-wrap gap-2">
              {topicOptions.map(t => (
                <button
                  key={t}
                  onClick={() => setTopic(t)}
                  className={cn(
                    'text-xs px-3.5 py-1.5 rounded-full font-medium border transition-colors',
                    topic === t ? 'bg-gradient-blue-purple text-white border-transparent shadow-gradient' : 'bg-white text-ink-600 border-ink-200'
                  )}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          {/* 匿名开关 */}
          <div className="flex items-center justify-between">
            <div>
              <h4 className="text-sm font-semibold text-ink-800">匿名发布</h4>
              <p className="text-[11px] text-ink-400 mt-0.5">隐藏你的昵称和头像</p>
            </div>
            <button
              onClick={() => setAnonymous(a => !a)}
              className={cn(
                'relative w-11 h-6 rounded-full transition-colors',
                anonymous ? 'bg-primary-600' : 'bg-ink-200'
              )}
            >
              <span
                className={cn(
                  'absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform',
                  anonymous && 'translate-x-5'
                )}
              />
            </button>
          </div>

          {/* 提交按钮 */}
          <div className="flex gap-3 pt-1">
            <button
              onClick={() => setPublishOpen(false)}
              className="flex-1 py-2.5 rounded-xl text-sm font-medium bg-ink-100 text-ink-600 btn-press"
            >
              取消
            </button>
            <button
              onClick={handleSubmit}
              className="flex-1 py-2.5 rounded-xl text-sm font-medium bg-gradient-blue-purple text-white btn-press shadow-gradient"
            >
              发布
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

function PostCard({ post }: { post: Post }) {
  const name = post.anonymous ? '匿名同学' : post.author.nickname;
  const avatar = post.anonymous ? '' : post.author.avatar;

  return (
    <Link
      to={`/plaza/post/${post.id}`}
      className="block bg-white rounded-2xl p-3.5 shadow-card hover:shadow-soft transition-shadow btn-press border border-ink-100 animate-slide-up"
    >
      <div className="flex items-center gap-2">
        <Avatar src={avatar} name={name} size={36} />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5">
            <span className="text-sm font-medium text-ink-800 truncate">{name}</span>
            {post.anonymous && (
              <span className="text-[10px] px-1 py-0.5 rounded bg-ink-100 text-ink-500">匿名</span>
            )}
          </div>
          <div className="flex items-center gap-1.5 text-[11px] text-ink-400 mt-0.5">
            <span className="px-1.5 py-0.5 rounded bg-primary-50 text-primary-600 font-medium">{post.topic}</span>
            <span>·</span>
            <span>{post.createdAt}</span>
          </div>
        </div>
      </div>

      <h3 className="font-semibold text-ink-900 text-[15px] mt-2.5 leading-snug">{post.title}</h3>
      <p className="text-sm text-ink-600 mt-1 line-clamp-2 leading-relaxed">{post.content}</p>

      <div className="flex items-center gap-4 mt-2.5 text-[11px] text-ink-400">
        <span className="flex items-center gap-1"><Eye size={13} />{post.views}</span>
        <span className={cn('flex items-center gap-1', post.liked && 'text-danger-500')}>
          <Heart size={13} fill={post.liked ? 'currentColor' : 'none'} />{post.likes}
        </span>
        <span className="flex items-center gap-1"><MessageCircle size={13} />{post.comments.length}</span>
      </div>
    </Link>
  );
}
