import { useState } from 'react';
import { Star } from 'lucide-react';
import Modal from '@/components/Modal';
import { useStore } from '@/store';
import { cn } from '@/lib/utils';

const RATING_TAGS = ['准时', '沟通顺畅', '完成质量好', '描述准确', '态度好'];

const SCORE_LABELS: Record<number, string> = {
  5: '非常满意，强烈推荐',
  4: '满意',
  3: '一般',
  2: '不太满意',
  1: '需要改进',
};

interface RatingModalProps {
  open: boolean;
  orderId: string;
  onClose: () => void;
}

export default function RatingModal({ open, orderId, onClose }: RatingModalProps) {
  const { rateOrder, showToast } = useStore();
  const [score, setScore] = useState(5);
  const [hoverScore, setHoverScore] = useState(0);
  const [comment, setComment] = useState('');
  const [selectedTags, setSelectedTags] = useState<string[]>([]);

  const toggleTag = (tag: string) => {
    setSelectedTags(prev =>
      prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]
    );
  };

  const submit = () => {
    if (score === 0) {
      showToast('请选择评分', 'error');
      return;
    }
    rateOrder(orderId, score, comment, selectedTags);
    handleClose();
    showToast('评价提交成功', 'success');
  };

  const handleClose = () => {
    onClose();
    setComment('');
    setSelectedTags([]);
    setScore(5);
  };

  const displayScore = hoverScore || score;

  return (
    <Modal open={open} onClose={handleClose} title="评价订单">
      <div className="p-5">
        <div className="flex flex-col items-center mb-5">
          <div className="text-xs text-ink-400 mb-2">为本次交易评分</div>
          <div className="flex items-center gap-1.5">
            {[1, 2, 3, 4, 5].map(i => (
              <button
                key={i}
                onClick={() => setScore(i)}
                onMouseEnter={() => setHoverScore(i)}
                onMouseLeave={() => setHoverScore(0)}
                className="btn-press"
              >
                <Star
                  size={32}
                  className={i <= displayScore ? 'text-warning-500' : 'text-ink-200'}
                  fill={i <= displayScore ? 'currentColor' : 'none'}
                />
              </button>
            ))}
          </div>
          <div className="text-xs text-ink-500 mt-1.5">{SCORE_LABELS[displayScore] || ''}</div>
        </div>

        <div className="mb-4">
          <div className="text-xs text-ink-500 mb-2">选择标签（可多选）</div>
          <div className="flex flex-wrap gap-2">
            {RATING_TAGS.map(tag => (
              <button
                key={tag}
                onClick={() => toggleTag(tag)}
                className={cn(
                  'px-3 py-1.5 rounded-full text-xs font-medium btn-press transition-all',
                  selectedTags.includes(tag)
                    ? 'bg-gradient-blue-purple text-white shadow-gradient'
                    : 'bg-ink-100 text-ink-500'
                )}
              >
                {tag}
              </button>
            ))}
          </div>
        </div>

        <div className="mb-5">
          <div className="text-xs text-ink-500 mb-2">补充评价</div>
          <textarea
            value={comment}
            onChange={e => setComment(e.target.value)}
            placeholder="说说本次交易的感受吧…"
            maxLength={200}
            className="w-full h-24 p-3 rounded-xl bg-ink-50 border border-ink-200 text-sm text-ink-900 placeholder:text-ink-300 focus:outline-none focus:border-primary-400 resize-none"
          />
          <div className="text-right text-[11px] text-ink-400 mt-1">{comment.length}/200</div>
        </div>

        <button
          onClick={submit}
          className="w-full py-3 rounded-xl bg-gradient-blue-purple text-white text-sm font-semibold btn-press shadow-gradient"
        >
          提交评价
        </button>
      </div>
    </Modal>
  );
}
