import { Link } from 'react-router-dom';
import { MapPin, Clock, Heart, Eye, Users } from 'lucide-react';
import type { Task } from '@/types';
import { categoryConfig, formatPrice } from '@/data/mock';
import { cn } from '@/lib/utils';
import Avatar from './Avatar';
import StatusBadge from './StatusBadge';
import { useStore } from '@/store';

interface TaskCardProps {
  task: Task;
  showStatus?: boolean;
}

export default function TaskCard({ task, showStatus }: TaskCardProps) {
  const cat = categoryConfig[task.category];
  const favorites = useStore(s => s.favorites);
  const isFav = favorites.includes(task.id);

  return (
    <Link to={`/tasks/${task.id}`} className="block bg-gradient-card rounded-2xl p-3.5 shadow-soft-xs hover-lift btn-press border border-white">
      <div className="flex items-start gap-3">
        {/* 分类图标 - 渐变柔光背景 */}
        <div
          className="w-11 h-11 rounded-xl flex items-center justify-center text-xl shrink-0"
          style={{ backgroundColor: cat.color + '12', boxShadow: `0 2px 8px ${cat.color}15` }}
        >
          {cat.icon}
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between gap-2">
            <h3 className="font-medium text-ink-800 text-sm line-clamp-2 leading-snug">{task.title}</h3>
            {showStatus && <StatusBadge status={task.status} />}
          </div>

          <div className="flex items-center gap-1.5 mt-1.5 flex-wrap">
            <span
              className="badge"
              style={{ color: cat.color, backgroundColor: cat.color + '12' }}
            >
              {cat.label}
            </span>
            {task.tags.map(tag => (
              <span key={tag} className="badge bg-ink-200 text-ink-500">{tag}</span>
            ))}
          </div>

          <div className="flex items-center gap-3 mt-2 text-[11px] text-ink-500">
            <span className="flex items-center gap-0.5"><MapPin size={12} />{task.location}</span>
            <span className="flex items-center gap-0.5"><Clock size={12} />{task.deadline}</span>
            {task.headcount > 1 && <span className="flex items-center gap-0.5"><Users size={12} />{task.headcount}人</span>}
          </div>

          <div className="flex items-center justify-between mt-2.5">
            <div className="flex items-center gap-1.5">
              <Avatar src={task.publisher.avatar} name={task.publisher.nickname} size={18} />
              <span className="text-[11px] text-ink-500">{task.publisher.nickname}</span>
              <span className="text-[11px] text-ink-300">·</span>
              <span className="text-[11px] text-ink-500">信誉 {task.publisher.creditScore}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="flex items-center gap-0.5 text-[11px] text-ink-400"><Eye size={12} />{task.views}</span>
              <span className={cn('flex items-center gap-0.5 text-[11px]', isFav ? 'text-danger-300' : 'text-ink-400')}>
                <Heart size={12} fill={isFav ? 'currentColor' : 'none'} />{task.favorites}
              </span>
            </div>
          </div>
        </div>

        <div className="text-right shrink-0">
          <div className="text-lg font-bold font-display tracking-tight text-gradient">
            ¥{formatPrice(task.price)}
          </div>
          {task.price > 1000 && <div className="text-[10px] text-primary-400">高薪</div>}
        </div>
      </div>
    </Link>
  );
}
