import { useState } from 'react';
import { Check, X, Ban, Flag, Eye, MessageSquare } from 'lucide-react';
import AdminLayout from '@/components/AdminLayout';
import Avatar from '@/components/Avatar';
import Empty from '@/components/Empty';
import { useStore } from '@/store';
import { adminContent } from '@/data/mock';
import { cn } from '@/lib/utils';

const tabs = [
  { label: '待审核', value: 'pending' },
  { label: '已通过', value: 'approved' },
  { label: '已驳回', value: 'rejected' },
  { label: '举报', value: 'reported' },
];

const statusConfig: Record<string, { label: string; color: string; bg: string }> = {
  pending: { label: '待审核', color: '#D97706', bg: '#FEF3C7' },
  approved: { label: '已通过', color: '#059669', bg: '#D1FAE5' },
  rejected: { label: '已驳回', color: '#EF4444', bg: '#FEE2E2' },
};

export default function AdminContent() {
  const showToast = useStore(s => s.showToast);
  const [tab, setTab] = useState('pending');

  const filtered = adminContent.filter(p => {
    if (tab === 'reported') return p.reportCount > 0;
    return p.status === tab;
  });

  return (
    <AdminLayout>
      {/* 状态筛选 */}
      <div className="bg-white rounded-2xl p-3 shadow-card">
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
          {tabs.map(t => (
            <button
              key={t.value}
              onClick={() => setTab(t.value)}
              className={cn(
                'px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors',
                tab === t.value ? 'bg-primary-600 text-white' : 'bg-ink-100 text-ink-500'
              )}
            >
              {t.label}
            </button>
          ))}
        </div>
      </div>

      {/* 内容列表 */}
      <div className="mt-3 bg-white rounded-2xl shadow-card overflow-hidden">
        <div className="px-4 py-3 border-b border-ink-100 flex items-center justify-between">
          <h2 className="font-display font-semibold text-ink-900 text-sm">内容列表</h2>
          <span className="text-xs text-ink-400">共 {filtered.length} 条</span>
        </div>

        {filtered.length === 0 ? (
          <Empty icon="📝" title="暂无内容" desc="该状态下没有内容" />
        ) : (
          <div className="divide-y divide-ink-100">
            {filtered.map(post => {
              const cfg = statusConfig[post.status] || statusConfig.pending;
              const isReported = post.reportCount > 0;
              return (
                <div key={post.id} className="p-3.5 hover:bg-ink-50/50 transition-colors">
                  <div className="flex items-start gap-3">
                    <Avatar src={post.author.avatar} name={post.author.nickname} size={36} />
                    <div className="flex-1 min-w-0">
                      {/* 标题 + 状态 */}
                      <div className="flex items-start justify-between gap-2">
                        <h3 className="font-semibold text-ink-900 text-sm line-clamp-1">{post.title}</h3>
                        <span
                          className="text-[10px] px-1.5 py-0.5 rounded font-medium shrink-0"
                          style={{ color: cfg.color, backgroundColor: cfg.bg }}
                        >
                          {cfg.label}
                        </span>
                      </div>

                      {/* 作者信息 */}
                      <div className="flex items-center gap-2 mt-1 text-[11px] text-ink-500 flex-wrap">
                        <span>{post.author.nickname}</span>
                        <span className="text-ink-300">·</span>
                        <span className="px-1.5 py-0.5 rounded bg-ink-100 text-ink-500">#{post.topic}</span>
                        <span className="text-ink-300">·</span>
                        <span>{post.createdAt}</span>
                      </div>

                      {/* 内容预览 */}
                      <p className="text-xs text-ink-600 mt-1.5 line-clamp-2">{post.content}</p>

                      {/* 统计 */}
                      <div className="flex items-center gap-3 mt-2 text-[11px] text-ink-400">
                        <span className="flex items-center gap-0.5"><Eye size={12} />{post.views}</span>
                        <span className="flex items-center gap-0.5"><MessageSquare size={12} />{post.comments.length}</span>
                        {isReported && (
                          <span className="flex items-center gap-0.5 text-danger-600 bg-danger-50 px-1.5 py-0.5 rounded font-medium">
                            <Flag size={11} /> 举报 {post.reportCount}
                          </span>
                        )}
                      </div>

                      {/* 举报原因 */}
                      {tab === 'reported' && isReported && (
                        <div className="mt-2 text-[11px] text-danger-600 bg-danger-50 rounded-lg px-2 py-1.5">
                          举报原因：内容涉嫌违规/广告引流
                        </div>
                      )}

                      {/* 操作按钮 */}
                      <div className="flex items-center gap-1.5 mt-2.5">
                        {post.status === 'pending' ? (
                          <>
                            <button
                              onClick={() => showToast(`已通过帖子「${post.title}」`, 'success')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-success-500 text-white text-xs font-medium hover:bg-success-600 btn-press"
                            >
                              <Check size={13} /> 通过
                            </button>
                            <button
                              onClick={() => showToast(`已驳回帖子「${post.title}」`, 'error')}
                              className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-danger-500 text-white text-xs font-medium hover:bg-danger-600 btn-press"
                            >
                              <X size={13} /> 驳回
                            </button>
                          </>
                        ) : null}
                        {post.status !== 'rejected' && (
                          <button
                            onClick={() => showToast(`已下架帖子「${post.title}」`, 'info')}
                            className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-warning-100 text-warning-600 text-xs font-medium hover:bg-warning-500 hover:text-white btn-press"
                          >
                            <Ban size={13} /> 下架
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
