import { useState, useEffect } from 'react';

/** 实时倒计时 hook，返回剩余时分秒 */
export function useCountdown(deadline: number | null) {
  const [remaining, setRemaining] = useState(() => calcRemaining(deadline));

  useEffect(() => {
    setRemaining(calcRemaining(deadline));
    if (deadline === null) return;
    const timer = setInterval(() => {
      setRemaining(calcRemaining(deadline));
    }, 1000);
    return () => clearInterval(timer);
  }, [deadline]);

  return remaining;
}

function calcRemaining(deadline: number | null) {
  if (deadline === null) return { hours: 0, minutes: 0, seconds: 0, total: 0, expired: false };
  const diff = deadline - Date.now();
  if (diff <= 0) return { hours: 0, minutes: 0, seconds: 0, total: 0, expired: true };
  const total = Math.floor(diff / 1000);
  const hours = Math.floor(total / 3600);
  const minutes = Math.floor((total % 3600) / 60);
  const seconds = total % 60;
  return { hours, minutes, seconds, total, expired: false };
}
